const MOCK_CRITERIA_CYCLE_NODE_PREFIX = 'mockCriteriaCycle:';
const DEVELOPER_POOL_STORAGE_KEY = 'rediforge.developerPoolByProject.v1';
const DESIGN_OBJECT_NODE_PREFIX = 'designObject:';
const DESIGN_DELIVERABLE_NODE_PREFIX = 'designDeliverable:';
const DESIGN_DELIVERABLE_CHILD_NODE_PREFIX = 'designDeliverableChild:';
type DesignDeliverableChildKey = 'plan' | 'maintain' | 'approvals';
const DESIGN_PHASE_DELIVERABLES: Array<{ key: string; label: string; accentColor: string; icon: HierarchyIconChoice }> = [
  { key: 'dataDefinitionSource', label: 'Data Definition (Source)', accentColor: '#7E57C2', icon: 'fa-table-cells' },
  { key: 'dataDefinitionTarget', label: 'Data Definition (Target)', accentColor: '#9575CD', icon: 'fa-table-cells' },
  { key: 'functionalDesign', label: 'Functional Design', accentColor: '#26A69A', icon: 'fa-file-lines' },
  { key: 'fieldMapping', label: 'Field Mapping Document', accentColor: '#4FC3F7', icon: 'fa-network-wired' },
  { key: 'technicalDesignInitial', label: 'Technical Design (Initial)', accentColor: '#FFA726', icon: 'fa-diagram-project' },
  { key: 'validationScripts', label: 'Validation Scripts', accentColor: '#66BB6A', icon: 'fa-list-check' },
];

const buildDesignObjectNodeId = (objectId: string) => `${DESIGN_OBJECT_NODE_PREFIX}${objectId}`;
const buildDesignDeliverableNodeId = (objectId: string, deliverableKey: string) => `${DESIGN_DELIVERABLE_NODE_PREFIX}${objectId}:${deliverableKey}`;
const buildDesignDeliverableChildNodeId = (objectId: string, deliverableKey: string, childKey: DesignDeliverableChildKey) => `${DESIGN_DELIVERABLE_CHILD_NODE_PREFIX}${objectId}:${deliverableKey}:${childKey}`;

const parseDesignObjectNodeId = (nodeId: string) => {
  if (!nodeId.startsWith(DESIGN_OBJECT_NODE_PREFIX)) return null;
  return { objectId: nodeId.substring(DESIGN_OBJECT_NODE_PREFIX.length) };
};

const parseDesignDeliverableNodeId = (nodeId: string) => {
  if (!nodeId.startsWith(DESIGN_DELIVERABLE_NODE_PREFIX)) return null;
  const trimmed = nodeId.substring(DESIGN_DELIVERABLE_NODE_PREFIX.length);
  const [objectId, deliverableKey] = trimmed.split(':');
  if (!objectId || !deliverableKey) return null;
  return { objectId, deliverableKey };
};

const parseDesignDeliverableChildNodeId = (nodeId: string) => {
  if (!nodeId.startsWith(DESIGN_DELIVERABLE_CHILD_NODE_PREFIX)) return null;
  const trimmed = nodeId.substring(DESIGN_DELIVERABLE_CHILD_NODE_PREFIX.length);
  const [objectId, deliverableKey, childKey] = trimmed.split(':');
  if (!objectId || !deliverableKey || !childKey) return null;
  return { objectId, deliverableKey, childKey: childKey as DesignDeliverableChildKey };
};

// ── Roadmap component ──────────────────────────────────────────────────────
interface RoadmapItem {
  id: string;
  type: 'phase' | 'test-cycle' | 'milestone';
  projectKey: string; // project name (stable key across cycles)
  name: string;
  linkedCycleId?: string;
  startDate?: string;
  endDate?: string;
  date?: string;
  color: string;
  subtype?: 'planning' | 'design' | 'build';
}

interface RoadmapViewProps {
  programs: any[];
  mockCycles: Record<string, any[]>;
  projectsByMockCycle: Record<string, any[]>;
  onSaveCycleDates: (cycleId: string, startDate: string, endDate: string) => Promise<void>;
  forcedProjectName?: string;
  hideFilters?: boolean;
}

const PHASE_COLORS: Record<string, string> = { planning: '#4FC3F7', design: '#CE93D8', build: '#A5D6A7' };
const TEST_CYCLE_COLOR = '#FFB74D';
const MILESTONE_COLOR = '#FFD54F';

const RoadmapView: React.FC<RoadmapViewProps> = ({ programs, mockCycles, projectsByMockCycle, onSaveCycleDates, forcedProjectName, hideFilters = false }) => {
  const [roadmapItems, setRoadmapItems] = React.useState<RoadmapItem[]>([]);
  const [filterProgram, setFilterProgram] = React.useState('');
  const [filterProject, setFilterProject] = React.useState('');
  const [editCycle, setEditCycle] = React.useState<any | null>(null);
  const [editStart, setEditStart] = React.useState('');
  const [editEnd, setEditEnd] = React.useState('');
  const [savingCycle, setSavingCycle] = React.useState(false);
  const [addDialog, setAddDialog] = React.useState<'phase' | 'test-cycle' | 'milestone' | null>(null);
  const [editingItem, setEditingItem] = React.useState<RoadmapItem | null>(null);
  const [form, setForm] = React.useState<Partial<RoadmapItem & { subtype: string }>>({});
  const [savingItem, setSavingItem] = React.useState(false);
  const [lastRoadmapInteraction, setLastRoadmapInteraction] = React.useState('');
  // Horizontal date drag
  const [drag, setDrag] = React.useState<{
    id: string; entityType: 'cycle' | 'roadmap'; handle: 'start' | 'end' | 'date';
    currentDate: string; indicatorX: number;
    origStart: string; origEnd: string;
  } | null>(null);
  // Lane-based layout: activityId → laneIndex per project
  const [laneAssign, setLaneAssign] = React.useState<Record<string, Record<string, number>>>({});
  // Vertical activity drag — visual state only (listeners set up directly in mousedown)
  const [actDrag, setActDrag] = React.useState<{ projectKey: string; actId: string } | null>(null);
  const [laneDragOver, setLaneDragOver] = React.useState<{ projectKey: string; laneIdx: number; canDrop: boolean } | null>(null);
  const laneAssignRef = React.useRef(laneAssign);
  const fullLaneMapsRef = React.useRef<Record<string, Record<string, number>>>({});
  React.useEffect(() => { laneAssignRef.current = laneAssign; }, [laneAssign]);

  // Start a lane drag — sets up mousemove/mouseup directly (no effect delay, no stale closures)
  // Y-delta based lane drag — pure math, no DOM queries needed
  const startLaneDrag = React.useCallback((
    e: React.MouseEvent, actId: string, projectKey: string, fromLane: number, totalLanes: number
  ) => {
    e.stopPropagation();
    e.preventDefault();
    setActDrag({ projectKey, actId });
    const startY = e.clientY;
    const ROW_H = 44; // approximate lane row height in px
    let targetLane = fromLane;

    const onMove = (me: MouseEvent) => {
      const delta = Math.round((me.clientY - startY) / ROW_H);
      targetLane = Math.max(0, Math.min(totalLanes, fromLane + delta));
      setLaneDragOver({ projectKey, laneIdx: targetLane, canDrop: true });
    };
    const onUp = () => {
      document.removeEventListener('mousemove', onMove);
      document.removeEventListener('mouseup', onUp);
      // Always save when the lane changed
      if (targetLane !== fromLane) {
        const full = { ...(fullLaneMapsRef.current[projectKey] || {}), ...(laneAssignRef.current[projectKey] || {}) };
        const updated = { ...full, [actId]: targetLane };
        const next = { ...laneAssignRef.current, [projectKey]: updated };
        laneAssignRef.current = next;
        setLaneAssign({ ...next });
        apiClient.put('/api/hierarchy-preferences/global-process-areas', { roadmapLaneAssign: next })
          .catch(err => console.error('Lane save failed:', err));
      }
      setActDrag(null);
      setLaneDragOver(null);
    };
    document.addEventListener('mousemove', onMove);
    document.addEventListener('mouseup', onUp);
  // eslint-disable-next-line react-hooks/exhaustive-deps
  }, []);
  const timelineRef = React.useRef<HTMLDivElement>(null);
  const scrollContainerRef = React.useRef<HTMLDivElement>(null);

  // Scroll to center today's date on first render
  React.useLayoutEffect(() => {
    const container = scrollContainerRef.current;
    const inner = timelineRef.current;
    if (!container || !inner) return;
    const totalWidth = inner.scrollWidth;
    const containerWidth = container.clientWidth;
    const todayPct = totalDays > 0 ? (today.getTime() - rangeStart.getTime()) / (rangeEnd.getTime() - rangeStart.getTime()) : 0.5;
    const scrollTo = todayPct * totalWidth - containerWidth / 2;
    container.scrollLeft = Math.max(0, scrollTo);
  // Run once on mount (rangeStart/rangeEnd/today are stable after first render)
  // eslint-disable-next-line react-hooks/exhaustive-deps
  }, []);

  React.useEffect(() => {
    apiClient.get('/api/hierarchy-preferences/state').then(res => {
      const d = res.data?.data || res.data?.preferences || res.data;
      if (Array.isArray(d?.roadmapItems)) setRoadmapItems(d.roadmapItems);
      if (d?.roadmapLaneAssign && typeof d.roadmapLaneAssign === 'object') setLaneAssign(d.roadmapLaneAssign);
    }).catch(() => {});
  }, []);

  const persistItems = (items: RoadmapItem[]) => {
    setRoadmapItems(items);
    apiClient.put('/api/hierarchy-preferences/global-process-areas', { roadmapItems: items }).catch(() => {});
  };


  const allCyclesById = React.useMemo(() => {
    const m = new Map<string, any>();
    Object.values(mockCycles).flat().forEach((c: any) => m.set(c.id, c));
    return m;
  }, [mockCycles]);

  // Deduplicated projects by name, annotated with their program
  const uniqueProjects: { name: string; programName: string; programAccent: string; cycleIds: string[] }[] = React.useMemo(() => {
    const map = new Map<string, { name: string; programName: string; programAccent: string; cycleIds: string[] }>();
    programs.forEach(prog => {
      (mockCycles[prog.id] || []).forEach((c: any) => {
        (projectsByMockCycle[c.id] || []).forEach((p: any) => {
          const key = (p.name || p.id || '').trim();
          if (!map.has(key)) {
            map.set(key, { name: key, programName: prog.name, programAccent: prog.accentColor || '#5B67CA', cycleIds: [] });
          }
          if (!map.get(key)!.cycleIds.includes(c.id)) map.get(key)!.cycleIds.push(c.id);
        });
      });
    });
    return Array.from(map.values()).sort((a, b) => a.name.localeCompare(b.name));
  }, [programs, mockCycles, projectsByMockCycle]);

  // Filtered projects
  const filteredProjects = React.useMemo(() => {
    if (forcedProjectName) {
      return uniqueProjects.filter((p) => p.name === forcedProjectName);
    }
    let projs = uniqueProjects;
    if (filterProgram) {
      const prog = programs.find((p: any) => p.id === filterProgram);
      if (prog) projs = projs.filter(p => p.programName === prog.name);
    }
    if (filterProject) projs = projs.filter(p => p.name === filterProject);
    return projs;
  }, [uniqueProjects, filterProgram, filterProject, programs]);

  // Collect all date-able items for range calculation
  const allDates: Date[] = React.useMemo(() => {
    const dates: Date[] = [];
    filteredProjects.forEach(proj => {
      proj.cycleIds.forEach(cid => {
        const c = Object.values(mockCycles).flat().find((x: any) => x.id === cid) as any;
        if (c?.startDate) dates.push(new Date(c.startDate));
        if (c?.endDate) dates.push(new Date(c.endDate));
      });
    });
    roadmapItems.forEach(item => {
      if (item.startDate) dates.push(new Date(item.startDate));
      if (item.endDate) dates.push(new Date(item.endDate));
      if (item.date) dates.push(new Date(item.date));
    });
    return dates;
  }, [filteredProjects, mockCycles, roadmapItems]);

  const today = React.useMemo(() => new Date(), []);
  const rangeStart = React.useMemo(() => {
    // Always show 6 months before today; extend if data reaches further back
    const sixMonthsBefore = new Date(today);
    sixMonthsBefore.setMonth(sixMonthsBefore.getMonth() - 6);
    if (!allDates.length) return sixMonthsBefore;
    const dataMin = new Date(Math.min(...allDates.map(x => x.getTime())));
    return new Date(Math.min(sixMonthsBefore.getTime(), dataMin.getTime()));
  }, [allDates, today]);
  const rangeEnd = React.useMemo(() => {
    // Always show 6 months after today; extend if data reaches further ahead
    const sixMonthsAfter = new Date(today);
    sixMonthsAfter.setMonth(sixMonthsAfter.getMonth() + 6);
    if (!allDates.length) return sixMonthsAfter;
    const dataMax = new Date(Math.max(...allDates.map(x => x.getTime())));
    return new Date(Math.max(sixMonthsAfter.getTime(), dataMax.getTime()));
  }, [allDates, today]);
  const totalDays = Math.max(1, (rangeEnd.getTime() - rangeStart.getTime()) / 86400000);
  const dateToX = (d: Date) => Math.max(0, Math.min(100, ((d.getTime() - rangeStart.getTime()) / 86400000 / totalDays) * 100));

  // These helpers depend on rangeStart/rangeEnd — must be declared after them
  const xToDate = React.useCallback((clientX: number): string => {
    const el = timelineRef.current;
    if (!el) return '';
    const rect = el.getBoundingClientRect();
    const pct = Math.max(0, Math.min(1, (clientX - rect.left) / rect.width));
    const ms = rangeStart.getTime() + pct * (rangeEnd.getTime() - rangeStart.getTime());
    const d = new Date(ms);
    return `${d.getFullYear()}-${String(d.getMonth()+1).padStart(2,'0')}-${String(d.getDate()).padStart(2,'0')}`;
  }, [rangeStart, rangeEnd]);

  const getIndicatorX = React.useCallback((clientX: number): number => {
    const el = timelineRef.current;
    if (!el) return 0;
    const rect = el.getBoundingClientRect();
    return Math.max(0, Math.min(100, ((clientX - rect.left) / rect.width) * 100));
  }, []);

  // Global mousemove/mouseup for drag
  React.useEffect(() => {
    if (!drag) return;
    const onMove = (e: MouseEvent) => {
      const date = xToDate(e.clientX);
      const ix = getIndicatorX(e.clientX);
      setDrag(prev => prev ? { ...prev, currentDate: date, indicatorX: ix } : null);
    };
    const onUp = async (e: MouseEvent) => {
      if (!drag) return;
      const finalDate = xToDate(e.clientX);
      if (drag.entityType === 'cycle') {
        const newStart = drag.handle === 'start' ? finalDate : drag.origStart;
        const newEnd   = drag.handle === 'end'   ? finalDate : drag.origEnd;
        await onSaveCycleDates(drag.id, newStart, newEnd);
      } else {
        setRoadmapItems(prev => {
          const updated = prev.map(x => x.id === drag.id ? {
            ...x,
            ...(drag.handle === 'start' ? { startDate: finalDate } : {}),
            ...(drag.handle === 'end'   ? { endDate:   finalDate } : {}),
            ...(drag.handle === 'date'  ? { date:      finalDate } : {}),
          } : x);
          apiClient.put('/api/hierarchy-preferences/global-process-areas', { roadmapItems: updated }).catch(() => {});
          return updated;
        });
      }
      setDrag(null);
    };
    document.addEventListener('mousemove', onMove);
    document.addEventListener('mouseup', onUp);
    return () => { document.removeEventListener('mousemove', onMove); document.removeEventListener('mouseup', onUp); };
  // eslint-disable-next-line react-hooks/exhaustive-deps
  }, [drag]);

  const months: { label: string; left: number }[] = React.useMemo(() => {
    const out: { label: string; left: number }[] = [];
    const cur = new Date(rangeStart.getFullYear(), rangeStart.getMonth(), 1);
    while (cur <= rangeEnd) {
      out.push({ label: cur.toLocaleDateString('en-US', { month: 'short', year: '2-digit' }), left: dateToX(cur) });
      cur.setMonth(cur.getMonth() + 1);
    }
    return out;
  }, [rangeStart, rangeEnd]);

  const todayX = dateToX(today);

  const TimelineBar = ({ startDate, endDate, color, label, subtitle, onClick, dashed = false, onStartDrag, onEndDrag }: {
    startDate?: string; endDate?: string; color: string; label: string; subtitle?: string;
    onClick?: () => void; dashed?: boolean;
    onStartDrag?: (e: React.MouseEvent) => void;
    onEndDrag?: (e: React.MouseEvent) => void;
  }) => {
    const hasS = !!startDate, hasE = !!endDate;
    const HANDLE = 8;
    const openEditFromTimeline = (e?: React.MouseEvent) => {
      e?.stopPropagation();
      onClick?.();
    };
    if (!hasS && !hasE) return (
      <Box
        onClick={openEditFromTimeline}
        onDoubleClick={openEditFromTimeline}
        sx={{ position: 'absolute', left: '4px', top: '50%', transform: 'translateY(-50%)', height: 26, px: 1.25, borderRadius: 1.5, border: `1px dashed rgba(255,255,255,0.2)`, cursor: 'pointer', display: 'flex', alignItems: 'center', zIndex: 5, pointerEvents: 'auto', '&:hover': { borderColor: color } }}
      >
        <Typography sx={{ fontSize: '0.7rem', color: 'text.disabled' }}>{label} — click to set dates</Typography>
      </Box>
    );
    const xS = hasS ? dateToX(new Date(startDate!)) : dateToX(new Date(endDate!)) - 2;
    const xE = hasE ? dateToX(new Date(endDate!)) : dateToX(new Date(startDate!)) + 2;
    const w = Math.max(1.5, xE - xS);
    return (
      <Box
        onClick={openEditFromTimeline}
        onDoubleClick={openEditFromTimeline}
        sx={{ position: 'absolute', left: `${xS}%`, width: `${w}%`, top: '50%', transform: 'translateY(-50%)', height: subtitle ? 34 : 26, borderRadius: 1.5, backgroundColor: `${color}28`, border: `1.5px ${dashed ? 'dashed' : 'solid'} ${color}88`, display: 'flex', alignItems: 'center', overflow: 'hidden', userSelect: 'none', zIndex: 4, pointerEvents: 'auto', cursor: onClick ? 'pointer' : 'default', '&:hover': { borderColor: color }, transition: 'border-color 0.12s' }}
      >
        {/* Left drag handle */}
        {onStartDrag && (
          <Box onMouseDown={e => { e.stopPropagation(); e.preventDefault(); onStartDrag(e); }}
            sx={{ position: 'absolute', left: 0, top: 0, bottom: 0, width: HANDLE, cursor: 'ew-resize', display: 'flex', alignItems: 'center', justifyContent: 'center', zIndex: 2, '&:hover > div': { backgroundColor: color } }}>
            <Box sx={{ width: 2, height: 12, backgroundColor: `${color}80`, borderRadius: 1, transition: 'background 0.1s' }} />
          </Box>
        )}
        {/* Label + optional subtitle — click opens modal */}
        <Box
          sx={{ flex: 1, px: onStartDrag ? `${HANDLE+4}px` : '8px', overflow: 'hidden', display: 'flex', flexDirection: 'column', justifyContent: 'center', gap: 0 }}
        >
          <Typography sx={{ fontWeight: 600, fontSize: '0.7rem', color, whiteSpace: 'nowrap', overflow: 'hidden', textOverflow: 'ellipsis', lineHeight: 1.2 }}>{label}</Typography>
          {subtitle && <Typography sx={{ fontSize: '0.58rem', color: `${color}99`, whiteSpace: 'nowrap', overflow: 'hidden', textOverflow: 'ellipsis', lineHeight: 1.1 }}>{subtitle}</Typography>}
        </Box>
        {/* Right drag handle */}
        {onEndDrag && (
          <Box onMouseDown={e => { e.stopPropagation(); e.preventDefault(); onEndDrag(e); }}
            sx={{ position: 'absolute', right: 0, top: 0, bottom: 0, width: HANDLE, cursor: 'ew-resize', display: 'flex', alignItems: 'center', justifyContent: 'center', zIndex: 2, '&:hover > div': { backgroundColor: color } }}>
            <Box sx={{ width: 2, height: 12, backgroundColor: `${color}80`, borderRadius: 1, transition: 'background 0.1s' }} />
          </Box>
        )}
      </Box>
    );
  };

  const rowSx = { position: 'relative' as const, height: 38 };
  const trackSx = { position: 'absolute' as const, left: 0, right: 0, top: '50%', transform: 'translateY(-50%)', height: '1px', backgroundColor: 'rgba(255,255,255,0.04)', pointerEvents: 'none' };

  const openAdd = (type: 'phase' | 'test-cycle' | 'milestone', projectKey?: string) => {
    const defaultColor = type === 'phase' ? PHASE_COLORS.planning : type === 'test-cycle' ? TEST_CYCLE_COLOR : MILESTONE_COLOR;
    setForm({
      type,
      projectKey: projectKey || forcedProjectName || uniqueProjects[0]?.name || '',
      color: defaultColor,
      subtype: type === 'phase' ? 'planning' : undefined,
      name: type === 'phase' ? 'Planning' : '',
    });
    setEditingItem(null);
    setAddDialog(type);
  };

  const openEditItem = (item: RoadmapItem) => {
    setLastRoadmapInteraction(`Edit requested: ${item.name || item.type}`);
    let inferredCycleId = item.linkedCycleId || '';
    if (item.type === 'test-cycle' && !inferredCycleId) {
      const project = uniqueProjects.find((p) => p.name === item.projectKey);
      const cycleCandidates = (project?.cycleIds || [])
        .map((cid) => Object.values(mockCycles).flat().find((c: any) => c.id === cid) as any)
        .filter(Boolean);
      const match = cycleCandidates.find((cycle: any) => {
        const phaseLabel = String(cycle.testPhase || cycle.description || cycle.name || '').trim().toLowerCase();
        return phaseLabel && phaseLabel === String(item.name || '').trim().toLowerCase();
      });
      inferredCycleId = match?.id || '';
    }

    setForm({ ...item, linkedCycleId: inferredCycleId });
    setEditingItem(item);
    setAddDialog(item.type);
  };

  const closeEditCycleDialog = React.useCallback((reason?: string) => {
    if (reason === 'backdropClick') return;
    setEditCycle(null);
  }, []);

  const closeRoadmapItemDialog = React.useCallback((reason?: string) => {
    if (reason === 'backdropClick') return;
    setAddDialog(null);
    setEditingItem(null);
    setForm({});
  }, []);

  const saveItem = async () => {
    if (!form.projectKey || !form.name?.trim() || !form.type) return;
    if (form.type === 'test-cycle' && !String((form as any).linkedCycleId || '').trim()) return;
    if (form.type !== 'milestone' && (!String(form.startDate || '').trim() || !String(form.endDate || '').trim())) return;
    setSavingItem(true);
    try {
      if (editingItem) {
        const updated = roadmapItems.map(x => x.id === editingItem.id ? { ...x, ...form, name: form.name!.trim() } as RoadmapItem : x);
        persistItems(updated);
      } else {
        const newItem: RoadmapItem = {
          id: `rm-${Date.now()}`,
          type: form.type!,
          projectKey: form.projectKey!,
          name: form.name!.trim(),
          linkedCycleId: String((form as any).linkedCycleId || '').trim() || undefined,
          color: form.color || '#667eea',
          startDate: form.startDate,
          endDate: form.endDate,
          date: form.date,
          subtype: form.subtype as any,
        };
        persistItems([...roadmapItems, newItem]);
      }
      closeRoadmapItemDialog();
    } finally { setSavingItem(false); }
  };

  const deleteItem = (id: string) => persistItems(roadmapItems.filter(x => x.id !== id));

  const selectedProjectCycleOptions = React.useMemo(() => {
    const selectedProject = uniqueProjects.find((p) => p.name === String(form.projectKey || '').trim());
    if (!selectedProject) return [] as any[];

    return selectedProject.cycleIds
      .map((cid) => Object.values(mockCycles).flat().find((c: any) => c.id === cid) as any)
      .filter(Boolean)
      .map((cycle: any) => ({
        id: cycle.id,
        label: String(cycle.testPhase || cycle.description || cycle.name || '').trim(),
        startDate: cycle.startDate ? String(cycle.startDate).substring(0, 10) : '',
        endDate: cycle.endDate ? String(cycle.endDate).substring(0, 10) : '',
      }))
      .filter((option) => option.label.length > 0);
  }, [form.projectKey, uniqueProjects, mockCycles]);

  // Lane helpers
  const getActRange = (actId: string, phases: RoadmapItem[], cycles: any[], testCycles: RoadmapItem[]): {start:string;end:string}|null => {
    const ph = phases.find(x => x.id === actId); if (ph?.startDate && ph?.endDate) return {start: ph.startDate, end: ph.endDate};
    const c = cycles.find(x => x.id === actId); if (c?.startDate && c?.endDate) return {start: c.startDate.substring(0,10), end: c.endDate.substring(0,10)};
    const tc = testCycles.find(x => x.id === actId); if (tc?.startDate && tc?.endDate) return {start: tc.startDate, end: tc.endDate};
    return null;
  };
  const rangesOverlap = (a:{start:string;end:string}, b:{start:string;end:string}) => !(a.end <= b.start || b.end <= a.start);

  // Greedy auto-packing for activities without explicit lane assignments
  const autoPackLanes = (actIds: string[], getRangeById: (id: string) => {start:string;end:string}|null): Record<string,number> => {
    const assign: Record<string,number> = {};
    const laneDates: Array<Array<{start:string;end:string}>> = [];
    actIds.forEach(id => {
      const range = getRangeById(id);
      if (!range) { assign[id] = laneDates.length; return; }
      let placed = false;
      for (let i = 0; i < laneDates.length; i++) {
        if (!laneDates[i].some(d => rangesOverlap(range, d))) {
          assign[id] = i; laneDates[i].push(range); placed = true; break;
        }
      }
      if (!placed) { assign[id] = laneDates.length; laneDates.push([range]); }
    });
    return assign;
  };

  // Check if placing actId onto laneIdx would overlap with existing occupants
  const laneHasOverlap = (projectKey: string, actId: string, laneIdx: number): boolean => {
    const cur = laneAssign[projectKey] || {};
    const sameLaneIds = Object.entries(cur).filter(([id, l]) => l === laneIdx && id !== actId).map(([id]) => id);
    const getRange = (id: string): {start:string;end:string}|null => {
      const ri = roadmapItems.find(x => x.id === id);
      if (ri?.startDate && ri?.endDate) return {start: ri.startDate, end: ri.endDate};
      const cyc = Object.values(mockCycles).flat().find((c: any) => c.id === id) as any;
      if (cyc?.startDate && cyc?.endDate) return {start: cyc.startDate.substring(0,10), end: cyc.endDate.substring(0,10)};
      return null;
    };
    const dragRange = getRange(actId);
    if (!dragRange) return false;
    return sameLaneIds.some(otherId => { const r = getRange(otherId); return r ? rangesOverlap(dragRange, r) : false; });
  };

  return (
    <Box sx={{ p: 2, display: 'flex', flexDirection: 'column', gap: 2 }}>
      {/* Update window snaps for the lane drag closure (avoids stale closure on roadmapItems/mockCycles) */}
      {(() => { (window as any).__roadmapItemsSnap = roadmapItems; (window as any).__mockCyclesSnap = Object.values(mockCycles).flat(); return null; })()}
      {/* Header */}
      <Box sx={{ display: 'flex', alignItems: 'flex-start', justifyContent: 'space-between', flexWrap: 'wrap', gap: 1.5 }}>
        <Box>
          <Typography variant="h5" sx={{ fontWeight: 700 }}>Roadmap</Typography>
          <Typography variant="caption" color="text.secondary">High-level timeline. Click or double-click bars to edit dates.</Typography>
          {lastRoadmapInteraction && (
            <Typography variant="caption" sx={{ display: 'block', color: 'rgba(255,255,255,0.48)', mt: 0.25 }}>
              {lastRoadmapInteraction}
            </Typography>
          )}
        </Box>
        <Box sx={{ display: 'flex', gap: 1, flexWrap: 'wrap' }}>
          {(['phase', 'test-cycle', 'milestone'] as const).map(t => (
            <Button key={t} size="small" variant="outlined" startIcon={t === 'milestone' ? <span>★</span> : <AddIcon sx={{ fontSize: '0.9rem !important' }} />}
              onClick={() => openAdd(t, forcedProjectName)}
              sx={{ textTransform: 'none', fontSize: '0.75rem', borderColor: 'rgba(255,255,255,0.2)', color: 'rgba(255,255,255,0.7)', '&:hover': { borderColor: 'white', color: 'white' } }}>
              {t === 'phase' ? 'Add Phase' : t === 'test-cycle' ? 'Add Test Cycle' : 'Add Milestone'}
            </Button>
          ))}
        </Box>
      </Box>

      {/* Filters */}
      {!hideFilters && (
      <Box sx={{ display: 'flex', gap: 1.5, flexWrap: 'wrap' }}>
        <Box component="select" value={filterProgram} onChange={(e: any) => { setFilterProgram(e.target.value); setFilterProject(''); }}
          sx={{ fontSize: '0.78rem', px: 1, py: 0.6, borderRadius: 1, border: '1px solid rgba(255,255,255,0.15)', backgroundColor: 'rgba(255,255,255,0.06)', color: '#DBE7FF', minWidth: 160, cursor: 'pointer' }}>
          <option value="">All Programs</option>
          {programs.map(p => <option key={p.id} value={p.id}>{p.name}</option>)}
        </Box>
        <Box component="select" value={filterProject} onChange={(e: any) => setFilterProject(e.target.value)}
          sx={{ fontSize: '0.78rem', px: 1, py: 0.6, borderRadius: 1, border: '1px solid rgba(255,255,255,0.15)', backgroundColor: 'rgba(255,255,255,0.06)', color: '#DBE7FF', minWidth: 160, cursor: 'pointer' }}>
          <option value="">All Projects</option>
          {uniqueProjects.map(p => <option key={p.name} value={p.name}>{p.name}</option>)}
        </Box>
        {(filterProgram || filterProject) && (
          <Button size="small" variant="text" onClick={() => { setFilterProgram(''); setFilterProject(''); }} sx={{ textTransform: 'none', color: 'text.secondary', fontSize: '0.75rem' }}>Clear</Button>
        )}
      </Box>
      )}

      {/* Timeline card — tall, horizontally scrollable */}
      <Box ref={scrollContainerRef} sx={{ backgroundColor: 'rgba(255,255,255,0.03)', border: '1px solid rgba(255,255,255,0.1)', borderRadius: 2, p: 2, overflowX: 'auto', overflowY: 'auto', minHeight: '60vh', maxHeight: '80vh' }}>
        <Box ref={timelineRef} sx={{ minWidth: Math.max(900, totalDays * 3), position: 'relative' }}>
          {/* Month header */}
          <Box sx={{ position: 'relative', height: 24, mb: 1, borderBottom: '1px solid rgba(255,255,255,0.08)' }}>
            {months.map((m, i) => (
              <React.Fragment key={i}>
                <Typography sx={{ position: 'absolute', left: `${m.left}%`, fontSize: '0.62rem', color: 'rgba(255,255,255,0.38)', fontWeight: 600, whiteSpace: 'nowrap' }}>{m.label}</Typography>
                <Box sx={{ position: 'absolute', left: `${m.left}%`, top: 0, bottom: -9999, width: '1px', backgroundColor: 'rgba(255,255,255,0.05)', zIndex: 0, pointerEvents: 'none' }} />
              </React.Fragment>
            ))}
            {todayX >= 0 && todayX <= 100 && (
              <Box sx={{ position: 'absolute', left: `${todayX}%`, top: 0, bottom: -9999, width: '2px', backgroundColor: 'rgba(102,126,234,0.55)', zIndex: 1, pointerEvents: 'none' }}>
                <Box sx={{ position: 'absolute', top: 0, left: -10, fontSize: '0.6rem', color: '#667eea', fontWeight: 700, whiteSpace: 'nowrap', background: 'rgba(20,30,53,0.9)', px: 0.5, borderRadius: 0.5 }}>Today</Box>
              </Box>
            )}
            {/* Drag indicator */}
            {drag && (
              <Box sx={{ position: 'absolute', left: `${drag.indicatorX}%`, top: 0, bottom: 0, width: '2px', backgroundColor: '#ffa726', zIndex: 20, pointerEvents: 'none' }}>
                <Box sx={{ position: 'absolute', top: 2, left: 4, backgroundColor: '#ffa726', color: '#000', fontSize: '0.62rem', fontWeight: 800, px: 0.6, py: 0.2, borderRadius: 0.5, whiteSpace: 'nowrap' }}>
                  {drag.currentDate}
                </Box>
              </Box>
            )}
          </Box>

          {/* Rows — grouped by project */}
          {filteredProjects.map(proj => {
            const cycles = proj.cycleIds
              .map(cid => Object.values(mockCycles).flat().find((c: any) => c.id === cid))
              .filter(Boolean) as any[];
            const projAccent = proj.programAccent;
            const projItems = roadmapItems.filter(x => x.projectKey === proj.name);
            const phases = projItems.filter(x => x.type === 'phase');
            const testCycles = projItems.filter(x => x.type === 'test-cycle');
            const milestones = projItems.filter(x => x.type === 'milestone');
            // Build per-activity rows list
            const allActs = [
              ...phases.map(ph => ({ id: ph.id, kind: 'phase' as const })),
              ...cycles.map(c => ({ id: c.id, kind: 'cycle' as const })),
              ...testCycles.map(tc => ({ id: tc.id, kind: 'test-cycle' as const })),
            ];
            // Get or auto-compute lane assignments
            // Always auto-pack first (base), then apply explicit saved overrides on top
            const autoPacked = autoPackLanes(allActs.map(a => a.id), id => getActRange(id, phases, cycles, testCycles));
            const curAssign = laneAssign[proj.name] || {};
            // Merge: start from auto-pack, override with any explicitly saved lane assignments
            const laneMap: Record<string, number> = { ...autoPacked, ...curAssign };
            fullLaneMapsRef.current[proj.name] = laneMap; // keep ref for save in drag handler
            // Group into lanes
            const maxLane = Math.max(-1, ...allActs.map(a => laneMap[a.id] ?? 0));
            const lanes: Array<typeof allActs> = Array.from({ length: maxLane + 1 }, () => []);
            allActs.forEach(a => { const l = laneMap[a.id] ?? 0; if (lanes[l]) lanes[l].push(a); else lanes[l] = [a]; });

            // Grip handle — calls startLaneDrag directly (no effect delay)
            const ActGrip = ({ actId, fromLane }: { actId: string; fromLane: number }) => (
              <Box onMouseDown={e => startLaneDrag(e, actId, proj.name, fromLane, lanes.length)}
                sx={{ position: 'absolute', left: -18, top: '50%', transform: 'translateY(-50%)', width: 14, cursor: actDrag ? 'grabbing' : 'ns-resize', color: 'rgba(255,255,255,0.25)', fontSize: '0.78rem', lineHeight: 1, userSelect: 'none', '&:hover': { color: 'rgba(255,255,255,0.55)' }, zIndex: 3 }}>
                ⠿
              </Box>
            );

            return (
              <Box key={proj.name} sx={{ mb: 1.5, pl: 2 }}>
                {/* Project header */}
                <Box sx={{ display: 'flex', alignItems: 'baseline', gap: 1, py: 0.4, px: 0.5, mb: 0.25 }}>
                  <Box sx={{ width: 8, height: 8, borderRadius: '50%', backgroundColor: projAccent, flexShrink: 0, mt: 0.25 }} />
                  <Typography sx={{ fontWeight: 800, color: projAccent, fontSize: '0.72rem', textTransform: 'uppercase', letterSpacing: '0.08em' }}>{proj.name}</Typography>
                  <Typography sx={{ fontSize: '0.6rem', color: 'rgba(255,255,255,0.3)', fontWeight: 500 }}>{proj.programName}</Typography>
                </Box>

                {/* Activity lanes — each lane = one row, can hold multiple non-overlapping bars */}
                {lanes.map((laneActs, laneIdx) => {
                  const isDropTarget = laneDragOver?.projectKey === proj.name && laneDragOver?.laneIdx === laneIdx;
                  const showInsertBefore = laneDragOver?.projectKey === proj.name && laneDragOver?.laneIdx === laneIdx && actDrag;
                  return (
                    <Box key={laneIdx} data-lane-idx={String(laneIdx)} data-project-key={proj.name}
                      sx={{ ...rowSx, mb: 0.5, position: 'relative', borderRadius: 1,
                        ml: '-20px', pl: '20px', // extend left to cover the grip handle
                        outline: isDropTarget ? '2px solid #667eea' : 'none',
                        backgroundColor: isDropTarget ? 'rgba(102,126,234,0.1)' : 'transparent',
                      }}>
                      <Box sx={trackSx} />
                      {laneActs.map(row => {
                        const opacity = actDrag?.actId === row.id ? 0.35 : 1;
                        if (row.kind === 'phase') {
                          const ph = phases.find(p => p.id === row.id)!;
                          if (!ph) return null;
                          const dispStart = drag?.id === ph.id && drag?.handle === 'start' ? drag.currentDate : ph.startDate;
                          const dispEnd   = drag?.id === ph.id && drag?.handle === 'end'   ? drag.currentDate : ph.endDate;
                          return (
                            <React.Fragment key={ph.id}>
                              <ActGrip actId={ph.id} fromLane={laneIdx} />
                              <Box sx={{ opacity }}>
                                <TimelineBar startDate={dispStart} endDate={dispEnd} color={ph.color} label={`▐ ${ph.name}`} onClick={() => openEditItem(ph)}
                                  subtitle={`${proj.programName} · ${proj.name}`}
                                  onStartDrag={e => setDrag({ id: ph.id, entityType: 'roadmap', handle: 'start', currentDate: ph.startDate || '', indicatorX: getIndicatorX(e.clientX), origStart: ph.startDate || '', origEnd: ph.endDate || '' })}
                                  onEndDrag={e => setDrag({ id: ph.id, entityType: 'roadmap', handle: 'end', currentDate: ph.endDate || '', indicatorX: getIndicatorX(e.clientX), origStart: ph.startDate || '', origEnd: ph.endDate || '' })}
                                />
                              </Box>
                            </React.Fragment>
                          );
                        }
                        if (row.kind === 'cycle') {
                          const c = cycles.find(x => x.id === row.id);
                          if (!c) return null;
                          const accent = c.accentColor || projAccent;
                          const dispStart = drag?.id === c.id && drag?.handle === 'start' ? drag.currentDate : c.startDate?.substring(0, 10);
                          const dispEnd   = drag?.id === c.id && drag?.handle === 'end'   ? drag.currentDate : c.endDate?.substring(0, 10);
                          return (
                            <React.Fragment key={c.id}>
                              <ActGrip actId={c.id} fromLane={laneIdx} />
                              <Box sx={{ opacity }}>
                                <TimelineBar startDate={dispStart} endDate={dispEnd} color={accent} label={c.name}
                                  subtitle={`${proj.programName} · ${proj.name}`}
                                  onClick={() => {
                                    setLastRoadmapInteraction(`Edit requested: ${c.name}`);
                                    setEditCycle(c);
                                    setEditStart(c.startDate?.substring(0, 10) || '');
                                    setEditEnd(c.endDate?.substring(0, 10) || '');
                                  }}
                                  onStartDrag={e => setDrag({ id: c.id, entityType: 'cycle', handle: 'start', currentDate: c.startDate?.substring(0, 10) || '', indicatorX: getIndicatorX(e.clientX), origStart: c.startDate?.substring(0, 10) || '', origEnd: c.endDate?.substring(0, 10) || '' })}
                                  onEndDrag={e => setDrag({ id: c.id, entityType: 'cycle', handle: 'end', currentDate: c.endDate?.substring(0, 10) || '', indicatorX: getIndicatorX(e.clientX), origStart: c.startDate?.substring(0, 10) || '', origEnd: c.endDate?.substring(0, 10) || '' })}
                                />
                              </Box>
                            </React.Fragment>
                          );
                        }
                        if (row.kind === 'test-cycle') {
                          const tc = testCycles.find(x => x.id === row.id)!;
                          if (!tc) return null;
                          const dispStart = drag?.id === tc.id && drag?.handle === 'start' ? drag.currentDate : tc.startDate;
                          const dispEnd   = drag?.id === tc.id && drag?.handle === 'end'   ? drag.currentDate : tc.endDate;
                          return (
                            <React.Fragment key={tc.id}>
                              <ActGrip actId={tc.id} fromLane={laneIdx} />
                              <Box sx={{ opacity }}>
                                <TimelineBar startDate={dispStart} endDate={dispEnd} color={tc.color} label={`◆ ${tc.name}`} onClick={() => openEditItem(tc)} dashed
                                  subtitle={`${proj.programName} · ${proj.name}`}
                                  onStartDrag={e => setDrag({ id: tc.id, entityType: 'roadmap', handle: 'start', currentDate: tc.startDate || '', indicatorX: getIndicatorX(e.clientX), origStart: tc.startDate || '', origEnd: tc.endDate || '' })}
                                  onEndDrag={e => setDrag({ id: tc.id, entityType: 'roadmap', handle: 'end', currentDate: tc.endDate || '', indicatorX: getIndicatorX(e.clientX), origStart: tc.startDate || '', origEnd: tc.endDate || '' })}
                                />
                              </Box>
                            </React.Fragment>
                          );
                        }
                        return null;
                      })}
                    </Box>
                  );
                })}

                {/* New lane drop zone (always shown at bottom during drag) */}
                {actDrag?.projectKey === proj.name && (
                  <Box data-new-lane={proj.name} data-lane-idx={String(lanes.length)} data-project-key={proj.name}
                    sx={{ height: 28, borderRadius: 1, border: `1px dashed ${laneDragOver?.laneIdx === lanes.length || laneDragOver?.laneIdx === -1 ? '#667eea' : 'rgba(255,255,255,0.12)'}`,
                      backgroundColor: (laneDragOver?.laneIdx === lanes.length || laneDragOver?.laneIdx === -1) ? 'rgba(102,126,234,0.08)' : 'transparent',
                      mb: 0.5, display: 'flex', alignItems: 'center', px: 1 }}>
                    <Typography sx={{ fontSize: '0.65rem', color: 'rgba(255,255,255,0.3)' }}>+ New lane</Typography>
                  </Box>
                )}

                {/* Milestone row (separate, always last) */}
                {milestones.length > 0 && (
                  <Box sx={{ ...rowSx, mb: 0.25, position: 'relative' }}>
                    <Box sx={trackSx} />
                    {milestones.map(ms => {
                      const dispDate = drag?.id === ms.id && drag?.handle === 'date' ? drag.currentDate : ms.date;
                      const x = dispDate ? dateToX(new Date(dispDate)) : null;
                      if (x === null) return null;
                      return (
                        <Box key={ms.id}
                          onClick={() => openEditItem(ms)}
                          onDoubleClick={() => openEditItem(ms)}
                          title={ms.name}
                          sx={{ position: 'absolute', left: `${x}%`, top: '50%', transform: 'translate(-50%, -50%)', cursor: 'pointer', display: 'flex', flexDirection: 'column', alignItems: 'center', userSelect: 'none', zIndex: 6, pointerEvents: 'auto' }}>
                          <Typography sx={{ fontSize: '1.1rem', color: ms.color, lineHeight: 1, filter: 'drop-shadow(0 0 4px currentColor)', pointerEvents: 'none' }}>★</Typography>
                          <Typography sx={{ fontSize: '0.58rem', color: ms.color, whiteSpace: 'nowrap', fontWeight: 700, mt: -0.25, pointerEvents: 'none' }}>{ms.name}</Typography>
                        </Box>
                      );
                    })}
                  </Box>
                )}
              </Box>
            );
          })}

          {filteredProjects.length === 0 && (
            <Box sx={{ py: 6, textAlign: 'center', color: 'text.disabled' }}>
              <Typography variant="body2">No projects match the selected filters.</Typography>
            </Box>
          )}
        </Box>
      </Box>

      {/* Edit mock cycle dates dialog */}
      <Dialog
        open={!!editCycle}
        onClose={(_, reason) => closeEditCycleDialog(reason)}
        maxWidth="xs"
        fullWidth
      >
        <DialogTitle sx={{ pb: 1 }}>
          Edit Mock Cycle Dates
          <Typography variant="caption" sx={{ display: 'block', color: 'text.secondary', mt: 0.25 }}>{editCycle?.name || ''}</Typography>
        </DialogTitle>
        <DialogContent>
          <Box sx={{ pt: 0.5, display: 'flex', flexDirection: 'column', gap: 1.25 }}>
            {[['Start Date', editStart, setEditStart], ['End Date', editEnd, setEditEnd]].map(([label, val, setter]: any) => (
              <TextField
                key={label as string}
                size="small"
                label={label as string}
                type="date"
                value={val as string}
                onChange={(e) => setter(e.target.value)}
                InputLabelProps={{ shrink: true }}
              />
            ))}
          </Box>
        </DialogContent>
        <DialogActions>
          <Button size="small" onClick={() => closeEditCycleDialog()} sx={{ textTransform: 'none' }}>Cancel</Button>
          <Button
            size="small"
            variant="contained"
            disabled={savingCycle || !editCycle?.id}
            onClick={async () => {
              if (!editCycle?.id) return;
              setSavingCycle(true);
              try {
                await onSaveCycleDates(editCycle.id, editStart, editEnd);
                setEditCycle(null);
              } finally {
                setSavingCycle(false);
              }
            }}
            sx={{ textTransform: 'none' }}
          >
            {savingCycle ? 'Saving…' : 'Save'}
          </Button>
        </DialogActions>
      </Dialog>

      {/* Add/Edit phase, test-cycle, milestone dialog */}
      <Dialog
        open={!!addDialog}
        onClose={(_, reason) => closeRoadmapItemDialog(reason)}
        maxWidth="sm"
        fullWidth
      >
        <DialogTitle>
          {editingItem ? 'Edit' : 'Add'} {addDialog === 'phase' ? 'Phase' : addDialog === 'test-cycle' ? 'Test Cycle' : 'Milestone'}
        </DialogTitle>
        <DialogContent>
          <Box sx={{ pt: 0.5, display: 'flex', flexDirection: 'column', gap: 1.75 }}>
              {/* Project */}
              <Box>
                <Typography variant="caption" color="text.secondary" sx={{ mb: 0.5, display: 'block' }}>Project</Typography>
                <Box component="select" value={form.projectKey || ''} onChange={(e: any) => setForm(p => ({ ...p, projectKey: e.target.value }))}
                  disabled={!!forcedProjectName}
                  style={{ width: '100%', padding: '8px 10px', borderRadius: 6, border: '1px solid rgba(255,255,255,0.2)', backgroundColor: 'rgba(255,255,255,0.06)', color: '#DBE7FF', fontSize: '0.85rem' }}>
                  {(forcedProjectName
                    ? uniqueProjects.filter((p) => p.name === forcedProjectName)
                    : uniqueProjects
                  ).map(p => <option key={p.name} value={p.name}>{p.name}</option>)}
                </Box>
              </Box>
              {/* Name / Subtype */}
              {addDialog === 'phase' ? (
                <Box>
                  <Typography variant="caption" color="text.secondary" sx={{ mb: 0.5, display: 'block' }}>Phase Type</Typography>
                  <Box sx={{ display: 'flex', gap: 1 }}>
                    {(['planning', 'design', 'build'] as const).map(st => (
                      <Box key={st} onClick={() => setForm(p => ({ ...p, subtype: st, name: st.charAt(0).toUpperCase() + st.slice(1), color: PHASE_COLORS[st] }))}
                        sx={{ flex: 1, py: 0.75, textAlign: 'center', borderRadius: 1, cursor: 'pointer', border: `1.5px solid ${form.subtype === st ? PHASE_COLORS[st] : 'rgba(255,255,255,0.15)'}`, backgroundColor: form.subtype === st ? `${PHASE_COLORS[st]}22` : 'transparent', color: form.subtype === st ? PHASE_COLORS[st] : 'rgba(255,255,255,0.5)', fontSize: '0.8rem', fontWeight: 600 }}>
                        {st.charAt(0).toUpperCase() + st.slice(1)}
                      </Box>
                    ))}
                  </Box>
                </Box>
              ) : (
                <Box>
                  {addDialog === 'test-cycle' ? (
                    <>
                      <Typography variant="caption" color="text.secondary" sx={{ mb: 0.5, display: 'block' }}>Test Phase (from Mock Cycles)</Typography>
                      <Box
                        component="select"
                        value={(form as any).linkedCycleId || ''}
                        onChange={(e: any) => {
                          const selectedId = String(e.target.value || '').trim();
                          const selected = selectedProjectCycleOptions.find((option) => option.id === selectedId);
                          setForm((prev) => ({
                            ...prev,
                            linkedCycleId: selectedId,
                            name: selected?.label || '',
                            startDate: selected?.startDate || '',
                            endDate: selected?.endDate || '',
                          }));
                        }}
                        style={{ width: '100%', padding: '8px 10px', borderRadius: 6, border: '1px solid rgba(255,255,255,0.2)', backgroundColor: 'rgba(255,255,255,0.06)', color: '#DBE7FF', fontSize: '0.85rem' }}
                      >
                        <option value="">Select a test phase</option>
                        {selectedProjectCycleOptions.map((option) => (
                          <option key={option.id} value={option.id}>{option.label}</option>
                        ))}
                      </Box>
                    </>
                  ) : (
                    <>
                      <Typography variant="caption" color="text.secondary" sx={{ mb: 0.5, display: 'block' }}>Name</Typography>
                      <input value={form.name || ''} onChange={e => setForm(p => ({ ...p, name: e.target.value }))} placeholder={addDialog === 'milestone' ? 'e.g. Go Live' : 'e.g. UAT'}
                        style={{ width: '100%', padding: '8px 10px', borderRadius: 6, border: '1px solid rgba(255,255,255,0.2)', backgroundColor: 'rgba(255,255,255,0.06)', color: '#DBE7FF', fontSize: '0.85rem', boxSizing: 'border-box' }} />
                    </>
                  )}
                </Box>
              )}
              {/* Dates */}
              {addDialog === 'milestone' ? (
                <Box>
                  <Typography variant="caption" color="text.secondary" sx={{ mb: 0.5, display: 'block' }}>Date</Typography>
                  <input type="date" value={form.date || ''} onChange={e => setForm(p => ({ ...p, date: e.target.value }))}
                    style={{ width: '100%', padding: '8px 10px', borderRadius: 6, border: '1px solid rgba(255,255,255,0.2)', backgroundColor: 'rgba(255,255,255,0.06)', color: '#DBE7FF', fontSize: '0.85rem', boxSizing: 'border-box' }} />
                </Box>
              ) : (
                <Box sx={{ display: 'grid', gridTemplateColumns: '1fr 1fr', gap: 1.5 }}>
                  {[['Start Date', 'startDate'], ['End Date', 'endDate']].map(([label, key]) => (
                    <Box key={key}>
                      <Typography variant="caption" color="text.secondary" sx={{ mb: 0.5, display: 'block' }}>{label}</Typography>
                      <input type="date" value={(form as any)[key] || ''} onChange={e => setForm(p => ({ ...p, [key]: e.target.value }))}
                        style={{ width: '100%', padding: '8px 10px', borderRadius: 6, border: '1px solid rgba(255,255,255,0.2)', backgroundColor: 'rgba(255,255,255,0.06)', color: '#DBE7FF', fontSize: '0.85rem', boxSizing: 'border-box' }} />
                    </Box>
                  ))}
                </Box>
              )}
              {/* Color */}
              {addDialog !== 'phase' && (
                <Box>
                  <Typography variant="caption" color="text.secondary" sx={{ mb: 0.5, display: 'block' }}>Color</Typography>
                  <Box sx={{ display: 'flex', gap: 1, alignItems: 'center' }}>
                    <input type="color" value={form.color || '#667eea'} onChange={e => setForm(p => ({ ...p, color: e.target.value }))} style={{ width: 40, height: 32, border: 'none', borderRadius: 4, cursor: 'pointer', backgroundColor: 'transparent' }} />
                    <Typography variant="caption" sx={{ color: 'text.secondary', fontFamily: 'monospace' }}>{form.color}</Typography>
                  </Box>
                </Box>
              )}
          </Box>
        </DialogContent>
        <DialogActions>
          {editingItem && (
            <Button size="small" onClick={() => { deleteItem(editingItem.id); closeRoadmapItemDialog(); }} sx={{ textTransform: 'none', color: '#ef5350', mr: 'auto' }}>Delete</Button>
          )}
          <Button size="small" onClick={() => closeRoadmapItemDialog()} sx={{ textTransform: 'none' }}>Cancel</Button>
          <Button
            size="small"
            variant="contained"
            disabled={
              savingItem
              || !form.name?.trim()
              || !form.projectKey
              || (addDialog === 'test-cycle' && !String((form as any).linkedCycleId || '').trim())
              || (addDialog !== 'milestone' && (!String(form.startDate || '').trim() || !String(form.endDate || '').trim()))
            }
            onClick={saveItem}
            sx={{ textTransform: 'none' }}
          >
            {savingItem ? 'Saving…' : editingItem ? 'Update' : 'Add'}
          </Button>
        </DialogActions>
      </Dialog>
    </Box>
  );
};
const planningViewToTab: Record<string, number> = {
  plan: 0,
  design: 0,
  strategy: 8,
  inventory: 1,
  structure: 6,
  roadmap: 7,
};

const normalizeDesignBuildTaskType = (value: unknown): DesignBuildTaskType => {
  return String(value || '').toLowerCase() === 'design' ? 'Design' : 'Build';
};

const normalizeTaskOptions = (rawTasks: any): DesignBuildEstimationTaskOption[] => {
  if (!Array.isArray(rawTasks)) return DEFAULT_DESIGN_BUILD_ESTIMATION_TASKS;
  const mapped = rawTasks.map((task: any, index: number) => ({
    id: String(task?.id || '').trim() || `task-${Date.now()}-${index}`,
    label: String(task?.label || task?.taskName || '').trim(),
    taskType: normalizeDesignBuildTaskType(task?.taskType),
  })).filter((task) => task.label.length > 0);
  return mapped.length > 0 ? mapped : DEFAULT_DESIGN_BUILD_ESTIMATION_TASKS;
};

const normalizeEstimationRows = (rawRows: any, taskOptions: DesignBuildEstimationTaskOption[]): DesignBuildEstimationRow[] => {
  if (!Array.isArray(rawRows)) return DEFAULT_DESIGN_BUILD_ESTIMATION_ROWS;
  const taskIds = new Set(taskOptions.map((task) => task.id));
  const mapped = rawRows.map((row: any, index: number) => {
    const legacyTaskName = String(row?.taskName || '').trim();
    const inferredTaskId = DESIGN_BUILD_TASK_ID_BY_NAME[legacyTaskName.toLowerCase()] || '';
    const rawTaskId = String(row?.taskId || '').trim();
    const resolvedTaskId = taskIds.has(rawTaskId)
      ? rawTaskId
      : taskIds.has(inferredTaskId)
        ? inferredTaskId
        : taskOptions[0]?.id || '';
    const resolvedTaskName = taskOptions.find((task) => task.id === resolvedTaskId)?.label || legacyTaskName || '';
    return {
      id: row?.id || `${Date.now()}-${index}`,
      buildType: String(row?.buildType || ''),
      factorType: String(row?.factorType || ''),
      complexity: String(row?.complexity || ''),
      taskId: resolvedTaskId,
      taskName: resolvedTaskName,
      hours: Number(row?.hours) || 0,
    };
  });
  return mapped.length > 0 ? mapped : DEFAULT_DESIGN_BUILD_ESTIMATION_ROWS;
};

// Helper component: renders the date-range + On Target/Behind summary for a sub-object row
const SubObjectTimeline: React.FC<{ tasks: any[]; status?: string }> = ({ tasks, status }) => {
  if (!tasks || tasks.length === 0) return null;
  const mn = ['Jan','Feb','Mar','Apr','May','Jun','Jul','Aug','Sep','Oct','Nov','Dec'];
  let minMs: number | null = null;
  let maxMs: number | null = null;
  let minD: Date | null = null;
  let maxD: Date | null = null;
  for (const t of tasks) {
    const parseV = (v?: string) => {
      if (!v) return null;
      const s = String(v).substring(0, 10);
      const parts = s.split('-');
      if (parts.length !== 3) return null;
      const d = new Date(Number(parts[0]), Number(parts[1]) - 1, Number(parts[2]));
      return isNaN(d.getTime()) ? null : d;
    };
    const s = parseV(t.startDate);
    const e = parseV(t.endDate);
    if (s) { const ms = s.getTime(); if (minMs === null || ms < minMs) { minMs = ms; minD = s; } }
    if (e) { const ms = e.getTime(); if (maxMs === null || ms > maxMs) { maxMs = ms; maxD = e; } }
  }
  if (!minD || !maxD) return null;
  const str = mn[minD.getMonth()] + ' ' + minD.getDate() + ' \u2192 ' + mn[maxD.getMonth()] + ' ' + maxD.getDate();
  const behind = new Date() > maxD || status === 'blocked';
  return (
    <Box sx={{ px: 2.5, py: 0.4, display: 'flex', alignItems: 'center', gap: 1, backgroundColor: 'rgba(255,255,255,0.02)', borderTop: '1px solid rgba(255,255,255,0.05)' }}>
      <Typography variant="caption" sx={{ color: 'text.disabled', fontSize: '0.7rem', fontWeight: 500 }}>{str}</Typography>
      <Box sx={{ width: 12, height: 12, borderRadius: '50%', backgroundColor: behind ? 'rgba(255,152,0,0.3)' : 'rgba(76,175,80,0.3)', display: 'flex', alignItems: 'center', justifyContent: 'center', color: behind ? '#FFA726' : '#66BB6A', fontSize: '0.6rem', fontWeight: 'bold' }}>
        {behind ? '\u26a0' : '\u2713'}
      </Box>
      <Typography variant="caption" sx={{ color: behind ? '#FFA726' : '#66BB6A', fontSize: '0.65rem' }}>{behind ? 'Behind' : 'On Target'}</Typography>
    </Box>
  );
};

