  const inventoryProjects = React.useMemo(() => {
    const seen = new Set<string>();
    const unique: Project[] = [];
    Object.values(projectsByProgram).flat().forEach((project: any) => {
      const nameKey = (project.name || '').trim().toLowerCase();
      const dedupeKey = `${project.programId || ''}::${nameKey || project.id}`;
      if (!seen.has(dedupeKey)) {
        seen.add(dedupeKey);
        unique.push(project);
      }
    });
    return unique;
  }, [projectsByProgram]);

  const inventoryProjectsForSelectedProgram = React.useMemo(() => {
    if (!selectedInventoryProgramId) return inventoryProjects;
    return inventoryProjects.filter((project: Project) => project.programId === selectedInventoryProgramId);
  }, [inventoryProjects, selectedInventoryProgramId]);

  useEffect(() => {
    if (programs.length === 0) {
      if (selectedInventoryProgramId !== '') setSelectedInventoryProgramId('');
      return;
    }

    const stillExists = selectedInventoryProgramId
      ? programs.some((program: Program) => program.id === selectedInventoryProgramId)
      : false;

    if (!stillExists) {
      setSelectedInventoryProgramId(programs[0].id);
    }
  }, [programs, selectedInventoryProgramId]);

  useEffect(() => {
    if (inventoryProjectsForSelectedProgram.length === 0) {
      if (selectedProjectForInventory !== null) setSelectedProjectForInventory(null);
      return;
    }

    const stillExists = selectedProjectForInventory
      ? inventoryProjectsForSelectedProgram.some((project) => project.id === selectedProjectForInventory)
      : false;

    if (!stillExists) {
      setSelectedProjectForInventory(inventoryProjectsForSelectedProgram[0].id);
    }
  }, [inventoryProjectsForSelectedProgram, selectedProjectForInventory]);

  useEffect(() => {
    const loadHierarchySummaries = async () => {
      // Build a map of (projectId, cycleId) pairs for cycle-scoped data
      // Use composite key to handle projects with multiple cycles
      const projectCyclePairs: Array<[string, string]> = [];
      for (const [cycleId, projects] of Object.entries(projectsByMockCycle)) {
        for (const project of projects as any[]) {
          projectCyclePairs.push([project.id, cycleId]);
        }
      }

      if (projectCyclePairs.length === 0) {
        setProjectHierarchySummaries({});
        return;
      }

      try {
        const entries = await Promise.all(projectCyclePairs.map(async ([projectId, cycleId]) => {
          const compositeKey = `${projectId}_${cycleId}`;
          if (!cycleId) return [compositeKey, { processAreas: {}, projectProgressPct: 0, projectObjectCount: 0, projectTaskGroupCount: 0 }] as const;
          const [objectsRes, groupsRes, tasksRes] = await Promise.all([
            apiClient.get(`/api/project-objects/cycle/${cycleId}`),
            apiClient.get(`/api/tasks/groups/cycle/${cycleId}`),
            apiClient.get(`/api/tasks/cycle/${cycleId}`),
          ]);

          const objects = objectsRes.data?.data || [];
          const groups = groupsRes.data?.data || [];
          const tasks = tasksRes.data?.data || [];

          const processAreaSummary: Record<string, { objectCount: number; taskGroupCount: number; taskCount: number; progressPct: number }> = {};
          const objectAreaMap = new Map<string, string>();
          const groupAreaMap = new Map<string, string>();

          objects.forEach((obj: any) => {
            const area = (obj.processArea || '').trim();
            if (!area) return;
            objectAreaMap.set(obj.id, area);
            if (!processAreaSummary[area]) processAreaSummary[area] = { objectCount: 0, taskGroupCount: 0, taskCount: 0, progressPct: 0 };
            processAreaSummary[area].objectCount += 1;
          });

          groups.forEach((group: any) => {
            const area = (group.processArea || '').trim();
            if (!area) return;
            groupAreaMap.set(group.id, area);
            if (!processAreaSummary[area]) processAreaSummary[area] = { objectCount: 0, taskGroupCount: 0, taskCount: 0, progressPct: 0 };
            processAreaSummary[area].taskGroupCount += 1;
          });

          const progressBuckets: Record<string, number[]> = {};
          tasks.forEach((task: any) => {
            const taskArea = (task.processArea || '').trim();
            const objectArea = task.projectObjectId ? objectAreaMap.get(task.projectObjectId) : null;
            const groupArea = task.taskGroupId ? groupAreaMap.get(task.taskGroupId) : null;
            const area = taskArea || objectArea || groupArea || null;
            if (!area) return;
            if (!progressBuckets[area]) progressBuckets[area] = [];
            progressBuckets[area].push(getEffectiveTaskProgress(task));
          });

          Object.keys(processAreaSummary).forEach((area) => {
            const values = progressBuckets[area] || [];
            processAreaSummary[area].taskCount = values.length;
            processAreaSummary[area].progressPct = values.length > 0 ? getProgressAverage(values) : 0;
          });

          const projectProgressPct = tasks.length > 0
            ? getProgressAverage(tasks.map((task: any) => getEffectiveTaskProgress(task)))
            : 0;

          return [compositeKey, {
            processAreas: processAreaSummary,
            projectProgressPct,
            projectObjectCount: objects.length,
            projectTaskGroupCount: groups.length,
          }] as const;
        }));

        setProjectHierarchySummaries(Object.fromEntries(entries));
      } catch (error) {
        console.error('Failed to load hierarchy summaries:', error);
      }
    };

    loadHierarchySummaries();
  }, [projectsByMockCycle]);

  // Keep inventory and plan project contexts isolated.
  const activeProjectId = canAccessInventory && tabValue === 1
    ? selectedProjectForInventory
    : (selectedItem?.type === 'project'
      ? selectedItem.id
      : selectedItem?.type === 'deliverable'
        ? selectedItem.projectId
      : selectedItem?.type === 'deliverableProcessArea'
        ? selectedItem.projectId
      : selectedItem?.type === 'processArea'
        ? selectedItem.projectId
        : selectedItem?.type === 'cycle'
          ? (selectedItem.projectId || null)
          : null);
  const selectedCycleProjectId = selectedItem?.type === 'cycle'
    ? (selectedItem.projectId || null)
    : selectedItem?.type === 'processArea'
      ? selectedItem.projectId
      : null;
  const activeCycleId = selectedItem?.type === 'project'
    ? (selectedItem.cycleId || null)
    : selectedItem?.type === 'deliverable'
      ? (selectedItem.cycleId || null)
    : selectedItem?.type === 'deliverableProcessArea'
      ? (selectedItem.cycleId || null)
    : selectedItem?.type === 'processArea'
      ? selectedItem.cycleId
    : selectedItem?.type === 'cycle'
      ? selectedItem.id
      : null;

  // All active mock cycles (in_hierarchy = true) — used by the Maintain screen and hierarchy tree.
  const { data: allMockCyclesForMaintain = {} } = useQuery({
    queryKey: ['allMockCyclesForMaintain'],
    queryFn: async () => {
      const cycles: Record<string, MockCycle[]> = {};
      await Promise.all(
        programs.map(async (program: Program) => {
          try {
            const response = await apiClient.get(`/api/programs/${program.id}/mock-cycles`);
            cycles[program.id] = response.data.data;
          } catch {
            cycles[program.id] = [];
          }
        })
      );
      return cycles;
    },
    enabled: programs.length > 0,
  });

  const allMaintainCycles: MockCycle[] = React.useMemo(() => (
    Object.values(allMockCyclesForMaintain).flatMap((cycles) => cycles || []) as MockCycle[]
  ), [allMockCyclesForMaintain]);
  const allMaintainProjects: Project[] = React.useMemo(() => (
    Object.values(projectsByProgram).flatMap((projects) => projects || []) as Project[]
  ), [projectsByProgram]);
  const maintainCycleParentProjectOptions = React.useMemo(() => {
    const byName = new Map<string, Project>();
    allMaintainProjects.forEach((project) => {
      const key = (project.name || '').trim().toLowerCase();
      if (!key) return;
      if (!byName.has(key)) {
        byName.set(key, project);
      }
    });
    return Array.from(byName.values()).sort((a, b) => (a.name || '').localeCompare(b.name || ''));
  }, [allMaintainProjects]);
  const maintainCycleRows = React.useMemo(() => (
    allMaintainCycles
      .map((cycle) => {
        const linkedProject = allMaintainProjects.find((project) => project.id === cycle.projectId) || null;
        return {
          ...cycle,
          linkedProjectId: linkedProject?.id || '',
          linkedProjectName: linkedProject?.name || 'Unassigned Project',
          programName: programs.find((program) => program.id === cycle.programId)?.name || 'Program',
        };
      })
      .sort((a, b) => a.programName.localeCompare(b.programName) || a.name.localeCompare(b.name))
  ), [allMaintainCycles, allMaintainProjects, programs]);
  const maintainProjectRows = React.useMemo(() => (
    allMaintainProjects
      .map((project) => {
        const projectCycles = allMaintainCycles.filter((entry) => entry.projectId === project.id);
        const firstCycle = projectCycles[0] || null;
        const resolvedProgramId = project.programId || firstCycle?.programId || '';
        const programName = programs.find((program) => program.id === resolvedProgramId)?.name || 'Program';
        return {
          ...project,
          cycleName: firstCycle?.name || 'No Mock Cycles',
          programId: resolvedProgramId,
          programName,
        };
      })
      .sort((a, b) => a.programName.localeCompare(b.programName) || a.cycleName.localeCompare(b.cycleName) || a.name.localeCompare(b.name))
  ), [allMaintainProjects, allMaintainCycles, programs]);
  const visibleMaintainCycleRows = maintainCycleRows.filter((row) => {
    const matchesProgram = maintainCycleFilterProgramId === 'all' || row.programId === maintainCycleFilterProgramId;
    const matchesParentProject = !maintainCycleParentProjectId || row.linkedProjectId === maintainCycleParentProjectId;
    return matchesProgram && matchesParentProject;
  });
  const visibleMaintainProjectRows = React.useMemo(() => {
    const scopedRows = maintainProjectRows.filter((row) => row.programId === maintainProjectParentProgramId);
    const byName = new Map<string, typeof scopedRows[number]>();
    scopedRows.forEach((row) => {
      const key = `${row.programId}::${(row.name || '').trim().toLowerCase()}`;
      if (!byName.has(key)) {
        byName.set(key, row);
      }
    });
    return Array.from(byName.values());
  }, [maintainProjectRows, maintainProjectParentProgramId]);
  const treeProjectOptionsForProgram = React.useMemo(() => {
    if (!contextProgramId) return [] as Project[];
    const scoped = maintainProjectRows.filter((row: any) => row.programId === contextProgramId);
    const byName = new Map<string, Project>();
    scoped.forEach((row: any) => {
      const key = `${row.programId}::${(row.name || '').trim().toLowerCase()}`;
      if (!byName.has(key)) {
        byName.set(key, row as Project);
      }
    });
    return Array.from(byName.values()).sort((a, b) => (a.name || '').localeCompare(b.name || ''));
  }, [contextProgramId, maintainProjectRows]);
  const cyclesForMaintainProjectProgram = maintainProjectParentProgramId
    ? allMaintainCycles.filter((cycle) => cycle.programId === maintainProjectParentProgramId)
    : [];
  const maintainCycleParentProject = allMaintainProjects.find((project) => project.id === maintainCycleParentProjectId) || null;
  const maintainProjectProgramMap = React.useMemo(() => {
    const map = new Map<string, string>();
    allMaintainProjects.forEach((project) => {
      const fallbackProgramId = allMaintainCycles.find((cycle) => cycle.projectId === project.id)?.programId || '';
      const resolvedProgramId = (project.programId || fallbackProgramId || '').trim();
      if (resolvedProgramId) {
        map.set(project.id, resolvedProgramId);
      }
    });
    return map;
  }, [allMaintainProjects, allMaintainCycles]);
  const strategyProgramOptions = React.useMemo(() => {
    return programs.filter((program) => (
      allMaintainProjects.some((project) => maintainProjectProgramMap.get(project.id) === program.id)
    ));
  }, [programs, allMaintainProjects, maintainProjectProgramMap]);
  const strategyProjectOptions = React.useMemo(() => {
    return allMaintainProjects
      .filter((project) => !strategyProgramId || maintainProjectProgramMap.get(project.id) === strategyProgramId)
      .sort((a, b) => (a.name || '').localeCompare(b.name || ''));
  }, [allMaintainProjects, strategyProgramId, maintainProjectProgramMap]);

  React.useEffect(() => {
    if (strategyProgramId && !strategyProgramOptions.some((program) => program.id === strategyProgramId)) {
      setStrategyProgramId('');
    }
  }, [strategyProgramId, strategyProgramOptions]);

  React.useEffect(() => {
    if (strategyProjectId && !strategyProjectOptions.some((project) => project.id === strategyProjectId)) {
      setStrategyProjectId('');
    }
  }, [strategyProjectId, strategyProjectOptions]);

  React.useEffect(() => {
    if (!activeProjectId) return;
    if (!allMaintainProjects.some((project) => project.id === activeProjectId)) return;
    if (strategyProjectId) return;

    setStrategyProjectId(activeProjectId);
    const inferredProgramId = maintainProjectProgramMap.get(activeProjectId) || '';
    if (inferredProgramId) {
      setStrategyProgramId((prev) => prev || inferredProgramId);
    }
  }, [activeProjectId, allMaintainProjects, strategyProjectId, maintainProjectProgramMap]);

  const strategySelectedProject = React.useMemo(() => {
    if (!strategyProjectId) return null;
    return allMaintainProjects.find((project) => project.id === strategyProjectId) || null;
  }, [strategyProjectId, allMaintainProjects]);
  const selectedMaintainCycle = allMaintainCycles.find((cycle) => cycle.id === maintainSelectedCycleId) || null;
  const cycleEntryCriteriaRows =
    Array.isArray(cycleEntryCriteriaDraft) && cycleEntryCriteriaDraft.length > 0
      ? cycleEntryCriteriaDraft
      : MOCK_CYCLE_ENTRY_CRITERIA_DEFAULTS;
  const cycleExitCriteriaRows =
    Array.isArray(cycleExitCriteriaDraft) && cycleExitCriteriaDraft.length > 0
      ? cycleExitCriteriaDraft
      : MOCK_CYCLE_EXIT_CRITERIA_DEFAULTS;
  const workflowUserIdSet = React.useMemo(() => new Set(workflowUsers.map((u) => u.id)), [workflowUsers]);

  // Debug logging
  if (editDialogOpen && editItemType === 'cycle') {
    console.log('Modal open for cycle edit:', {
      cycleEntryCriteriaDraft,
      cycleEntryCriteriaRows,
      cycleExitCriteriaDraft,
      cycleExitCriteriaRows,
      defaults_entry_length: MOCK_CYCLE_ENTRY_CRITERIA_DEFAULTS.length,
      defaults_exit_length: MOCK_CYCLE_EXIT_CRITERIA_DEFAULTS.length,
    });
  }

  const normalizeCriteriaDraft = React.useCallback((
    source: any,
    defaults: MockCycleCriterionDraft[],
  ): MockCycleCriterionDraft[] => {
    const incoming = Array.isArray(source) ? source : [];
    // If stored data uses the new fieldType schema, merge with defaults
    if (incoming.length > 0 && incoming[0]?.fieldType) {
      const byKey = new Map<string, MockCycleCriterionDraft>();
      incoming.forEach((item: MockCycleCriterionDraft) => { if (item?.key) byKey.set(item.key, item); });
      return defaults.map((def) => byKey.get(def.key) ?? { ...def });
    }
    // Old format or empty — return fresh defaults
    return defaults.map((d) => ({ ...d }));
  }, []);
  const getScopedProjectsForCycle = (cycleId: string, projectId?: string | null): Project[] => {
    const projects = (projectsByMockCycle[cycleId] || []) as Project[];
    if (!projectId) return projects;
    return projects.filter((project) => project.id === projectId);
  };

  useEffect(() => {
    if (!selectedItem) return;

    const payload = selectedItem.type === 'project'
      ? { type: 'project', projectId: selectedItem.id, cycleId: selectedItem.cycleId }
      : selectedItem.type === 'deliverable'
        ? {
            type: 'deliverable',
            projectId: selectedItem.projectId,
            cycleId: selectedItem.cycleId,
            deliverableId: selectedItem.deliverableId,
          }
      : selectedItem.type === 'processArea'
        ? { type: 'processArea', projectId: selectedItem.projectId, cycleId: selectedItem.cycleId, area: selectedItem.area }
      : selectedItem.type === 'cycle'
        ? { type: 'cycle', cycleId: selectedItem.id, programId: selectedItem.programId, projectId: selectedItem.projectId || null }
        : selectedItem.type === 'program'
          ? { type: 'program', programId: selectedItem.id }
          : {
              type: 'deliverableProcessArea',
              projectId: selectedItem.projectId,
              cycleId: selectedItem.cycleId,
              deliverableId: selectedItem.deliverableId,
              area: selectedItem.area,
            };

    localStorage.setItem(HIERARCHY_SELECTION_STORAGE_KEY, JSON.stringify(payload));
  }, [selectedItem]);

  useEffect(() => {
    if (!maintainCycleParentProgramId || !programs.some((program) => program.id === maintainCycleParentProgramId)) {
      setMaintainCycleParentProgramId(programs[0]?.id || '');
    }
  }, [programs, maintainCycleParentProgramId]);

  useEffect(() => {
    if (!maintainCycleParentProjectId || !allMaintainProjects.some((project) => project.id === maintainCycleParentProjectId)) {
      setMaintainCycleParentProjectId(maintainCycleParentProjectOptions[0]?.id || '');
    }
  }, [maintainCycleParentProjectOptions, maintainCycleParentProjectId, allMaintainProjects]);

  useEffect(() => {
    if (maintainFormView !== 'cycle') return;

    if (!maintainSelectedCycleId || !visibleMaintainCycleRows.some((cycle) => cycle.id === maintainSelectedCycleId)) {
      setMaintainSelectedCycleId(visibleMaintainCycleRows[0]?.id || '');
    }
  }, [maintainFormView, maintainSelectedCycleId, visibleMaintainCycleRows]);

  useEffect(() => {
    if (maintainFormView !== 'cycle') return;
    if (!selectedMaintainCycle) {
      setCycleEntryCriteriaDraft(MOCK_CYCLE_ENTRY_CRITERIA_DEFAULTS);
      setCycleExitCriteriaDraft(MOCK_CYCLE_EXIT_CRITERIA_DEFAULTS);
      setProjectLeadUserIdDraft('');
      setProjectManagerUserIdDraft('');
      setCycleWorkflowEvaluation(null);
      return;
    }

    setCycleEntryCriteriaDraft(normalizeCriteriaDraft(selectedMaintainCycle.entryCriteriaItems, MOCK_CYCLE_ENTRY_CRITERIA_DEFAULTS));
    setCycleExitCriteriaDraft(normalizeCriteriaDraft(selectedMaintainCycle.exitCriteriaItems, MOCK_CYCLE_EXIT_CRITERIA_DEFAULTS));

    const loadProjectWorkflowRoles = async () => {
      try {
        const response = await apiClient.get(`/api/projects/${selectedMaintainCycle.projectId}/workflow-roles`);
        const payload = response.data?.data || {};
        setProjectLeadUserIdDraft(payload.leadUserId || '');
        setProjectManagerUserIdDraft(payload.projectManagerUserId || '');
      } catch {
        setProjectLeadUserIdDraft('');
        setProjectManagerUserIdDraft('');
      }
    };

    const loadCycleWorkflowStatus = async () => {
      try {
        const response = await apiClient.get(`/api/mock-cycles/${selectedMaintainCycle.id}/workflow-status`);
        setCycleWorkflowEvaluation(response.data?.data || null);
      } catch {
        setCycleWorkflowEvaluation(null);
      }
    };

    loadProjectWorkflowRoles().catch(() => {});
    loadCycleWorkflowStatus().catch(() => {});
  }, [maintainFormView, selectedMaintainCycle, normalizeCriteriaDraft]);

  useEffect(() => {
    if (!maintainCycleParentProject) return;
    const parentProgramId = maintainCycleParentProject.programId || '';
    if (parentProgramId && parentProgramId !== maintainCycleParentProgramId) {
      setMaintainCycleParentProgramId(parentProgramId);
    }
  }, [maintainCycleParentProject, maintainCycleParentProgramId]);

  useEffect(() => {
    if (!maintainProjectParentProgramId || !programs.some((program) => program.id === maintainProjectParentProgramId)) {
      setMaintainProjectParentProgramId(programs[0]?.id || '');
    }
  }, [programs, maintainProjectParentProgramId]);

  useEffect(() => {
    const validCycles = maintainProjectParentProgramId
      ? allMaintainCycles.filter((cycle) => cycle.programId === maintainProjectParentProgramId)
      : allMaintainCycles;
    if (!maintainProjectParentCycleId || !validCycles.some((cycle) => cycle.id === maintainProjectParentCycleId)) {
      setMaintainProjectParentCycleId(validCycles[0]?.id || '');
    }
  }, [allMaintainCycles, maintainProjectParentProgramId, maintainProjectParentCycleId]);

  useEffect(() => {
    const isTreeProjectSelectionMode = dialogMode === 'project' && !isPlanningMaintainTab && !treeProjectCreateByNameMode;
    if (!createDialogOpen || !isTreeProjectSelectionMode) return;
    const currentStillValid = treeProjectOptionsForProgram.some((project) => project.id === selectedExistingProjectOptionId);
    if (!currentStillValid) {
      setSelectedExistingProjectOptionId(treeProjectOptionsForProgram[0]?.id || '');
    }
  }, [createDialogOpen, dialogMode, isPlanningMaintainTab, treeProjectCreateByNameMode, treeProjectOptionsForProgram, selectedExistingProjectOptionId]);

  useEffect(() => {
    if (maintainCycleFilterProgramId === 'all') return;
    if (!programs.some((program) => program.id === maintainCycleFilterProgramId)) {
      setMaintainCycleFilterProgramId('all');
    }
  }, [programs, maintainCycleFilterProgramId]);

  useEffect(() => {
    if (maintainProjectFilterCycleId === 'all') return;
    if (!allMaintainCycles.some((cycle) => cycle.id === maintainProjectFilterCycleId)) {
      setMaintainProjectFilterCycleId('all');
    }
  }, [allMaintainCycles, maintainProjectFilterCycleId]);
  const activeCycleScheduleMode: CalendarMode = (() => {
    if (!activeCycleId) return 'all_days';
    for (const programId in mockCycles) {
      const cycle = (mockCycles[programId] || []).find((c: MockCycle) => c.id === activeCycleId);
      if (cycle?.scheduleMode === 'working_days') return 'working_days';
      if (cycle?.scheduleMode === 'all_days') return 'all_days';
    }
    return 'all_days';
  })();

  const { data: myTasksData, isLoading: isLoadingMyTasks, error: myTasksError } = useQuery({
    queryKey: ['projects-my-tasks', user?.id, user?.email, activeCycleId, selectedCycleProjectId, programs.length, Object.keys(mockCycles).length, Object.keys(projectsByMockCycle).length],
    queryFn: async () => {
      const normalizeValue = (value?: string | null) => (value || '').trim().toLowerCase();
      const emailAlias = normalizeValue((user?.email || '').split('@')[0]?.split('+')[0]);
      const tokenSet = new Set(
        [user?.id, user?.email, emailAlias]
          .map((item) => normalizeValue(item))
          .filter(Boolean)
      );

      const cycleScopes = Object.entries(mockCycles).flatMap(([programId, cycles]) => {
        const program = programs.find((p: any) => p.id === programId);
        return (cycles || []).map((cycle: any) => ({ program, cycle }));
      });

      const filteredCycleScopes = activeCycleId
        ? cycleScopes.filter(({ cycle }: any) => cycle?.id === activeCycleId)
        : cycleScopes;

      const projectScopes = filteredCycleScopes.flatMap(({ program, cycle }: any) => {
        const projects = getScopedProjectsForCycle(cycle.id, selectedCycleProjectId);
        return projects.map((project: any) => ({ program, cycle, project }));
      });

      const taskBatches = await Promise.all(
        projectScopes.map(async ({ program, cycle, project }: any) => {
          try {
            const tasksResponse = await apiClient.get(`/api/tasks/cycle/${cycle.id}`);
            const tasks = tasksResponse.data.data || [];
            return tasks
              .filter((task: any) => {
                const dra = normalizeValue(task.draUserId);
                const developer = normalizeValue(task.developerUserId);
                const assignedTo = normalizeValue(task.assignedTo);
                return tokenSet.has(dra) || tokenSet.has(developer) || tokenSet.has(assignedTo);
              })
              .map((task: any) => ({
                ...task,
                taskId: task.id,
                taskName: task.name,
                projectName: project.name,
                mockCycleName: cycle.name,
                programName: program?.name || 'Program',
              }));
          } catch {
            return [];
          }
        })
      );

      const assignedTasks = taskBatches.flat();
      const parseDateOnlyLocal = (value?: string) => {
        if (!value) return null;
        const date = new Date(value);
        if (Number.isNaN(date.getTime())) return null;
        return new Date(date.getFullYear(), date.getMonth(), date.getDate());
      };
      const now = new Date();
      const todayStartLocal = new Date(now.getFullYear(), now.getMonth(), now.getDate());
      const weekEndLocal = new Date(todayStartLocal);
      weekEndLocal.setDate(todayStartLocal.getDate() + 6);

      const sections = {
        late: assignedTasks.filter((task: any) => {
          if (task.status === 'complete') return false;
          const end = parseDateOnlyLocal(task.endDate);
          return !!end && end < todayStartLocal;
        }),
        in_progress: assignedTasks.filter((task: any) => task.status === 'in_progress'),
        due_this_week: assignedTasks.filter((task: any) => {
          if (task.status === 'complete') return false;
          const end = parseDateOnlyLocal(task.endDate);
          return !!end && end >= todayStartLocal && end <= weekEndLocal;
        }),
        blocked: assignedTasks.filter((task: any) => task.status === 'blocked'),
        complete: assignedTasks.filter((task: any) => task.status === 'complete'),
      };

      const selectedCycleName = activeCycleId
        ? filteredCycleScopes.find(({ cycle }: any) => cycle.id === activeCycleId)?.cycle?.name || null
        : null;

      return {
        sections,
        totalAssigned: assignedTasks.length,
        selectedCycleName,
      };
    },
    enabled: !!user && tabValue === 5 && Object.keys(mockCycles).length > 0,
  });

  const scheduleWeekDates = Array.from({ length: 7 }, (_, idx) => {
    const d = new Date(scheduleWeekStart);
    d.setDate(scheduleWeekStart.getDate() + idx);
    return d;
  });

  const getProjectAccentColor = (project: Project, index: number) => {
    if (project.accentColor) return project.accentColor;
    const fallback = ['#5B67CA', '#00BFA5', '#FF5B8A', '#26C6DA', '#F59E0B', '#8B5CF6'];
    return fallback[index % fallback.length];
  };

  const toRgba = (hex: string, alpha: number) => {
    const value = (hex || '').trim();
    const fullHex = /^#?[0-9a-fA-F]{6}$/.test(value)
      ? value.replace('#', '')
      : /^#?[0-9a-fA-F]{3}$/.test(value)
        ? value.replace('#', '').split('').map(ch => ch + ch).join('')
        : '5B67CA';
    const r = parseInt(fullHex.slice(0, 2), 16);
    const g = parseInt(fullHex.slice(2, 4), 16);
    const b = parseInt(fullHex.slice(4, 6), 16);
    return `rgba(${r}, ${g}, ${b}, ${alpha})`;
  };

  const normalizeDateOnly = (value?: string) => {
    if (!value) return null;
    // Preserve date-only strings as local calendar dates (avoid UTC shift to prior day).
    if (/^\d{4}-\d{2}-\d{2}$/.test(value)) {
      const [y, m, d] = value.split('-').map(n => Number(n));
      return new Date(y, m - 1, d);
    }
    const d = new Date(value);
    if (Number.isNaN(d.getTime())) return null;
    return new Date(d.getFullYear(), d.getMonth(), d.getDate());
  };

  const isSameDay = (a: Date, b: Date) => (
    a.getFullYear() === b.getFullYear() &&
    a.getMonth() === b.getMonth() &&
    a.getDate() === b.getDate()
  );

  const mergeOrder = (existing: string[], current: string[]) => {
    const existingFiltered = existing.filter(id => current.includes(id));
    const newItems = current.filter(id => !existingFiltered.includes(id));
    return [...existingFiltered, ...newItems];
  };

  const moveWithin = (list: string[], id: string, delta: number) => {
    const idx = list.indexOf(id);
    if (idx === -1) return list;
    const nextIdx = idx + delta;
    if (nextIdx < 0 || nextIdx >= list.length) return list;
    const copy = [...list];
    const [item] = copy.splice(idx, 1);
    copy.splice(nextIdx, 0, item);
    return copy;
  };

  const reorderByDrop = (list: string[], dragId: string, targetId: string) => {
    const from = list.indexOf(dragId);
    const to = list.indexOf(targetId);
    if (from === -1 || to === -1 || from === to) return list;
    const copy = [...list];
    const [item] = copy.splice(from, 1);
    copy.splice(to, 0, item);
    return copy;
  };

  const getOrderStorageKey = (projectId: string) => `rf-plan-order:${projectId}`;
  const objectRowKey = (id: string) => `obj:${id}`;
  const taskGroupRowKey = (id: string) => `grp:${id}`;

  const persistPlanRowOrder = (projectId: string, rows: string[]) => {
    const objectIds = rows.filter((k: string) => k.startsWith('obj:')).map((k: string) => k.slice(4));
    const groupIds = rows.filter((k: string) => k.startsWith('grp:')).map((k: string) => k.slice(4));
    localStorage.setItem(getOrderStorageKey(projectId), JSON.stringify({
      rows,
      objects: objectIds,
      groups: groupIds,
    }));
  };

  const getOrderedPrograms = () => {
    const ids = mergeOrder(treeOrder.programs, programs.map((p: Program) => p.id));
    return ids.map(id => programs.find((p: Program) => p.id === id)).filter(Boolean) as Program[];
  };

  const getOrderedCycles = (programId: string) => {
    const source = mockCycles[programId] || [];
    const existing = treeOrder.cycles[programId] || [];
    // Always include current source cycles so newly created cycles render immediately
    // even before tree-order preferences are persisted.
    const ids = mergeOrder(existing, source.map((c: MockCycle) => c.id));
    return ids.map((id: string) => source.find((c: MockCycle) => c.id === id)).filter(Boolean) as MockCycle[];
  };

  const getAttachableCyclesForProgram = (programId: string) => {
    const visibleIds = new Set(getOrderedCycles(programId).map((c: MockCycle) => c.id));
    return (mockCycles[programId] || []).filter((cycle: MockCycle) => !visibleIds.has(cycle.id));
  };

  const getOrderedProjects = (cycleId: string) => {
    const source = projectsByMockCycle[cycleId] || [];
    const existing = treeOrder.projects[cycleId] || [];
    const ids = mergeOrder(existing, source.map((p: Project) => p.id));
    return ids.map(id => source.find((p: Project) => p.id === id)).filter(Boolean) as Project[];
  };

  const getProjectGroupOrderKey = (name: string) => (name || '').trim().toLowerCase();

  const getProjectsByProgram = (programId: string) => {
    const programProjects = (projectsByProgram[programId] || []) as Project[];
    const byName = new Map<string, Project>();
    programProjects.forEach((project: Project) => {
      const key = getProjectGroupOrderKey(project.name || '');
      if (key && !byName.has(key)) {
        byName.set(key, project);
      }
    });
    const keys = mergeOrder(treeOrder.projectGroups[programId] || [], Array.from(byName.keys()));
    return keys
      .map((key) => byName.get(key))
      .filter(Boolean) as Project[];
  };

  const getCyclesForProjectInProgram = (programId: string, projectId?: string | null) => {
    const ordered = getOrderedCycles(programId);
    if (!projectId) return ordered;

    return ordered.filter((cycle: MockCycle) => {
      if (cycle.projectId && cycle.projectId === projectId) return true;
      const cycleProjects = (projectsByMockCycle[cycle.id] || []) as Project[];
      return cycleProjects.some((project) => project.id === projectId);
    });
  };

  const getPrimaryProjectIdForCycle = (cycleId: string) => {
    const projects = (projectsByMockCycle[cycleId] || []) as Project[];
    return projects[0]?.id || null;
  };

  const getInventoryProcessAreaOptions = (projectId: string) => {
    const candidateProjectIds = new Set<string>([projectId]);
    const allProjects = Object.values(projectsByProgram).flat() as any[];
    const selectedProjectRecord = allProjects.find((project: any) => project.id === projectId) || null;
    const selectedProjectName = (selectedProjectRecord?.name || '').trim().toLowerCase();
    const selectedProjectProgramId = selectedProjectRecord?.programId || '';

    if (selectedProjectName && selectedProjectProgramId) {
      allProjects.forEach((project: any) => {
        if (
          project.programId === selectedProjectProgramId &&
          (project.name || '').trim().toLowerCase() === selectedProjectName
        ) {
          candidateProjectIds.add(project.id);
        }
      });
    }

    const labels = new Set<string>();
    projectInventoryItems
      .filter((item: any) => candidateProjectIds.has(item.projectId))
      .forEach((item: any) => {
        const label = (item.processArea || '').trim();
        if (label) labels.add(label);
      });

    (hiddenProcessAreas[projectId] || []).forEach((area) => {
      const label = (area || '').trim();
      if (label) labels.add(label);
    });

    return Array.from(labels).sort((a, b) => a.localeCompare(b));
  };

  // planningAdditionalGroups is now keyed by cycleId (not projectId) so that
  // cycles sharing the same project have independent plan-group label sets.
  const getDeliverableAssignedGroupIds = React.useCallback((projectId: string) => {
    return new Set(Object.keys(deliverableTaskGroupAssignments[projectId] || {}));
  }, [deliverableTaskGroupAssignments]);

  const isDeliverableAssignedGroup = React.useCallback((projectId: string, group: any) => {
    if (!projectId || !group?.id) return false;
    return !!deliverableTaskGroupAssignments[projectId]?.[group.id];
  }, [deliverableTaskGroupAssignments]);

  const getVisiblePlanningAdditionalGroups = React.useCallback((projectId: string, cycleId?: string) => {
    const key = cycleId || projectId;
    const assignedIds = getDeliverableAssignedGroupIds(projectId);
    return (planningAdditionalGroups[key] || []).filter((groupName) => {
      const normalizedGroupName = (groupName || '').trim().toLowerCase();
      if (!normalizedGroupName) return false;
      return !projectTaskGroups.some((group: any) => (
        group.projectId === projectId &&
        !group.processArea &&
        assignedIds.has(group.id) &&
        (group.name || '').trim().toLowerCase() === normalizedGroupName
      ));
    });
  }, [getDeliverableAssignedGroupIds, planningAdditionalGroups, projectTaskGroups]);

  const getProcessAreasForProjectCycle = (projectId: string, cycleId?: string) => {
    const key = cycleId || projectId;
    const areas = new Set<string>();
    const structureAssignedAreaNorms = new Set<string>();
    const additionalGroupSet = new Set(
      getVisiblePlanningAdditionalGroups(projectId, cycleId)
        .map((name) => (name || '').trim().toLowerCase())
        .filter(Boolean)
    );
    const attached = treeOrder.processAreas[key] || [];
    attached.forEach((area) => {
      const label = (area || '').trim();
      if (label && !additionalGroupSet.has(label.toLowerCase())) areas.add(label);
    });
    const additionalProcessAreaNodes = planningAdditionalProcessAreas[key] || [];
    additionalProcessAreaNodes.forEach((areaName) => {
      const label = (areaName || '').trim();
      if (label && !additionalGroupSet.has(label.toLowerCase())) areas.add(label);
    });
    const manualAssignedAreas = projectManualProcessAreas[projectId] || [];
    manualAssignedAreas.forEach((areaName) => {
      const label = (areaName || '').trim();
      if (label) areas.add(label);
    });
    const structureAssignedAreas = projectAssignedProcessAreas[projectId] || [];
    structureAssignedAreas.forEach((areaName) => {
      const label = (areaName || '').trim();
      if (label) {
        areas.add(label);
        structureAssignedAreaNorms.add(label.toLowerCase());
      }
    });

    const hiddenAreaSet = new Set((hiddenProcessAreas[key] || []).map((area) => (area || '').trim().toLowerCase()));
    const allAreas = Array.from(areas).filter((area) => {
      const normalized = (area || '').trim().toLowerCase();
      if (!normalized) return false;
      // Assigned process areas from Structure must remain visible in every cycle.
      if (structureAssignedAreaNorms.has(normalized)) return true;
      return !hiddenAreaSet.has(normalized);
    });
    const ordered = mergeOrder(attached, allAreas);
    return ordered;
  };

  // processAreaAccentOverrides is keyed by cycleId (set in handleCreateProcessArea and copy handler).
  // Accept an optional cycleId so call sites that have it can pass it; fall back to projectId.
  const getProcessAreaAccent = (projectId: string, area: string, fallback: string, cycleId?: string) => {
    const key = cycleId || projectId;
    // Global settings (from Settings page) take priority.
    // Per-cycle overrides are kept for future per-cycle customisation but only apply
    // when no global default has been explicitly set for this area.
    const global = globalProcessAreaAccents[area];
    const perCycle = processAreaAccentOverrides[key]?.[area];
    return global || perCycle || fallback;
  };

  const getProcessAreaDisplayName = (projectId: string, area: string, cycleId?: string) => {
    const scopedKey = cycleId || projectId;
    const localFallback = Object.values(processAreaDescriptions)
      .map((bucket: any) => bucket?.[area])
      .find((value) => typeof value === 'string' && value.trim().length > 0) as string | undefined;
    // Priority: per-cycle description → global API description → localStorage fallback
    const description = (processAreaDescriptions[scopedKey]?.[area]
      || processAreaDescriptions[projectId]?.[area]
      || globalProcessAreaDescriptions[area]
      || settingsProcessAreaDescriptions[area]
      || localFallback
      || '').trim();
    return description || area;
  };

  const getResolvedProcessAreaKey = (projectId: string, area: string, cycleId?: string) => {
    const requested = (area || '').trim();
    if (!requested) return requested;
    const requestedNorm = requested.toLowerCase();
    const summaryKey = cycleId ? `${projectId}_${cycleId}` : projectId;
    const cachedKeys = Object.keys(projectHierarchySummaries[summaryKey]?.processAreas || {});

    const exact = cachedKeys.find((key) => key === requested);
    if (exact) return exact;

    const caseInsensitive = cachedKeys.find((key) => (key || '').trim().toLowerCase() === requestedNorm);
    if (caseInsensitive) return caseInsensitive;

    const byDisplayName = cachedKeys.find((key) =>
      (getProcessAreaDisplayName(projectId, key) || '').trim().toLowerCase() === requestedNorm
    );
    if (byDisplayName) return byDisplayName;

    return requested;
  };

  const renderHierarchyIcon = (level: HierarchyLevel, color: string, size: string, overrideKey?: string, overrideArea?: string) => {
    // Global settings (from Settings page) take priority over per-cycle overrides and defaults.
    const globalIcon = overrideArea ? globalProcessAreaIcons[overrideArea] : undefined;
    const perCycleIcon = (overrideKey && overrideArea && processAreaIconOverrides[overrideKey]?.[overrideArea]) || undefined;
    const iconChoice = globalIcon || perCycleIcon || hierarchyLevelIcons[level];
    // Delegate to renderIconChoice which handles MUI, FA, and all new icon types.
    return renderIconChoice(iconChoice, color, size);
  };

  const renderIconChoice = (choice: HierarchyIconChoice, color: string, size: string) => {
    const sx = { fontSize: size, color, flexShrink: 0 };
    // Font Awesome icons
    const faIconMap: Record<string, any> = {
      'fa-database': faDatabase, 'fa-server': faServer, 'fa-cloud': faCloud, 'fa-code': faCode,
      'fa-gears': faGears, 'fa-diagram-project': faDiagramProject, 'fa-list-check': faListCheck,
      'fa-file-lines': faFileLines, 'fa-circle-nodes': faCircleNodes, 'fa-network-wired': faNetworkWired,
      'fa-table-cells': faTableCells, 'fa-chart-gantt': faChartGantt, 'fa-clipboard-list': faClipboardList,
      'fa-triangle-exclamation': faTriangleExclamation,
    };
    if (faIconMap[choice]) {
      // Wrap in a span so FA SVG inherits font-size correctly
      return (
        <span style={{ fontSize: size, color, display: 'inline-flex', alignItems: 'center', lineHeight: 1, flexShrink: 0 }}>
          <FontAwesomeIcon icon={faIconMap[choice]} />
        </span>
      );
    }
    switch (choice) {
      case 'sync': return <SyncIcon sx={sx} />;
      case 'folderOutlined': return <FolderOutlinedIcon sx={sx} />;
      case 'accountTree': return <AccountTreeIcon sx={sx} />;
      case 'layers': return <LayersIcon sx={sx} />;
      case 'viewList': return <ViewListIcon sx={sx} />;
      case 'event': return <EventIcon sx={sx} />;
      case 'storage': return <StorageIcon sx={sx} />;
      case 'dashboard': return <DashboardIcon sx={sx} />;
      case 'build': return <BuildIcon sx={sx} />;
      case 'assignment': return <AssignmentIcon sx={sx} />;
      case 'settings': return <SettingsIcon sx={sx} />;
      case 'barChart': return <BarChartIcon sx={sx} />;
      case 'corporateFare':
      default: return <CorporateFareIcon sx={sx} />;
    }
  };

  const renderIconPicker = (level: HierarchyLevel, accent: string, selectedValue?: HierarchyIconChoice, onSelect?: (v: HierarchyIconChoice) => void) => {
    const muiOptions = HIERARCHY_ICON_OPTIONS.filter(o => o.group === 'MUI');
    const faOptions = HIERARCHY_ICON_OPTIONS.filter(o => o.group === 'FA');
    const current = selectedValue !== undefined ? selectedValue : hierarchyLevelIcons[level];
    const btn = (option: typeof HIERARCHY_ICON_OPTIONS[0]) => {
      const selected = current === option.value;
      return (
        <IconButton
          key={`${level}-${option.value}`}
          size="small"
          title={option.label}
          onClick={() => onSelect ? onSelect(option.value) : setHierarchyLevelIcons((prev) => ({ ...prev, [level]: option.value }))}
          sx={{
            width: 30, height: 30, border: '1px solid',
            borderColor: selected ? accent : 'rgba(255,255,255,0.2)',
            backgroundColor: selected ? toRgba(accent, 0.18) : 'rgba(255,255,255,0.04)',
            borderRadius: 1,
            '&:hover': { backgroundColor: selected ? toRgba(accent, 0.24) : 'rgba(255,255,255,0.08)' },
          }}
        >
          {renderIconChoice(option.value, selected ? accent : 'rgba(255,255,255,0.78)', '0.85rem')}
        </IconButton>
      );
    };
    return (
      <Box sx={{ mt: 0.75 }}>
        <Typography variant="caption" sx={{ color: 'text.disabled', fontSize: '0.62rem', letterSpacing: '0.06em', display: 'block', mb: 0.4 }}>MUI ICONS</Typography>
        <Box sx={{ display: 'flex', flexWrap: 'wrap', gap: 0.5, mb: 0.75 }}>{muiOptions.map(btn)}</Box>
        <Typography variant="caption" sx={{ color: 'text.disabled', fontSize: '0.62rem', letterSpacing: '0.06em', display: 'block', mb: 0.4 }}>FONT AWESOME</Typography>
        <Box sx={{ display: 'flex', flexWrap: 'wrap', gap: 0.5 }}>{faOptions.map(btn)}</Box>
      </Box>
    );
  };

  const getProgressAverage = (values: number[]) => {
    if (values.length === 0) return 0;
    return Math.round(values.reduce((sum, value) => sum + Math.max(0, Math.min(100, value || 0)), 0) / values.length);
  };

  const getEffectiveTaskProgress = (task: any) => {
    const pct = Number(task?.progressPercentage ?? 0);
    if (pct > 0) return pct;
    return task?.status === 'complete' ? 100 : 0;
  };

  const taskMatchesProcessArea = (projectId: string, task: any, requestedArea: string, cycleId?: string) => {
    const resolvedRequested = getResolvedProcessAreaKey(projectId, requestedArea, cycleId);
    const requestedNorm = (requestedArea || '').trim().toLowerCase();
    const resolvedNorm = (resolvedRequested || '').trim().toLowerCase();
    const requestedDisplayNorm = getProcessAreaDisplayName(projectId, resolvedRequested || requestedArea || '').trim().toLowerCase();

    const taskRaw = (task?.processArea || '').trim();
    const taskRawNorm = taskRaw.toLowerCase();
    const taskDisplayNorm = getProcessAreaDisplayName(projectId, taskRaw).trim().toLowerCase();

    if (taskRawNorm) {
      return taskRawNorm === resolvedNorm || taskRawNorm === requestedNorm || taskDisplayNorm === requestedDisplayNorm || taskDisplayNorm === requestedNorm;
    }

    return false;
  };

  const getProcessAreaProgress = (projectId: string, area: string, fallbackPct: number, cycleId?: string) => {
    const summaryKey = cycleId ? `${projectId}_${cycleId}` : projectId;
    const resolvedArea = getResolvedProcessAreaKey(projectId, area, cycleId);
    const cachedProcessAreas = projectHierarchySummaries[summaryKey]?.processAreas || {};
    if (cachedProcessAreas[resolvedArea]) {
      return cachedProcessAreas[resolvedArea].progressPct;
    }
    // For hierarchy area rows, never inherit cycle/project progress on cache miss.
    // If this area has no scoped task data, it should display 0%.
    if (activeProjectId !== projectId) return 0;
    const normalizedArea = (resolvedArea || '').trim().toLowerCase();
    const requestedAreaDisplayNorm = (area || '').trim().toLowerCase();
    const areaObjectIds = new Set(
      projectInventoryItems
        .filter((item: any) => {
          if (item.projectId !== projectId) return false;
          const raw = (item.processArea || '').trim().toLowerCase();
          const display = getProcessAreaDisplayName(projectId, item.processArea || '').trim().toLowerCase();
          return raw === normalizedArea || display === requestedAreaDisplayNorm;
        })
        .map((item: any) => item.id)
    );
    const areaGroupIds = new Set(
      projectTaskGroups
        .filter((group: any) => {
          if (group.projectId !== projectId) return false;
          const raw = (group.processArea || '').trim().toLowerCase();
          const display = getProcessAreaDisplayName(projectId, group.processArea || '').trim().toLowerCase();
          return raw === normalizedArea || display === requestedAreaDisplayNorm;
        })
        .map((group: any) => group.id)
    );
    const areaTasks = projectTasks.filter((task: any) => {
      if (taskMatchesProcessArea(projectId, task, resolvedArea, cycleId)) return true;
      return (task.projectObjectId && areaObjectIds.has(task.projectObjectId)) ||
        (task.taskGroupId && areaGroupIds.has(task.taskGroupId));
    });
    if (areaTasks.length === 0) return 0;
    return getProgressAverage(areaTasks.map((task: any) => getEffectiveTaskProgress(task)));
  };

  const handleAddAdditionalGroup = (cycleId: string) => {
    setPlanGroupTargetProjectId(cycleId); // store cycleId in this slot (renamed semantics)
    setNewPlanGroupName('');
    setPlanGroupDialogOpen(true);
  };

  const handleAddProcessArea = (projectId: string) => {
    setProcessAreaTargetProjectId(projectId);
    setProcessAreaTargetCycleId(activeCycleId || null); // capture cycle context at open time
    setNewProcessAreaName(processAreaOptions[0] || '');
    setProcessAreaDialogOpen(true);
  };

  const reloadProjectPlanData = async (mockCycleId: string) => {
    const [tasksRes, groupsRes] = await Promise.all([
      apiClient.get(`/api/tasks/cycle/${mockCycleId}`),
      apiClient.get(`/api/tasks/groups/cycle/${mockCycleId}`),
    ]);
    setProjectTasks((tasksRes.data.data || []).map((task: any) => normalizeTaskDateFields(task)));
    setProjectTaskGroups(groupsRes.data.data || []);
  };

  const handleCreatePlanGroup = async () => {
    const projectId = planGroupTargetProjectId;
    const name = newPlanGroupName.trim();
    if (!projectId) {
      alert('Project context missing for Plan Group.');
      return;
    }
    if (!name) {
      alert('Plan Group name is required.');
      return;
    }

    // Persist the plan group as a real task_group DB record so it is
    // included in cycle copies and server-side queries.
    if (activeCycleId) {
      try {
        // Infer the process area context from the current selection if available.
        const processAreaHint = (selectedItem?.type === 'processArea' ? selectedItem.area : '').trim() || null;
        const response = await apiClient.post(`/api/tasks/groups/cycle/${activeCycleId}`, {
          name,
          processArea: processAreaHint,
        });
        const newGroup = response.data?.data;
        if (newGroup) {
          setProjectTaskGroups(prev => [...prev, newGroup]);
        }
      } catch (error) {
        console.error('Failed to persist plan group:', error);
        // Proceed to add local label even if API fails so the UI is not blocked.
      }
    }

    // Also keep the local label for display ordering in the hierarchy.
    // Key by cycleId so cycles that share a project don't interfere.
    const cycleKey = activeCycleId || projectId;
    setPlanningAdditionalGroups(prev => {
      const existing = prev[cycleKey] || [];
      if (existing.some(g => g.toLowerCase() === name.toLowerCase())) return prev;
      return {
        ...prev,
        [cycleKey]: [...existing, name],
      };
    });
    setPlanGroupDialogOpen(false);
    setPlanGroupTargetProjectId(null);
    setNewPlanGroupName('');
  };

  // cycleKey: accepts a cycleId (preferred) or projectId as fallback
  const handleRemovePlanGroup = (cycleKey: string, areaName: string) => {
    const normalizedTarget = (areaName || '').trim().toLowerCase();
    if (!normalizedTarget) return;

    // Remove from local state immediately
    setPlanningAdditionalGroups((prev) => {
      const existing = prev[cycleKey] || [];
      const next = existing.filter((group) => (group || '').trim().toLowerCase() !== normalizedTarget);
      return { ...prev, [cycleKey]: next };
    });

    // Also delete the DB task group record so it doesn't re-appear on next load
    const dbGroup = projectTaskGroups.find(
      (g: any) => !g.processArea && (g.name || '').trim().toLowerCase() === normalizedTarget
    );
    if (dbGroup) {
      setProjectTaskGroups((prev: any[]) => prev.filter((g: any) => g.id !== dbGroup.id));
      setDeliverableTaskGroupAssignments((prev) => {
        const projectKey = activeProjectId || '';
        if (!projectKey || !prev[projectKey]?.[dbGroup.id]) return prev;
        const nextProjectAssignments = { ...(prev[projectKey] || {}) };
        delete nextProjectAssignments[dbGroup.id];
        return {
          ...prev,
          [projectKey]: nextProjectAssignments,
        };
      });
      apiClient.delete(`/api/tasks/groups/${dbGroup.id}`).catch(() => {});
    }
  };

  const addObjectToGroup = async (groupId: string, objectId: string) => {
    const group = projectTaskGroups.find(g => g.id === groupId);
    if (!group) return;
    const currentMembers: string[] = Array.isArray(group.members) ? group.members : [];
    if (currentMembers.includes(objectId)) return;
    const newMembers = [...currentMembers, objectId];
    try {
      await apiClient.patch(`/api/tasks/groups/${groupId}`, { members: newMembers });
      setProjectTaskGroups(prev => prev.map(g => g.id === groupId ? { ...g, members: newMembers } : g));
    } catch (e) { console.error('[addObjectToGroup]', e); }
    setGroupObjectPickerGroupId(null);
    setGroupObjectPickerSearch('');
  };

  const removeObjectFromGroup = async (groupId: string, objectId: string) => {
    const group = projectTaskGroups.find(g => g.id === groupId);
    if (!group) return;
    const newMembers = (Array.isArray(group.members) ? group.members : []).filter((id: string) => id !== objectId);
    try {
      await apiClient.patch(`/api/tasks/groups/${groupId}`, { members: newMembers });
      setProjectTaskGroups(prev => prev.map(g => g.id === groupId ? { ...g, members: newMembers } : g));
    } catch (e) { console.error('[removeObjectFromGroup]', e); }
  };

  const handleCreateProcessArea = async () => {
    const projectId = processAreaTargetProjectId;
    const name = newProcessAreaName.trim();
    if (!projectId) {
      alert('Project context missing for Process Area.');
      return;
    }
    if (!name) {
      alert('Process Area name is required.');
      return;
    }

    // Use the cycle ID captured when the dialog was opened (not the current activeCycleId which may have changed)
    const cycleKey = processAreaTargetCycleId || activeCycleId || projectId;

    try {
      const normalizedArea = name.toLowerCase();

      setPlanningAdditionalProcessAreas((prev) => {
        const existing = prev[cycleKey] || [];
        if (existing.some((entry) => (entry || '').trim().toLowerCase() === normalizedArea)) return prev;
        return {
          ...prev,
          [cycleKey]: [...existing, name],
        };
      });

      setHiddenProcessAreas((prev) => {
        const existing = prev[cycleKey] || [];
        const next = existing.filter((entry) => (entry || '').trim().toLowerCase() !== normalizedArea);
        return {
          ...prev,
          [cycleKey]: next,
        };
      });

      setTreeOrder((prev) => ({
        ...prev,
        processAreas: {
          ...prev.processAreas,
          [cycleKey]: mergeOrder(prev.processAreas[cycleKey] || [], [name]),
        },
      }));

      if (activeCycleId) {
        await reloadProjectPlanData(activeCycleId);
      }

      setProcessAreaDialogOpen(false);
      setProcessAreaTargetProjectId(null);
      setProcessAreaTargetCycleId(null);
      setNewProcessAreaName('');
      // Persist immediately so the new process area survives refresh
      setTimeout(() => {
        apiClient.put('/api/hierarchy-preferences/state', {
          treeOrder, expandedPrograms: Array.from(expandedPrograms),
          expandedCycles: Array.from(expandedCycles), expandedProjectGroups: Array.from(expandedProjectGroups),
          expandedObjects: Array.from(expandedObjects), planningAdditionalGroups, planningAdditionalProcessAreas,
          hiddenProcessAreas, processAreaAccentOverrides, processAreaDescriptions, hierarchyLevelIcons,
        }).catch(() => {});
      }, 100);
    } catch (error) {
      console.error('Failed to add process area to plan:', error);
      alert('Failed to add process area to the execution plan');
    }
  };

  const handleHideProcessAreaFromTree = async (projectId: string, areaName: string) => {
    const normalizedTarget = (areaName || '').trim().toLowerCase();
    if (!normalizedTarget) return;

    try {
      const objectIdsInArea = new Set(
        projectInventoryItems
          .filter((item: any) => item.projectId === projectId && ((item.processArea || '').trim().toLowerCase() === normalizedTarget))
          .map((item: any) => item.id)
      );

      const taskGroupIdsInArea = new Set(
        projectTaskGroups
          .filter((group: any) => group.projectId === projectId && ((group.processArea || '').trim().toLowerCase() === normalizedTarget))
          .map((group: any) => group.id)
      );

      const tasksToDelete = projectTasks.filter((task: any) =>
        (task.projectObjectId && objectIdsInArea.has(task.projectObjectId)) ||
        (task.taskGroupId && taskGroupIdsInArea.has(task.taskGroupId))
      );

      await Promise.all(tasksToDelete.map((task: any) => apiClient.delete(`/api/tasks/${task.id}`)));
      await Promise.all(Array.from(taskGroupIdsInArea).map((groupId) => apiClient.delete(`/api/tasks/groups/${groupId}`)));

      setHiddenProcessAreas((prev) => {
        const existing = prev[activeCycleId || projectId] || [];
        if (existing.some((entry) => (entry || '').trim().toLowerCase() === normalizedTarget)) return prev;
        return {
          ...prev,
          [activeCycleId || projectId]: [...existing, areaName],
        };
      });

      setPlanningAdditionalProcessAreas((prev) => ({
        ...prev,
        [activeCycleId || projectId]: (prev[activeCycleId || projectId] || []).filter((entry) => (entry || '').trim().toLowerCase() !== normalizedTarget),
      }));

      setTreeOrder((prev) => ({
        ...prev,
        processAreas: {
          ...prev.processAreas,
          [activeCycleId || projectId]: (prev.processAreas[activeCycleId || projectId] || []).filter(
            (entry) => (entry || '').trim().toLowerCase() !== normalizedTarget
          ),
        },
      }));

      if (activeCycleId) {
        await reloadProjectPlanData(activeCycleId);
      }
    } catch (error) {
      console.error('Failed to remove process area from plan:', error);
      alert('Failed to remove process area from the execution plan');
    }
  };

  // Load schedule rows for all projects in the selected cycle.
  useEffect(() => {
    const loadCycleSchedule = async () => {
      if (!activeCycleId) {
        setCycleScheduleItems([]);
        return;
      }

      // If not on schedule tab, still rebuild items when dependencies change
      // (e.g., process area accents were updated on Settings page)
      // but don't fetch loading windows or perform layout calculation yet
      if (tabValue !== 3) {
        // Still update items with new accent colors when globalProcessAreaAccents changes
        // This ensures colors are current when user returns to schedule tab
      }

      const cycleProjects = getScopedProjectsForCycle(activeCycleId, selectedCycleProjectId);
      if (cycleProjects.length === 0) {
        setCycleScheduleItems([]);
        return;
      }

      let activeCycle: MockCycle | null = null;
      for (const programId in mockCycles) {
        const cycle = (mockCycles[programId] || []).find((c: MockCycle) => c.id === activeCycleId) || null;
        if (cycle) {
          activeCycle = cycle;
          break;
        }
      }

      const mockCycleName = activeCycle?.name || 'Mock Cycle';
      const mockCycleDescription = (activeCycle as any)?.description || activeCycle?.name || '';

      setIsLoadingCycleSchedule(true);
      try {
        const all = await Promise.all(
          cycleProjects.map(async (project: Project, index: number) => {
            try {
              const [objectsResponse, tasksResponse, groupsResponse] = await Promise.all([
                apiClient.get(`/api/project-objects/cycle/${activeCycleId}`),
                apiClient.get(`/api/tasks/cycle/${activeCycleId}`),
                apiClient.get(`/api/tasks/groups/cycle/${activeCycleId}`),
              ]);

              const items = objectsResponse.data?.data || [];
              const tasks = tasksResponse.data?.data || [];
              const groups = groupsResponse.data?.data || [];

              // Map each project object to a load date window (start/end).
              const loadWindowByObjectId: Record<string, { startDate: string | null; endDate: string | null }> = {};
              const loadWindowByTaskGroupId: Record<string, { startDate: string | null; endDate: string | null }> = {};
              tasks.forEach((task: any) => {
                const objectId = task.projectObjectId;
                const taskGroupId = task.taskGroupId;

                const isLoadTask =
                  (task.taskType || '').toLowerCase() === 'load' ||
                  (task.name || '').trim().toLowerCase() === 'load';

                if (!isLoadTask) return;
                if (!objectId && !taskGroupId) return;

                const startDate = task.startDate || null;
                const endDate = task.endDate || task.startDate || null;
                if (!startDate && !endDate) return;

                if (objectId) {
                  const existing = loadWindowByObjectId[objectId];
                  if (!existing) {
                    loadWindowByObjectId[objectId] = { startDate, endDate };
                  } else {
                    const nextStart = startDate && (!existing.startDate || startDate < existing.startDate)
                      ? startDate
                      : existing.startDate;
                    const nextEnd = endDate && (!existing.endDate || endDate > existing.endDate)
                      ? endDate
                      : existing.endDate;

                    loadWindowByObjectId[objectId] = {
                      startDate: nextStart,
                      endDate: nextEnd,
                    };
                  }
                }

                if (taskGroupId) {
                  const groupExisting = loadWindowByTaskGroupId[taskGroupId];
                  if (!groupExisting) {
                    loadWindowByTaskGroupId[taskGroupId] = { startDate, endDate };
                  } else {
                    const groupNextStart = startDate && (!groupExisting.startDate || startDate < groupExisting.startDate)
                      ? startDate
                      : groupExisting.startDate;
                    const groupNextEnd = endDate && (!groupExisting.endDate || endDate > groupExisting.endDate)
                      ? endDate
                      : groupExisting.endDate;
                    loadWindowByTaskGroupId[taskGroupId] = {
                      startDate: groupNextStart,
                      endDate: groupNextEnd,
                    };
                  }
                }
              });

              const projectColor = getProjectAccentColor(project, index);
              const objectRows = items.map((item: any) => {
                const processArea = (item.processArea || '').trim() || 'Unassigned Process Area';
                const processAreaAccent = getProcessAreaAccent(project.id, processArea, projectColor);
                return {
                  ...item,
                  scheduleEntityType: 'object',
                  entityLabel: item.objectId || 'Data Object',
                  processArea,
                  processAreaAccent,
                  taskGroupName: '',
                  mockCycleName,
                  mockCycleDescription,
                  projectName: project.name,
                  projectColor,
                  projectId: project.id,
                  loadStartDate: loadWindowByObjectId[item.id]?.startDate || null,
                  loadEndDate: loadWindowByObjectId[item.id]?.endDate || null,
                };
              });

              const taskGroupRows = groups.map((group: any) => {
                const processArea = (group.processArea || '').trim() || 'Unassigned Process Area';
                const processAreaAccent = getProcessAreaAccent(project.id, processArea, projectColor);
                return {
                  id: group.id,
                  description: group.name || 'Task Group',
                  scheduleEntityType: 'taskGroup',
                  entityLabel: group.name || 'Task Group',
                  processArea,
                  processAreaAccent,
                  taskGroupName: group.name || 'Task Group',
                  mockCycleName,
                  mockCycleDescription,
                  projectName: project.name,
                  projectColor,
                  projectId: project.id,
                  loadStartDate: loadWindowByTaskGroupId[group.id]?.startDate || null,
                  loadEndDate: loadWindowByTaskGroupId[group.id]?.endDate || null,
                };
              });

              return [...objectRows, ...taskGroupRows];
            } catch {
              return [];
            }
          })
        );

        // Deduplicate schedule items by object name + sub-object suffix (not DB id)
        // This handles the case where two project instances have the same logical object
        const seen = new Set<string>();
        const deduped = all.flat().filter(item => {
          const key = item.scheduleEntityType === 'object'
            ? `obj:${item.objectId || item.entityLabel}:${item.subObjectSuffix || ''}:${item.cycleId || ''}`
            : `grp:${item.taskGroupName}:${item.projectId}:${item.cycleId || ''}`;
          if (seen.has(key)) return false;
          seen.add(key);
          return true;
        });
        setCycleScheduleItems(deduped);
      } finally {
        setIsLoadingCycleSchedule(false);
      }
    };

    loadCycleSchedule();
  }, [tabValue, activeCycleId, selectedCycleProjectId, projectsByMockCycle, globalProcessAreaAccents]);

  // Load persisted ordering when project changes.
  useEffect(() => {
    if (!activeProjectId) {
      setPlanRowOrder([]);
      return;
    }
    try {
      const raw = localStorage.getItem(getOrderStorageKey(activeProjectId));
      if (!raw) {
        setPlanRowOrder([]);
        return;
      }
      const parsed = JSON.parse(raw);
      if (Array.isArray(parsed?.rows)) {
        setPlanRowOrder(parsed.rows);
      } else {
        const objects = Array.isArray(parsed?.objects) ? parsed.objects : [];
        const groups = Array.isArray(parsed?.groups) ? parsed.groups : [];
        setPlanRowOrder([
          ...objects.map((id: string) => objectRowKey(id)),
          ...groups.map((id: string) => taskGroupRowKey(id)),
        ]);
      }
    } catch {
      setPlanRowOrder([]);
    }
  }, [activeProjectId, activeCycleId]);

  // Keep ordering synced with available ids.
  useEffect(() => {
    if (!activeProjectId) return;
    const objectIds = projectInventoryItems.map((item: any) => item.id);
    const groupIds = projectTaskGroups.map(g => g.id);
    const currentKeys = [
      ...objectIds.map((id: string) => objectRowKey(id)),
      ...groupIds.map((id: string) => taskGroupRowKey(id)),
    ];
    setPlanRowOrder(prev => mergeOrder(prev, currentKeys));
  }, [activeProjectId, projectInventoryItems, projectTaskGroups]);

  // Load persisted tree ordering.
  useEffect(() => {
    let cancelled = false;

    const applyTreeOrder = (parsed: any) => {
      setTreeOrder({
        programs: Array.isArray(parsed?.programs) ? parsed.programs : [],
        cycles: typeof parsed?.cycles === 'object' && parsed?.cycles ? parsed.cycles : {},
        projects: typeof parsed?.projects === 'object' && parsed?.projects ? parsed.projects : {},
        projectGroups: typeof parsed?.projectGroups === 'object' && parsed?.projectGroups ? parsed.projectGroups : {},
        processAreas: typeof parsed?.processAreas === 'object' && parsed?.processAreas ? parsed.processAreas : {},
      });
    };

    const applyExpandedState = (parsed: any) => {
      setExpandedPrograms(new Set(Array.isArray(parsed?.expandedPrograms) ? parsed.expandedPrograms : []));
      setExpandedCycles(new Set(Array.isArray(parsed?.expandedCycles) ? parsed.expandedCycles : []));
      // Restore saved project group expansion; if none saved, expand all groups
      // so cycles are always visible without requiring an extra click.
      const savedGroups = Array.isArray(parsed?.expandedProjectGroups) ? parsed.expandedProjectGroups : null;
      setExpandedProjectGroups(new Set(savedGroups ?? []));
      setExpandedObjects(new Set());
    };

    const hydrateHierarchyState = async () => {
      try {
        const response = await apiClient.get('/api/hierarchy-preferences/state');
        const parsed = response.data?.data;
        if (!cancelled && parsed && typeof parsed === 'object') {
          if (parsed?.treeOrder) applyTreeOrder(parsed.treeOrder);
          if (parsed?.expandedPrograms || parsed?.expandedCycles || parsed?.expandedProjectGroups || parsed?.expandedObjects) {
            applyExpandedState(parsed);
          }
          if (parsed?.planningAdditionalGroups && typeof parsed.planningAdditionalGroups === 'object') setPlanningAdditionalGroups(parsed.planningAdditionalGroups);
          if (parsed?.deliverableTaskGroupAssignments && typeof parsed.deliverableTaskGroupAssignments === 'object') {
            setDeliverableTaskGroupAssignments(parsed.deliverableTaskGroupAssignments);
          }
          const resolvedTaskOptions = normalizeTaskOptions(parsed?.designBuildEstimationTasks);
          setDesignBuildEstimationTasks(resolvedTaskOptions);
          setDesignBuildEstimationRows(normalizeEstimationRows(parsed?.designBuildEstimationRows, resolvedTaskOptions));
          if (parsed?.planningAdditionalProcessAreas && typeof parsed.planningAdditionalProcessAreas === 'object') setPlanningAdditionalProcessAreas(parsed.planningAdditionalProcessAreas);
          if (parsed?.hiddenProcessAreas && typeof parsed.hiddenProcessAreas === 'object') setHiddenProcessAreas(parsed.hiddenProcessAreas);
          if (parsed?.projectManualProcessAreas && typeof parsed.projectManualProcessAreas === 'object') setProjectManualProcessAreas(parsed.projectManualProcessAreas);
          if (parsed?.processAreaAccentOverrides && typeof parsed.processAreaAccentOverrides === 'object') setProcessAreaAccentOverrides(parsed.processAreaAccentOverrides);
          if (parsed?.processAreaIconOverrides && typeof parsed.processAreaIconOverrides === 'object') setProcessAreaIconOverrides(parsed.processAreaIconOverrides);
          if (parsed?.processAreaDescriptions && typeof parsed.processAreaDescriptions === 'object') setProcessAreaDescriptions(parsed.processAreaDescriptions);
          if (parsed?.hierarchyLevelIcons && typeof parsed.hierarchyLevelIcons === 'object') {
            setHierarchyLevelIcons({
              ...DEFAULT_HIERARCHY_LEVEL_ICONS,
              ...parsed.hierarchyLevelIcons,
            });
          }
          if (parsed?.globalProcessAreaAccents && typeof parsed.globalProcessAreaAccents === 'object') {
            setGlobalProcessAreaAccents(parsed.globalProcessAreaAccents);
          }
          if (parsed?.globalProcessAreaIcons && typeof parsed.globalProcessAreaIcons === 'object') {
            setGlobalProcessAreaIcons(parsed.globalProcessAreaIcons as Record<string, HierarchyIconChoice>);
          }
          if (parsed?.globalProcessAreaDescriptions && typeof parsed.globalProcessAreaDescriptions === 'object') {
            setGlobalProcessAreaDescriptions(parsed.globalProcessAreaDescriptions);
          }
          if (parsed?.picklistValues && typeof parsed.picklistValues === 'object') {
            setPicklists(prev => {
              const merged = { ...prev };
              for (const [key, vals] of Object.entries(parsed.picklistValues as Record<string, string[]>)) {
                if (Array.isArray(vals) && vals.length > 0) merged[key] = vals;
              }
              return merged;
            });
          }
          setHierarchyStateHydrated(true);
          return;
        }
      } catch {
        // Fallback to local storage when no DB preference exists yet.
      }

      if (!cancelled) {
        setHierarchyStateHydrated(true);
      }
    };

    hydrateHierarchyState();

    // Re-load global process area settings when the user returns to this page
    // (e.g. after saving on the Settings page in the same browser tab).
    const handleVisibility = () => {
      if (document.visibilityState === 'visible') {
        apiClient.get('/api/hierarchy-preferences/state').then(res => {
          const parsed = res.data?.data;
          if (!parsed) return;
          if (parsed.globalProcessAreaAccents && typeof parsed.globalProcessAreaAccents === 'object') {
            setGlobalProcessAreaAccents(parsed.globalProcessAreaAccents);
          }
          if (parsed.globalProcessAreaIcons && typeof parsed.globalProcessAreaIcons === 'object') {
            setGlobalProcessAreaIcons(parsed.globalProcessAreaIcons as Record<string, HierarchyIconChoice>);
          }
          if (parsed.globalProcessAreaDescriptions && typeof parsed.globalProcessAreaDescriptions === 'object') {
            setGlobalProcessAreaDescriptions(parsed.globalProcessAreaDescriptions);
          }
          if (parsed.picklistValues && typeof parsed.picklistValues === 'object') {
            setPicklists(prev => {
              const merged = { ...prev };
              for (const [key, vals] of Object.entries(parsed.picklistValues as Record<string, string[]>)) {
                if (Array.isArray(vals) && vals.length > 0) merged[key] = vals;
              }
              return merged;
            });
          }
          // Also reload per-cycle overrides — Settings page may have cleared them.
          if (typeof parsed.processAreaAccentOverrides === 'object') {
            setProcessAreaAccentOverrides(parsed.processAreaAccentOverrides || {});
          }
          if (typeof parsed.processAreaIconOverrides === 'object') {
            setProcessAreaIconOverrides(parsed.processAreaIconOverrides || {});
          }
          if (typeof parsed.deliverableTaskGroupAssignments === 'object') {
            setDeliverableTaskGroupAssignments(parsed.deliverableTaskGroupAssignments || {});
          }
          if (typeof parsed.projectManualProcessAreas === 'object') {
            setProjectManualProcessAreas(parsed.projectManualProcessAreas || {});
          }
          const resolvedTaskOptions = normalizeTaskOptions(parsed.designBuildEstimationTasks);
          setDesignBuildEstimationTasks(resolvedTaskOptions);
          setDesignBuildEstimationRows(normalizeEstimationRows(parsed.designBuildEstimationRows, resolvedTaskOptions));
        }).catch(() => {});
      }
    };
    document.addEventListener('visibilitychange', handleVisibility);

    return () => {
      cancelled = true;
      document.removeEventListener('visibilitychange', handleVisibility);
    };
  }, []);

  // Refresh global process area settings when switching to Schedule tab
  // (user may have edited colors on Settings page while on different tab)
  useEffect(() => {
    if (tabValue === 3) {
      apiClient.get('/api/hierarchy-preferences/state').then(res => {
        const parsed = res.data?.data;
        if (!parsed) return;
        if (parsed.globalProcessAreaAccents && typeof parsed.globalProcessAreaAccents === 'object') {
          setGlobalProcessAreaAccents(parsed.globalProcessAreaAccents);
        }
        if (parsed.globalProcessAreaIcons && typeof parsed.globalProcessAreaIcons === 'object') {
          setGlobalProcessAreaIcons(parsed.globalProcessAreaIcons as Record<string, HierarchyIconChoice>);
        }
        if (parsed.globalProcessAreaDescriptions && typeof parsed.globalProcessAreaDescriptions === 'object') {
          setGlobalProcessAreaDescriptions(parsed.globalProcessAreaDescriptions);
        }
      }).catch(() => {});
    }
  }, [tabValue]);

  // Sync tree ordering when data changes.
  useEffect(() => {
    setTreeOrder(prev => {
      const nextPrograms = mergeOrder(prev.programs, programs.map((p: Program) => p.id));
      const nextCycles: Record<string, string[]> = { ...prev.cycles };
      for (const programId in mockCycles) {
        const cycles = mockCycles[programId] || [];
        const cycleIds = new Set(cycles.map((c: MockCycle) => c.id));
        nextCycles[programId] = (prev.cycles[programId] || []).filter((id: string) => cycleIds.has(id));
      }
      const nextProjects: Record<string, string[]> = { ...prev.projects };
      for (const cycleId in projectsByMockCycle) {
        const projects = projectsByMockCycle[cycleId] || [];
        nextProjects[cycleId] = mergeOrder(prev.projects[cycleId] || [], projects.map((p: Project) => p.id));
      }
      const nextProjectGroups: Record<string, string[]> = { ...prev.projectGroups };
      for (const programId in projectsByProgram) {
        const groups = Array.from(new Set(
          ((projectsByProgram[programId] || []) as Project[])
            .map((project: Project) => getProjectGroupOrderKey(project.name || ''))
            .filter(Boolean)
        ));
        nextProjectGroups[programId] = mergeOrder(prev.projectGroups[programId] || [], groups);
      }
      const nextProcessAreas: Record<string, string[]> = { ...prev.processAreas };
      for (const cycleId in projectsByMockCycle) {
        const cycleProjects = projectsByMockCycle[cycleId] || [];
        cycleProjects.forEach((project: Project) => {
          const areaLabels = new Set<string>();
          const summaryKey = `${project.id}_${cycleId}`;
          const cachedAreas = projectHierarchySummaries[summaryKey]?.processAreas || {};
          Object.keys(cachedAreas).forEach((area) => {
            const label = (area || '').trim();
            if (label) areaLabels.add(label);
          });
          projectInventoryItems
            .filter((item: any) => item.projectId === project.id)
            .forEach((item: any) => {
              const label = (item.processArea || '').trim();
              if (label) areaLabels.add(label);
            });
          nextProcessAreas[project.id] = mergeOrder(prev.processAreas[project.id] || [], Array.from(areaLabels));
        });
      }
      return { programs: nextPrograms, cycles: nextCycles, projects: nextProjects, projectGroups: nextProjectGroups, processAreas: nextProcessAreas };
    });
  }, [programs, mockCycles, projectsByMockCycle, projectsByProgram, projectHierarchySummaries, projectInventoryItems]);

  useEffect(() => {
    const projectRecords = Object.values(projectsByMockCycle)
      .flat()
      .map((project: any) => ({
        id: String(project?.id || '').trim(),
        nameKey: String(project?.name || '').trim().toLowerCase(),
        programId: String(project?.programId || '').trim(),
      }))
      .filter((project) => !!project.id);
    const projectIds = Array.from(new Set(projectRecords.map((project) => project.id)));
    if (projectIds.length === 0) {
      setProjectAssignedProcessAreas({});
      return;
    }

    let cancelled = false;
    (async () => {
      try {
        const responses = await Promise.all(projectIds.map(async (projectId) => {
          try {
            const response = await apiClient.get(`/api/hierarchy-preferences/project-role-assignments/${projectId}`);
            const processAreas = Array.isArray(response.data?.data?.processAreas) ? response.data.data.processAreas : [];
            return [projectId, processAreas] as const;
          } catch {
            return [projectId, []] as const;
          }
        }));
        if (cancelled) return;
        const nextMap: Record<string, string[]> = {};
        responses.forEach(([projectId, areas]) => {
          const normalizedAreas: string[] = areas
            .map((entry: any) => String(entry || '').trim())
            .filter((entry: string) => !!entry);
          nextMap[projectId] = Array.from(new Set(normalizedAreas)).sort((a, b) => a.localeCompare(b));
        });

        // Some cycles may reference the same project by different IDs.
        // Union assignments by program + project name so each cycle instance
        // shows the full assigned area set.
        const byProjectGroup: Record<string, Set<string>> = {};
        projectRecords.forEach((project) => {
          const groupKey = `${project.programId}::${project.nameKey}`;
          if (!project.nameKey) return;
          if (!byProjectGroup[groupKey]) byProjectGroup[groupKey] = new Set<string>();
          (nextMap[project.id] || []).forEach((area) => byProjectGroup[groupKey].add(area));
        });

        const normalizedMap: Record<string, string[]> = { ...nextMap };
        projectRecords.forEach((project) => {
          const groupKey = `${project.programId}::${project.nameKey}`;
          const groupedAreas = byProjectGroup[groupKey];
          if (!groupedAreas || groupedAreas.size === 0) return;
          normalizedMap[project.id] = Array.from(groupedAreas).sort((a, b) => a.localeCompare(b));
        });

        setProjectAssignedProcessAreas(normalizedMap);
      } catch {
        if (!cancelled) setProjectAssignedProcessAreas({});
      }
    })();

    return () => {
      cancelled = true;
    };
  }, [projectsByMockCycle]);

  // Persist tree ordering.
  // Also ensure all project groups for expanded programs are auto-expanded so
  // cycles are never hidden because a project group key is missing from saved state.
  useEffect(() => {
    if (!hierarchyStateHydrated || programs.length === 0) return;
    setExpandedProjectGroups(prev => {
      const next = new Set(prev);
      let changed = false;
      programs.forEach((prog: any) => {
        if (!expandedPrograms.has(prog.id)) return;
        const projectList = getProjectsByProgram(prog.id);
        projectList.forEach((project: Project) => {
          const key = `${prog.id}:${(project.name || '').trim().toLowerCase()}`;
          if (!next.has(key)) { next.add(key); changed = true; }
        });
      });
      return changed ? next : prev;
    });
  // Only run when programs/expandedPrograms change, not on every projectsByProgram update
  // eslint-disable-next-line react-hooks/exhaustive-deps
  }, [hierarchyStateHydrated, expandedPrograms, programs]);

  // Persist tree ordering to the server.
  useEffect(() => {
    if (!hierarchyStateHydrated) return;

    const payload = {
      treeOrder,
      expandedPrograms: Array.from(expandedPrograms),
      expandedCycles: Array.from(expandedCycles),
      expandedProjectGroups: Array.from(expandedProjectGroups),
      expandedObjects: Array.from(expandedObjects),
      planningAdditionalGroups,
      deliverableTaskGroupAssignments,
      planningAdditionalProcessAreas,
      hiddenProcessAreas,
      processAreaAccentOverrides,
      processAreaIconOverrides,
      processAreaDescriptions,
      hierarchyLevelIcons,
      globalProcessAreaAccents,
      globalProcessAreaIcons,
    };

    const timeout = setTimeout(() => {
      const serialized = JSON.stringify(payload);
      if (serialized === lastHierarchyPersistPayloadRef.current) return;
      lastHierarchyPersistPayloadRef.current = serialized;

      apiClient.put('/api/hierarchy-preferences/state', payload).catch(() => {
        // No-op: hierarchy state is shared through the database.
      });
    }, 450);

    return () => clearTimeout(timeout);
  }, [
    treeOrder,
    expandedPrograms,
    expandedCycles,
    expandedProjectGroups,
    expandedObjects,
    planningAdditionalGroups,
    deliverableTaskGroupAssignments,
    planningAdditionalProcessAreas,
    hiddenProcessAreas,
    processAreaAccentOverrides,
    processAreaIconOverrides,
    processAreaDescriptions,
    hierarchyLevelIcons,
    globalProcessAreaAccents,
    globalProcessAreaIcons,
    hierarchyStateHydrated,
  ]);

  // Persist ordering.
  useEffect(() => {
    if (!activeProjectId) return;
    const objectIds = planRowOrder.filter((k: string) => k.startsWith('obj:')).map((k: string) => k.slice(4));
    const groupIds = planRowOrder.filter((k: string) => k.startsWith('grp:')).map((k: string) => k.slice(4));
    localStorage.setItem(getOrderStorageKey(activeProjectId), JSON.stringify({
      rows: planRowOrder,
      objects: objectIds,
      groups: groupIds,
    }));
  }, [activeProjectId, planRowOrder]);

  // Fetch project inventory items when a project is selected
  useEffect(() => {
    const loadProjectInventory = async () => {
      if (!activeCycleId && !activeProjectId) {
        setProjectInventoryItems([]);
        setSelectedExecutionProcessArea('');
        projectInventoryLoadedRef.current = false;
        return;
      }

      projectInventoryLoadedRef.current = false;

      try {
        let objects: any[] = [];
        let taskObjectIds: string[] = [];
        // IDs of objects that belong to this cycle's own plan (cycle-scoped).
        // Used to tag items with isCycleScoped so the plan view vs. picker can differ.
        let cycleObjIds = new Set<string>();

        if (activeCycleId) {
          // Execution planning context: load project-inventory objects (shared across cycles)
          // and tasks for this specific cycle.  Tasks reference inventory objects by ID.
          // Loading both here atomically eliminates the race where objects show but tasks haven't loaded yet.
          // Load from ALL project instances with the same name (sibling projects across cycles)
          // so inventory items added via the Inventory tab are visible here regardless of which
          // project ID was used when adding them.
          const projectId = activeProjectId;
          const siblingProjectIds = new Set<string>();
          if (projectId) {
            siblingProjectIds.add(projectId);
            const projectRecord = Object.values(projectsByProgram).flat().find((p: any) => p.id === projectId);
            const projectName = (projectRecord?.name || '').trim().toLowerCase();
            const projectProgramId = projectRecord?.programId || '';
            if (projectName && projectProgramId) {
              Object.values(projectsByProgram).flat().forEach((p: any) => {
                if (p.programId === projectProgramId && (p.name || '').trim().toLowerCase() === projectName) {
                  siblingProjectIds.add(p.id);
                }
              });
            }
          }
          const [objResponses, taskRes] = await Promise.all([
            Promise.all(Array.from(siblingProjectIds).map(pid =>
              apiClient.get(`/api/project-objects/project/${pid}`).then(r => r.data.data || []).catch(() => [])
            )),
            apiClient.get(`/api/tasks/cycle/${activeCycleId}`),
          ]);
          // Deduplicate objects by ID in case they appear across project instances
          const seenIds = new Set<string>();
          objects = objResponses.flat().filter((obj: any) => { if (seenIds.has(obj.id)) return false; seenIds.add(obj.id); return true; });
          const cycleTasks = taskRes.data.data || [];
          taskObjectIds = cycleTasks.map((task: any) => task.projectObjectId).filter(Boolean);
          // Normalize dates and apply sibling-context end-date correction in one pass
          // so the state is correct from the first render (avoids race with loadTasksAndGroups).
          const normalizedTasks = cycleTasks.map((task: any) => normalizeTaskDateFields(task));
          const correctedTasks = applyAutoSchedule(normalizedTasks);
          setProjectTasks(correctedTasks);
          setProjectTaskGroups(await apiClient.get(`/api/tasks/groups/cycle/${activeCycleId}`).then(r => r.data.data || []).catch(() => []));
        } else {
          // Inventory tab context: load objects scoped to the selected project.
          const selectedProjectRecord = Object.values(projectsByProgram).flat().find((project: any) => project.id === activeProjectId) || null;
          const selectedProjectName = (selectedProjectRecord?.name || '').trim().toLowerCase();
          const selectedProjectProgramId = selectedProjectRecord?.programId || '';
          const siblingProjectIds = new Set<string>([activeProjectId as string]);
          const programProjects = selectedProjectProgramId
            ? Object.values(projectsByProgram).flat().filter((project: any) => project.programId === selectedProjectProgramId)
            : [];
          if (selectedProjectName) {
            programProjects.forEach((project: any) => {
              if ((project.name || '').trim().toLowerCase() === selectedProjectName) {
                siblingProjectIds.add(project.id);
              }
            });
          }
          const responses = await Promise.all(
            Array.from(siblingProjectIds).map(async (projectId) => {
              const response = await apiClient.get(`/api/project-objects/project/${projectId}`);
              return response.data.data || [];
            })
          );
          const taskResponses = await Promise.all(
            Array.from(siblingProjectIds).map(async (projectId) => {
              const response = await apiClient.get(`/api/tasks/project/${projectId}`);
              return response.data.data || [];
            })
          );
          objects = responses.flat();
          taskObjectIds = taskResponses.flat().map((task: any) => task.projectObjectId).filter(Boolean);
        }

        const itemsById = new Map<string, any>();
        objects.forEach((item: any) => {
          itemsById.set(item.id, {
            id: item.id,
            projectId: item.projectId,
            dataObjectId: item.objectId,
            objectId: item.objectId,
            globalObjectId: item.globalObjectId,
            parentProjectObjectId: item.parentProjectObjectId || '',
            parentObjectId: item.parentObjectId || '',
            subObjectSuffix: item.subObjectSuffix || '',
            subObjectDescription: item.subObjectDescription || '',
            isSubObject: !!item.parentProjectObjectId,
            processArea: item.processArea,
            targetApplicationId: item.targetApplicationId || '',
            targetApplicationName: item.targetApplicationName || '',
            sourceApplicationId: item.sourceApplicationId || '',
            sourceApplicationName: item.sourceApplicationName || '',
            complexity: item.complexity,
            deploymentDisposition: item.deploymentDisposition,
            buildType: item.buildType,
            objectType: item.objectType,
            cutoverPhase: item.cutoverPhase,
            ddmApproach: item.ddmApproach,
            riskSecurityType: item.riskSecurityType,
            migrationType: item.migrationType,
            factorType: item.factorType,
            loadMethod: item.loadMethod,
            startDate: item.startDate,
            endDate: item.endDate,
          });
        });

        setProjectInventoryItems(Array.from(itemsById.values()));
        setProjectInventoryTaskObjectIds(Array.from(new Set(taskObjectIds)));
        projectInventoryLoadedRef.current = true;
      } catch (error) {
        console.error('Failed to load project inventory:', error);
        setProjectInventoryItems([]);
        setProjectInventoryTaskObjectIds([]);
        projectInventoryLoadedRef.current = false;
      }
    };

    loadProjectInventory();
  // Only re-run when the cycle or project changes — NOT on background refetches
  // of projectsByMockCycle/projectsByProgram (which would cause a stale-data flash).
  // eslint-disable-next-line react-hooks/exhaustive-deps
  }, [activeCycleId, activeProjectId]);

  useEffect(() => {
    if (selectedItem?.type === 'processArea') {
      setSelectedExecutionProcessArea(selectedItem.area);
      return;
    }
    setSelectedExecutionProcessArea('');
  }, [activeProjectId, selectedItem]);

  // Load tasks and task groups when project is selected
  useEffect(() => {
    const loadTasksAndGroups = async () => {
      if (!activeCycleId && !activeProjectId) {
        setProjectTasks([]);
        setProjectTaskGroups([]);
        setTaskCommentCounts({});
        projectTasksLoadedRef.current = false;
        return;
      }

      projectTasksLoadedRef.current = false;

      try {
        // Load tasks — prefer cycle-scoped endpoint; fall back to project-scoped
        // (tab 1 Inventory context uses activeProjectId directly).
        const taskUrl = activeCycleId
          ? `/api/tasks/cycle/${activeCycleId}`
          : `/api/tasks/project/${activeProjectId}`;
        const tasksResponse = await apiClient.get(taskUrl);
        const tasks = (tasksResponse.data.data || []).map((task: any) => normalizeTaskDateFields(task));
        setProjectTasks(applyAutoSchedule(tasks));

        // Load task dependencies for all tasks in parallel
        const allDeps: Record<string, any[]> = {};
        const depsTs = Date.now();
        await Promise.all(tasks.map(async (task: any) => {
          try {
            const depsRes = await apiClient.get(`/api/tasks/${task.id}/dependencies?t=${depsTs}`);
            allDeps[task.id] = depsRes.data.data || [];
          } catch (e) {
            allDeps[task.id] = [];
          }
        }));
        setTaskDeps(allDeps);

        // Cascade dates for tasks with explicit dependency arrows.
        await cascadeAllDates(tasks, allDeps);

        // Auto-schedule sibling tasks: recalculate end dates using cumulative
        // fraction even when no explicit dependency arrows exist.
        const scheduledTasks = applyAutoSchedule(tasks);
        if (scheduledTasks !== tasks) {
          setProjectTasks(prev => {
            const correctedMap: Record<string, string> = {};
            scheduledTasks.forEach(st => { if (st !== tasks.find(t => t.id === st.id)) correctedMap[st.id] = st.endDate; });
            return prev.map(t => correctedMap[t.id] ? { ...t, endDate: correctedMap[t.id] } : t);
          });
        }

        // Load task groups
        const groupUrl = activeCycleId
          ? `/api/tasks/groups/cycle/${activeCycleId}`
          : `/api/tasks/groups/project/${activeProjectId}`;
        const groupsResponse = await apiClient.get(groupUrl);
        const groups = groupsResponse.data.data || [];
        setProjectTaskGroups(groups);

        // Fetch comment counts for each task
        const commentCounts: Record<string, number> = {};
        for (const task of tasks) {
          try {
            const commentsRes = await apiClient.get(`/api/comments/task/${task.id}`);
            commentCounts[task.id] = (commentsRes.data.data || []).length;
          } catch (e) {
            commentCounts[task.id] = 0;
          }
        }
        setTaskCommentCounts(commentCounts);
        projectTasksLoadedRef.current = true;

        // Sync any localStorage-only plan groups to the DB so they are
        // included in future cycle copies.
        if (activeCycleId && activeProjectId) {
          const localGroupNames: string[] = getVisiblePlanningAdditionalGroups(activeProjectId, activeCycleId);
          const dbGroupNames = new Set(groups.map((g: any) => (g.name || '').trim().toLowerCase()));
          const missingNames = localGroupNames.filter(n => n.trim() && !dbGroupNames.has(n.trim().toLowerCase()));
          for (const name of missingNames) {
            try {
              const syncRes = await apiClient.post(`/api/tasks/groups/cycle/${activeCycleId}`, { name: name.trim(), processArea: null });
              const synced = syncRes.data?.data;
              if (synced) setProjectTaskGroups(prev => prev.some((g: any) => g.id === synced.id) ? prev : [...prev, synced]);
            } catch (e) { console.error('[sync] plan group:', name, e); }
          }

          // Also populate planningAdditionalGroups from DB task_groups that have no
          // process_area — these are top-level plan group nodes in the hierarchy.
          // This ensures cycles that received data via copy show correctly.
          const topLevelGroupNames = groups
            .filter((g: any) => !g.processArea && !isDeliverableAssignedGroup(activeProjectId, g))
            .map((g: any) => (g.name || '').trim())
            .filter(Boolean);
          if (topLevelGroupNames.length > 0) {
            setPlanningAdditionalGroups(prev => {
              const existing = new Set((prev[activeCycleId || activeProjectId] || []).map((n: string) => n.toLowerCase()));
              const toAdd = topLevelGroupNames.filter((n: string) => !existing.has(n.toLowerCase()));
              if (toAdd.length === 0) return prev;
              return { ...prev, [activeCycleId || activeProjectId]: [...(prev[activeCycleId || activeProjectId] || []), ...toAdd] };
            });
          }
        }
      } catch (error) {
        console.error('Failed to load tasks:', error);
        setProjectTasks([]);
        setProjectTaskGroups([]);
        projectTasksLoadedRef.current = false;
      }
    };

    loadTasksAndGroups();
  // Intentionally keyed only by active cycle/project so background state updates
  // (like task group state mutations) do not re-trigger full task/comments reload loops.
  // eslint-disable-next-line react-hooks/exhaustive-deps
  }, [activeProjectId, activeCycleId]);

  useEffect(() => {
    seededDefaultTaskObjectsRef.current = new Set();
    projectTasksLoadedRef.current = false;
    projectInventoryLoadedRef.current = false;
  }, [activeProjectId, activeCycleId]);

  useEffect(() => {
    if (!activeProjectId) return;
    if (!projectTasksLoadedRef.current || !projectInventoryLoadedRef.current) return;
    if (defaultTaskOrder.length === 0) return;

    const seededIds = seededDefaultTaskObjectsRef.current;
    const inventoryById = new Map(projectInventoryItems.map((item: any) => [item.id, item]));
    const assignedParentObjectIds = new Set(
      projectTasks
        .filter((task: any) => !!task.projectObjectId)
        .map((task: any) => task.projectObjectId)
        .filter((objectId: string) => {
          const item = inventoryById.get(objectId);
          return !!item && !item.parentProjectObjectId;
        })
    );
    const subObjectsNeedingDefaults = projectInventoryItems.filter((item: any) =>
      item.parentProjectObjectId &&
      assignedParentObjectIds.has(item.parentProjectObjectId) &&
      !projectTasks.some((task: any) => task.projectObjectId === item.id) &&
      !seededIds.has(item.id)
    );

    if (subObjectsNeedingDefaults.length === 0) return;

    let cancelled = false;
    (async () => {
      for (const subObject of subObjectsNeedingDefaults) {
        seededIds.add(subObject.id);
        try {
          const tasksResponse = await apiClient.post(`/api/tasks/defaults/project-object-cycle/${subObject.id}`, {
            mockCycleId: activeCycleId,
          });
          if (cancelled) return;
          const seededTasks = (tasksResponse.data.data || []).map((t: any) => normalizeTaskDateFields(t));
          if (seededTasks.length > 0) {
            setProjectTasks(prev => [...prev, ...seededTasks]);
          }
        } catch (error) {
          console.error('Failed to seed default tasks for sub-object:', error);
          seededIds.delete(subObject.id);
        }
      }
    })();

    return () => {
      cancelled = true;
    };
  }, [activeProjectId, projectInventoryItems, projectTasks, defaultTaskOrder]);

  useEffect(() => {
    const loadCycleOverview = async () => {
      if (tabValue !== 0 || selectedItem?.type !== 'cycle') {
        setCycleOverview(null);
        return;
      }

      const cycleId = selectedItem.id;
      const projects = getScopedProjectsForCycle(cycleId, selectedItem.projectId || null);

      if (projects.length === 0) {
        setCycleOverview({
          projectCount: 0,
          objectCount: 0,
          taskGroupCount: 0,
          taskCount: 0,
          statusCounts: { complete: 0, in_progress: 0, blocked: 0, not_started: 0 },
          progressPct: 0,
          timelineStart: null,
          timelineEnd: null,
        });
        return;
      }

      try {
        setIsLoadingCycleOverview(true);
        const perProject = await Promise.all(projects.map(async (project: Project) => {
          const cycleId = project.mockCycleId;
          if (!cycleId) {
            return { tasks: [], objects: [], groups: [] };
          }
          const [tasksRes, objectsRes, groupsRes] = await Promise.all([
            apiClient.get(`/api/tasks/cycle/${cycleId}`),
            apiClient.get(`/api/project-objects/cycle/${cycleId}`),
            apiClient.get(`/api/tasks/groups/cycle/${cycleId}`),
          ]);

          return {
            tasks: tasksRes.data?.data || [],
            objects: objectsRes.data?.data || [],
            groups: groupsRes.data?.data || [],
          };
        }));

        const allTasks = perProject.flatMap((item: any) => item.tasks);
        const objectCount = perProject.reduce((sum: number, item: any) => sum + (item.objects?.length || 0), 0);
        const taskGroupCount = perProject.reduce((sum: number, item: any) => sum + (item.groups?.length || 0), 0);

        let minDate: Date | null = null;
        let maxDate: Date | null = null;
        for (const task of allTasks) {
          const start = normalizeDateOnly(task.startDate || undefined);
          const end = normalizeDateOnly(task.endDate || undefined);
          if (start && (!minDate || start < minDate)) minDate = start;
          if (end && (!maxDate || end > maxDate)) maxDate = end;
        }

        const statusCounts = {
          complete: allTasks.filter((task: any) => task.status === 'complete').length,
          in_progress: allTasks.filter((task: any) => task.status === 'in_progress').length,
          blocked: allTasks.filter((task: any) => task.status === 'blocked').length,
          not_started: allTasks.filter((task: any) => task.status === 'not_started').length,
        };

        const progressPct = allTasks.length > 0
          ? Math.round(allTasks.reduce((sum: number, task: any) => sum + (task.progressPercentage ?? 0), 0) / allTasks.length)
          : Math.round(projects.reduce((sum, project) => sum + (project.progressPercentage || 0), 0) / Math.max(1, projects.length));

        const formatDate = (value: Date | null) => {
          if (!value) return null;
          return `${value.getFullYear()}-${String(value.getMonth() + 1).padStart(2, '0')}-${String(value.getDate()).padStart(2, '0')}`;
        };

        setCycleOverview({
          projectCount: projects.length,
          objectCount,
          taskGroupCount,
          taskCount: allTasks.length,
          statusCounts,
          progressPct,
          timelineStart: formatDate(minDate),
          timelineEnd: formatDate(maxDate),
        });
      } catch (error) {
        console.error('Failed to load cycle overview:', error);
        setCycleOverview(null);
      } finally {
        setIsLoadingCycleOverview(false);
      }
    };

    loadCycleOverview();
  }, [tabValue, selectedItem, projectsByMockCycle]);

  useEffect(() => {
    const loadProgramOverview = async () => {
      if (tabValue !== 0 || selectedItem?.type !== 'program') {
        setProgramOverview(null);
        return;
      }

      const cycles = mockCycles[selectedItem.id] || [];
      const projects = cycles.flatMap((cycle: MockCycle) => projectsByMockCycle[cycle.id] || []);

      if (projects.length === 0) {
        setProgramOverview({
          projectCount: 0,
          objectCount: 0,
          taskGroupCount: 0,
          taskCount: 0,
          statusCounts: { complete: 0, in_progress: 0, blocked: 0, not_started: 0 },
          progressPct: 0,
          timelineStart: null,
          timelineEnd: null,
        });
        return;
      }

      try {
        setIsLoadingProgramOverview(true);
        const perProject = await Promise.all(projects.map(async (project: Project) => {
          const cycleId = project.mockCycleId;
          if (!cycleId) {
            return {
              tasks: [],
              objects: [],
              groups: [],
            };
          }

          const [tasksRes, objectsRes, groupsRes] = await Promise.all([
            apiClient.get(`/api/tasks/cycle/${cycleId}`),
            apiClient.get(`/api/project-objects/cycle/${cycleId}`),
            apiClient.get(`/api/tasks/groups/cycle/${cycleId}`),
          ]);

          return {
            tasks: tasksRes.data?.data || [],
            objects: objectsRes.data?.data || [],
            groups: groupsRes.data?.data || [],
          };
        }));

        const allTasks = perProject.flatMap((item: any) => item.tasks);
        const objectCount = perProject.reduce((sum: number, item: any) => sum + (item.objects?.length || 0), 0);
        const taskGroupCount = perProject.reduce((sum: number, item: any) => sum + (item.groups?.length || 0), 0);
      } finally {
        setIsLoadingProgramOverview(false);
      }
    };

    loadProgramOverview();
  }, [tabValue, selectedItem, mockCycles, projectsByMockCycle]);

  // Hydrate notification navigation target from URL query params.
  useEffect(() => {
    const params = new URLSearchParams(location.search);
    const openTask = params.get('openTask');
    if (!openTask) return;

    const projectId = params.get('projectId');
    const taskName = params.get('taskName') || 'Task';

    if (projectId) {
      sessionStorage.setItem('pendingNotificationTarget', JSON.stringify({ projectId, taskId: openTask, taskName }));
      return;
    }

    // Fallback if projectId was not passed: fetch task by id to resolve owning project.
    apiClient.get(`/api/tasks/${openTask}`).then((res) => {
      const task = res.data?.data;
      if (task?.projectId) {
        sessionStorage.setItem('pendingNotificationTarget', JSON.stringify({
          projectId: task.projectId,
          taskId: openTask,
          taskName: task.name || taskName,
        }));
      }
    }).catch(() => {});
  }, [location.search]);

  useEffect(() => {
    const params = new URLSearchParams(location.search);
    if (sectionMode === 'execution' && params.get('tab') === 'my-tasks') {
      setTabValue(5);
    }
  }, [location.search, sectionMode]);

  useEffect(() => {
    if (!canAccessInventory && tabValue === 1) {
      setTabValue(0);
    }
  }, [canAccessInventory, tabValue]);

  // Ensure Priorities tab has a project context so the panel doesn't appear blank.
  useEffect(() => {
    if (tabValue !== 2 || activeProjectId) return;

    if (selectedItem?.type === 'cycle') {
      if (selectedItem.projectId) {
        setSelectedItem({ type: 'project', id: selectedItem.projectId, cycleId: selectedItem.id });
        return;
      }
      const selectedCycleProjects = projectsByMockCycle[selectedItem.id] || [];
      if (selectedCycleProjects.length > 0) {
        setSelectedItem({ type: 'project', id: selectedCycleProjects[0].id, cycleId: selectedItem.id });
        return;
      }
    }

    for (const cycleId in projectsByMockCycle) {
      const projects = projectsByMockCycle[cycleId] || [];
      if (projects.length > 0) {
        const firstProject = projects[0];
        setSelectedItem({ type: 'project', id: firstProject.id, cycleId });
        return;
      }
    }
  }, [tabValue, activeProjectId, projectsByMockCycle, selectedItem]);

  // Handle navigation from notification click: select target project.
  useEffect(() => {
    const raw = sessionStorage.getItem('pendingNotificationTarget');
    if (!raw) return;

    let target: { projectId?: string } = {};
    try { target = JSON.parse(raw); } catch { return; }
    if (!target.projectId) return;

    const selectNotificationProject = async () => {
      if (selectedItem?.type === 'project' && selectedItem.id === target.projectId) {
        setTabValue(0);
        return;
      }

      let matchedCycleId: string | null = null;
      for (const [cycleId, projects] of Object.entries(projectsByMockCycle as Record<string, any[]>)) {
        if ((projects || []).some((p: any) => p.id === target.projectId)) {
          matchedCycleId = cycleId;
          break;
        }
      }

      // Fallback: resolve cycle directly from project API if tree maps are not ready yet.
      if (!matchedCycleId) {
        try {
          const res = await apiClient.get(`/api/projects/${target.projectId}`);
          matchedCycleId = res.data?.data?.mockCycleId || null;
        } catch {
          matchedCycleId = null;
        }
      }

      if (!matchedCycleId) return;

      let matchedProgramId: string | null = null;
      for (const [programId, cycles] of Object.entries(mockCycles as Record<string, any[]>)) {
        if ((cycles || []).some((c: any) => c.id === matchedCycleId)) {
          matchedProgramId = programId;
          break;
        }
      }

      if (matchedProgramId) {
        setExpandedPrograms(prev => new Set(prev).add(matchedProgramId as string));
      }
      setExpandedCycles(prev => new Set(prev).add(matchedCycleId as string));
      setSelectedItem({ type: 'project', id: target.projectId, cycleId: matchedCycleId });
      setTabValue(0);
    };

    selectNotificationProject();
  }, [projectsByMockCycle, mockCycles, selectedItem, location.search]);

  // Once tasks load for the selected project, open the full task modal for the target task.
  useEffect(() => {
    const raw = sessionStorage.getItem('pendingNotificationTarget');
    if (!raw || !activeProjectId) return;

    let target: { projectId?: string; taskId?: string; taskName?: string } = {};
    try { target = JSON.parse(raw); } catch { return; }

    if (!target.projectId || !target.taskId || target.projectId !== activeProjectId) return;

    setEditingTaskInitialTab(0);
    setEditingTaskId(target.taskId);
    sessionStorage.removeItem('pendingNotificationTarget');
  }, [activeProjectId, projectTasks, location.search]);

  const handleCreateItem = async () => {
    const isTreeProjectSelectionMode = dialogMode === 'project' && !isPlanningMaintainTab && !treeProjectCreateByNameMode;

    if (!isTreeProjectSelectionMode && !newItemName.trim()) {
      alert('Name is required');
      return;
    }

    if (isTreeProjectSelectionMode) {
      if (!selectedExistingProjectOptionId) {
        alert('Select a maintained project option first.');
        return;
      }

      const selectedProject = treeProjectOptionsForProgram.find((project) => project.id === selectedExistingProjectOptionId) || null;
      if (!selectedProject) {
        alert('Selected project option is no longer available.');
        return;
      }

      const targetProgramId = contextProgramId || selectedProject.programId || '';
      const existingCycles = targetProgramId ? getCyclesForProjectInProgram(targetProgramId, selectedProject.id) : [];
      if (existingCycles.length > 0) {
        const firstCycle = existingCycles[0];
        setExpandedPrograms((prev) => new Set(prev).add(targetProgramId));
        setExpandedCycles((prev) => new Set(prev).add(firstCycle.id));
        setSelectedExecutionProcessArea('');
        handleHierarchySelection({ type: 'project', id: selectedProject.id, cycleId: firstCycle.id });
      } else {
        if (targetProgramId) {
          setExpandedPrograms((prev) => new Set(prev).add(targetProgramId));
        }
        setSelectedExecutionProcessArea('');
        handleHierarchySelection({ type: 'project', id: selectedProject.id });
      }

      setCreateDialogOpen(false);
      setContextProgramId(null);
      setContextCycleId(null);
      setTreeProjectCreateByNameMode(false);
      setSelectedExistingProjectOptionId('');
      return;
    }

    try {
      setIsCreating(true);
      if (dialogMode === 'program') {
        await apiClient.post('/api/programs', {
          name: newItemName,
          description: newItemDesc,
          accentColor: newItemAccentColor || null,
        });
        queryClient.invalidateQueries({ queryKey: ['programs'] });
      } else if (dialogMode === 'cycle' && contextProgramId) {
        const response = await apiClient.post(`/api/programs/${contextProgramId}/mock-cycles`, {
          name: newItemName,
          description: newItemDesc,
          testPhase: newCycleTestPhase,
          startDate: new Date().toISOString().split('T')[0],
          endDate: new Date(Date.now() + 30 * 24 * 60 * 60 * 1000).toISOString().split('T')[0],
          scheduleMode: newCycleScheduleMode,
          accentColor: newItemAccentColor || null,
          projectId: maintainPendingCycleProjectId || undefined,
        });
        const createdCycle = response?.data?.data as MockCycle | undefined;
        if (createdCycle?.id) {
          setTreeOrder((prev) => {
            const current = prev.cycles[contextProgramId] || [];
            if (current.includes(createdCycle.id)) return prev;
            return {
              ...prev,
              cycles: {
                ...prev.cycles,
                [contextProgramId]: [...current, createdCycle.id],
              },
            };
          });
          if (createdCycle.projectId) {
            setSelectedExecutionProcessArea('');
            handleHierarchySelection({ type: 'cycle', id: createdCycle.id, programId: contextProgramId, projectId: createdCycle.projectId });
            setExpandedCycles((prev) => new Set(prev).add(createdCycle.id));
          }
        }
        setExpandedPrograms((prev) => new Set(prev).add(contextProgramId));
        await Promise.all([
          queryClient.invalidateQueries({ queryKey: ['mockCycles'] }),
          queryClient.invalidateQueries({ queryKey: ['allMockCyclesForMaintain'] }),
          queryClient.invalidateQueries({ queryKey: ['projectsByMockCycle'] }),
          queryClient.refetchQueries({ queryKey: ['mockCycles'], type: 'active' }),
          queryClient.refetchQueries({ queryKey: ['allMockCyclesForMaintain'], type: 'active' }),
          queryClient.refetchQueries({ queryKey: ['projectsByMockCycle'], type: 'active' }),
        ]);
      } else if (dialogMode === 'project' && (contextProgramId || newProjectParentProgramId)) {
        const targetProgramId = newProjectParentProgramId || contextProgramId || '';
        if (!targetProgramId) {
          alert('Parent program is required.');
          return;
        }
        await apiClient.post(`/api/projects/by-program/${targetProgramId}`, {
          name: newItemName,
          startDate: new Date().toISOString().split('T')[0],
          endDate: new Date(Date.now() + 30 * 24 * 60 * 60 * 1000).toISOString().split('T')[0],
          accentColor: newItemAccentColor || null,
        });
        queryClient.invalidateQueries({ queryKey: ['projectsByProgram'] });
      }
      setNewItemName('');
      setNewItemDesc('');
      setNewItemAccentColor('');
      setNewCycleTestPhase('');
      setCreateDialogOpen(false);
      setContextProgramId(null);
      setContextCycleId(null);
      setTreeProjectCreateByNameMode(false);
      setNewProjectParentProgramId('');
      setSelectedExistingProjectOptionId('');
      setMaintainPendingCycleProjectId(null);
    } catch (error) {
      console.error('Failed to create:', error);
      alert('Failed to create. Please try again.');
    } finally {
      setIsCreating(false);
      setTreeProjectCreateByNameMode(false);
      setNewProjectParentProgramId('');
      setSelectedExistingProjectOptionId('');
      setNewCycleTestPhase('');
      setMaintainPendingCycleProjectId(null);
    }
  };

  const toggleProgramExpanded = (programId: string) => {
    const newSet = new Set(expandedPrograms);
    if (newSet.has(programId)) {
      newSet.delete(programId);
    } else {
      newSet.add(programId);
    }
    setExpandedPrograms(newSet);
    apiClient.put('/api/hierarchy-preferences/state', {
      treeOrder,
      expandedPrograms: Array.from(newSet),
      expandedCycles: Array.from(expandedCycles),
      expandedProjectGroups: Array.from(expandedProjectGroups),
      expandedObjects: Array.from(expandedObjects),
      planningAdditionalGroups,
      planningAdditionalProcessAreas,
      hiddenProcessAreas,
      processAreaAccentOverrides,
      processAreaDescriptions,
      hierarchyLevelIcons,
    }).catch(() => {});
  };

  const toggleCycleExpanded = (cycleId: string) => {
    const newSet = new Set(expandedCycles);
    if (newSet.has(cycleId)) {
      newSet.delete(cycleId);
    } else {
      newSet.add(cycleId);
    }
    setExpandedCycles(newSet);
    apiClient.put('/api/hierarchy-preferences/state', {
      treeOrder,
      expandedPrograms: Array.from(expandedPrograms),
      expandedCycles: Array.from(newSet),
      expandedProjectGroups: Array.from(expandedProjectGroups),
      expandedObjects: Array.from(expandedObjects),
      planningAdditionalGroups,
      planningAdditionalProcessAreas,
      hiddenProcessAreas,
      processAreaAccentOverrides,
      processAreaDescriptions,
      hierarchyLevelIcons,
    }).catch(() => {});
  };

  const toggleProjectGroupExpanded = (projectGroupKey: string) => {
    const next = new Set(expandedProjectGroups);
    if (next.has(projectGroupKey)) {
      next.delete(projectGroupKey);
    } else {
      next.add(projectGroupKey);
    }
    setExpandedProjectGroups(next);
    apiClient.put('/api/hierarchy-preferences/state', {
      treeOrder,
      expandedPrograms: Array.from(expandedPrograms),
      expandedCycles: Array.from(expandedCycles),
      expandedProjectGroups: Array.from(next),
      expandedObjects: Array.from(expandedObjects),
      planningAdditionalGroups,
      planningAdditionalProcessAreas,
      hiddenProcessAreas,
      processAreaAccentOverrides,
      processAreaDescriptions,
      hierarchyLevelIcons,
    }).catch(() => {});
  };

  const openCreateDialog = (mode: 'program' | 'cycle' | 'project', programId?: string, cycleId?: string) => {
    setTreeProjectCreateByNameMode(false);
    setDialogMode(mode);
    setContextProgramId(programId || null);
    setContextCycleId(cycleId || null);
    setNewItemName('');
    setNewItemDesc('');
    setNewItemAccentColor('');
    setNewCycleTestPhase('');
    setNewProjectParentProgramId(
      mode === 'project'
        ? (programId || maintainProjectParentProgramId || programs[0]?.id || '')
        : ''
    );
    setSelectedExistingProjectOptionId('');
    setNewCycleScheduleMode('all_days');
    if (mode === 'cycle') {
      const defaultParentProjectId = maintainCycleParentProjectId || maintainCycleParentProjectOptions[0]?.id || null;
      setMaintainPendingCycleProjectId(defaultParentProjectId);
    }
    setCreateDialogOpen(true);
  };

  const openProjectNameCreateDialog = (programId: string) => {
    setTreeProjectCreateByNameMode(true);
    setDialogMode('project');
    setContextProgramId(programId);
    setContextCycleId(null);
    setNewProjectParentProgramId(programId);
    setSelectedExistingProjectOptionId('');
    setNewItemName('');
    setNewItemDesc('');
    setNewItemAccentColor('');
    setCreateDialogOpen(true);
  };

  const openAttachCycleDialog = (programId: string) => {
    const attachableCycles = getAttachableCyclesForProgram(programId);
    if (attachableCycles.length === 0) {
      alert('No maintained mock cycles are available to add for this program.');
      return;
    }
    setAttachCycleProgramId(programId);
    setAttachCycleId(attachableCycles[0].id);
    setAttachCycleDialogOpen(true);
  };

  const handleAttachCycleConfirm = async () => {
    if (!attachCycleProgramId || !attachCycleId) return;

    const cycle = (mockCycles[attachCycleProgramId] || []).find((entry: MockCycle) => entry.id === attachCycleId) || null;
    if (!cycle) {
      alert('Selected mock cycle is no longer available.');
      return;
    }

    const nextTreeOrder = {
      ...treeOrder,
      cycles: {
        ...treeOrder.cycles,
        [attachCycleProgramId]: mergeOrder(treeOrder.cycles[attachCycleProgramId] || [], [attachCycleId]),
      },
    };

    setTreeOrder(nextTreeOrder);
    await apiClient.put('/api/hierarchy-preferences/state', {
      treeOrder: nextTreeOrder,
      planningAdditionalGroups,
      planningAdditionalProcessAreas,
      hiddenProcessAreas,
      processAreaAccentOverrides,
      processAreaDescriptions,
      hierarchyLevelIcons,
    }).catch(() => {
      // The debounced saver will retry; this is just to avoid refresh races.
    });
    setExpandedPrograms((prev) => new Set(prev).add(attachCycleProgramId));
    setExpandedCycles((prev) => new Set(prev).add(attachCycleId));
    setSelectedItem({ type: 'cycle', id: attachCycleId, programId: attachCycleProgramId, projectId: cycle.projectId });
    setTabValue(0);

    setAttachCycleDialogOpen(false);
    setAttachCycleProgramId(null);
    setAttachCycleId('');
  };

  const getChildrenCount = (type: 'program' | 'cycle' | 'project', itemId: string): number => {
    if (type === 'program') {
      return mockCycles[itemId]?.length ?? 0;
    } else if (type === 'cycle') {
      return projectsByMockCycle[itemId]?.length ?? 0;
    } else if (type === 'project') {
      return Object.values(mockCycles)
        .flat()
        .filter((cycle: any) => cycle?.projectId === itemId).length;
    }
    return 0;
  };

  const getTotalDescendants = (type: 'program' | 'cycle' | 'project', itemId: string): { cycles: number; projects: number } => {
    let cycles = 0;
    let projects = 0;
    
    if (type === 'program') {
      const cycleList = mockCycles[itemId] ?? [];
      cycles = cycleList.length;
      cycleList.forEach(cycle => {
        projects += projectsByMockCycle[cycle.id]?.length ?? 0;
      });
    } else if (type === 'cycle') {
      projects = projectsByMockCycle[itemId]?.length ?? 0;
    }
    
    return { cycles, projects };
  };

  const openDeleteDialog = (type: 'program' | 'cycle' | 'project' | 'task' | 'taskGroup', itemId: string, itemName: string) => {
    let childrenCount = 0;
    if (type === 'program' || type === 'cycle' || type === 'project') {
      childrenCount = getChildrenCount(type, itemId);
    }
    
    setDeleteItemType(type);
    setDeleteItemId(itemId);
    setDeleteItemName(itemName);
    setDeleteChildrenCount(childrenCount);
    setDeleteDialogOpen(true);
    setMenuAnchorEl(null);
  };

  const handleDeleteConfirm = async () => {
    if (!deleteItemId || !deleteItemType) return;

    try {
      setIsDeleting(true);
      const deletedItemId = deleteItemId;
      const deletedItemType = deleteItemType;
      if (deleteItemType === 'program') {
        await apiClient.delete(`/api/programs/${deleteItemId}`);
      } else if (deleteItemType === 'cycle') {
        await apiClient.delete(`/api/mock-cycles/${deleteItemId}`);
      } else if (deleteItemType === 'project') {
        await apiClient.delete(`/api/projects/${deleteItemId}?cascade=true`);
      } else if (deleteItemType === 'task') {
        // Remove object from plan: delete its tasks (and sub-object tasks) for this cycle.
        // The inventory item itself is kept so the object can be re-added to the plan later.
        const objectIdsToRemove = getObjectAndDescendantIds(deleteItemId);
        const tasksForObjects = projectTasks.filter((task) => task.projectObjectId && objectIdsToRemove.has(task.projectObjectId));
        await Promise.all(tasksForObjects.map((task) => apiClient.delete(`/api/tasks/${task.id}`)));
        setProjectTasks((prev) => prev.filter((task) => !(task.projectObjectId && objectIdsToRemove.has(task.projectObjectId))));
        // Clear the seeded-tasks ref so the object can be re-added with fresh defaults
        objectIdsToRemove.forEach(id => seededDefaultTaskObjectsRef.current.delete(id));
        setProjectInventoryTaskObjectIds((prev: string[]) => prev.filter(id => !objectIdsToRemove.has(id)));
      } else if ((deleteItemType as any) === 'taskSingle') {
        // Delete a single task row
        await apiClient.delete(`/api/tasks/${deleteItemId}`);
        setProjectTasks(prev => prev.filter(t => t.id !== deleteItemId));
      } else if (deleteItemType === 'taskGroup') {
        await apiClient.delete(`/api/tasks/groups/${deleteItemId}`);
        setDeliverableTaskGroupAssignments((prev) => {
          let changed = false;
          const next = Object.fromEntries(
            Object.entries(prev).map(([projectId, assignments]) => {
              if (!assignments?.[deleteItemId]) return [projectId, assignments];
              changed = true;
              const nextAssignments = { ...assignments };
              delete nextAssignments[deleteItemId];
              return [projectId, nextAssignments];
            })
          );
          return changed ? next : prev;
        });
      }
      
      // Refresh hierarchy queries immediately so deleted items disappear without stale selection errors.
      await Promise.all([
        queryClient.invalidateQueries({ queryKey: ['programs'] }),
        queryClient.invalidateQueries({ queryKey: ['mockCycles'] }),
        queryClient.invalidateQueries({ queryKey: ['allMockCyclesForMaintain'] }),
        queryClient.invalidateQueries({ queryKey: ['projectsByMockCycle'] }),
        queryClient.invalidateQueries({ queryKey: ['projectsByProgram'] }),
      ]);

      await Promise.all([
        queryClient.refetchQueries({ queryKey: ['programs'], type: 'active' }),
        queryClient.refetchQueries({ queryKey: ['mockCycles'], type: 'active' }),
        queryClient.refetchQueries({ queryKey: ['allMockCyclesForMaintain'], type: 'active' }),
        queryClient.refetchQueries({ queryKey: ['projectsByMockCycle'], type: 'active' }),
        queryClient.refetchQueries({ queryKey: ['projectsByProgram'], type: 'active' }),
      ]);
      
      // Reload tasks if we deleted a task or task group
      if ((activeCycleId || activeProjectId) && (deleteItemType === 'task' || deleteItemType === 'taskGroup')) {
        const reloadTs = Date.now();
        const taskUrl = activeCycleId ? `/api/tasks/cycle/${activeCycleId}` : `/api/tasks/project/${activeProjectId}`;
        const groupUrl = activeCycleId ? `/api/tasks/groups/cycle/${activeCycleId}` : `/api/tasks/groups/project/${activeProjectId}`;
        const [tasksRes, groupsRes] = await Promise.all([
          apiClient.get(taskUrl),
          apiClient.get(groupUrl),
        ]);
        const reloadedTasks = (tasksRes.data.data || []).map((task: any) => normalizeTaskDateFields(task));
        setProjectTasks(reloadedTasks);
        setProjectTaskGroups(groupsRes.data.data || []);
        // Reload deps for all remaining tasks so stale dep state is cleared
        const freshDepsMap: Record<string, any[]> = {};
        await Promise.all(reloadedTasks.map(async (task: any) => {
          try {
            const dr = await apiClient.get(`/api/tasks/${task.id}/dependencies?t=${reloadTs}`);
            freshDepsMap[task.id] = dr.data.data || [];
          } catch { freshDepsMap[task.id] = []; }
        }));
        setTaskDeps(freshDepsMap);
      }
      
      // Clear selection if it now points to a deleted hierarchy node or its deleted parent.
      const shouldClearSelection = (() => {
        if (!selectedItem) return false;
        if ('id' in selectedItem && selectedItem.id === deletedItemId) return true;

        if (deletedItemType === 'program') {
          return (
            (selectedItem as any).programId === deletedItemId ||
            ((selectedItem.type === 'cycle' || selectedItem.type === 'project' || selectedItem.type === 'processArea') &&
              (selectedItem as any).programId === deletedItemId)
          );
        }

        if (deletedItemType === 'cycle') {
          return (
            (selectedItem as any).cycleId === deletedItemId ||
            (selectedItem.type === 'cycle' && selectedItem.id === deletedItemId)
          );
        }

        if (deletedItemType === 'project') {
          return (
            (selectedItem.type === 'project' && selectedItem.id === deletedItemId) ||
            (selectedItem.type === 'processArea' && selectedItem.projectId === deletedItemId)
          );
        }

        return false;
      })();

      if (shouldClearSelection) {
        setSelectedItem(null);
      }
      
      setDeleteDialogOpen(false);
    } catch (error: any) {
      console.error('Failed to delete:', error);
      const rawMessage = String(
        error?.response?.data?.error
        || error?.response?.data?.message
        || error?.message
        || ''
      ).trim();
      let msg = rawMessage || String(error?.response?.status || 'Unknown error');

      if (error?.response?.status === 409) {
        if (/Cannot delete project with existing mock cycles/i.test(rawMessage)) {
          msg = 'Cannot delete project because it is linked to one or more mock cycles. Reassign or delete those mock cycles first.';
        } else if (/Cannot delete project with existing project objects/i.test(rawMessage)) {
          msg = 'Cannot delete project because it still has inventory objects. Remove those objects first.';
        } else if (/Cannot delete project with existing task groups/i.test(rawMessage)) {
          msg = 'Cannot delete project because it still has task groups. Remove task groups first.';
        } else if (/Cannot delete project with existing tasks/i.test(rawMessage)) {
          msg = 'Cannot delete project because it still has tasks. Remove tasks first.';
        }
      }

      alert(`Failed to delete: ${msg}`);
    } finally {
      setIsDeleting(false);
    }
  };

  const openEditDialog = (type: 'program' | 'cycle' | 'project', itemId: string) => {
    setEditItemType(type);
    setEditItemId(itemId);
    setMenuAnchorEl(null);

    // Pre-fill form with current data
    if (type === 'program') {
      const program = programs.find(p => p.id === itemId);
      if (program) {
        setEditItemName(program.name);
        setEditItemDesc(program.description || '');
        setEditStartDate('');
        setEditEndDate('');
        setEditAccentColor(program.accentColor || '');
      }
    } else if (type === 'cycle') {
      setCycleEntryCriteriaDraft(MOCK_CYCLE_ENTRY_CRITERIA_DEFAULTS.map((item) => ({ ...item })));
      setCycleExitCriteriaDraft(MOCK_CYCLE_EXIT_CRITERIA_DEFAULTS.map((item) => ({ ...item })));
      setMaintainSelectedCycleId(itemId);
      const linkedCycle = allMaintainCycles.find((cycle) => cycle.id === itemId) || null;
      const linkedProject = allMaintainProjects.find((project) => project.id === linkedCycle?.projectId) || null;
      setEditCycleParentProjectId(linkedProject?.id || maintainCycleParentProjectOptions[0]?.id || '');
      setEditItemName(linkedCycle?.name || '');
      setEditItemDesc(linkedCycle?.description || '');
      setEditStartDate(linkedCycle?.startDate || '');
      setEditEndDate(linkedCycle?.endDate || '');
      setEditCycleScheduleMode((linkedCycle?.scheduleMode || 'all_days') as CalendarMode);
      setEditCycleTestPhase(linkedCycle?.testPhase || '');
      setEditAccentColor(linkedCycle?.accentColor || '');

      setCycleEntryCriteriaDraft(normalizeCriteriaDraft(linkedCycle?.entryCriteriaItems, MOCK_CYCLE_ENTRY_CRITERIA_DEFAULTS));
      setCycleExitCriteriaDraft(normalizeCriteriaDraft(linkedCycle?.exitCriteriaItems, MOCK_CYCLE_EXIT_CRITERIA_DEFAULTS));
      setCycleWorkflowEvaluation(null);

      if (linkedCycle?.projectId) {
        apiClient.get(`/api/projects/${linkedCycle.projectId}/workflow-roles`)
          .then((response) => {
            const payload = response.data?.data || {};
            setProjectLeadUserIdDraft(payload.leadUserId || '');
            setProjectManagerUserIdDraft(payload.projectManagerUserId || '');
          })
          .catch(() => {
            setProjectLeadUserIdDraft('');
            setProjectManagerUserIdDraft('');
          });
      } else {
        setProjectLeadUserIdDraft('');
        setProjectManagerUserIdDraft('');
      }

      apiClient.get(`/api/mock-cycles/${itemId}/workflow-status`)
        .then((response) => {
          setCycleWorkflowEvaluation(response.data?.data || null);
        })
        .catch(() => {
          setCycleWorkflowEvaluation(null);
        });
    } else if (type === 'project') {
      const project = allMaintainProjects.find((p) => p.id === itemId) || null;
      if (project) {
        setEditItemName(project.name);
        setEditItemDesc('');
        setEditStartDate(project.startDate || '');
        setEditEndDate(project.endDate || '');
        setEditAccentColor(project.accentColor || '');
        setEditProjectParentProgramId(project.programId || '');
      }
      setProjectLeadUserIdDraft('');
      setProjectManagerUserIdDraft('');
      apiClient.get(`/api/projects/${itemId}/workflow-roles`)
        .then((res) => {
          const payload = res.data?.data || {};
          setProjectLeadUserIdDraft(payload.leadUserId || '');
          setProjectManagerUserIdDraft(payload.projectManagerUserId || '');
        })
        .catch(() => {});
    }

    setEditDialogOpen(true);
  };

  useEffect(() => {
    if (!editDialogOpen || editItemType !== 'cycle') return;

    if (!Array.isArray(cycleEntryCriteriaDraft) || cycleEntryCriteriaDraft.length === 0) {
      setCycleEntryCriteriaDraft(MOCK_CYCLE_ENTRY_CRITERIA_DEFAULTS.map((item) => ({ ...item })));
    }

    if (!Array.isArray(cycleExitCriteriaDraft) || cycleExitCriteriaDraft.length === 0) {
      setCycleExitCriteriaDraft(MOCK_CYCLE_EXIT_CRITERIA_DEFAULTS.map((item) => ({ ...item })));
    }
  }, [editDialogOpen, editItemType, cycleEntryCriteriaDraft, cycleExitCriteriaDraft]);

  const handleEditConfirm = async () => {
    if (!editItemId || !editItemType) return;

    try {
      setIsEditing(true);
      if (editItemType === 'program') {
        await apiClient.patch(`/api/programs/${editItemId}`, {
          name: editItemName,
          description: editItemDesc,
          accentColor: editAccentColor || null,
        });
      } else if (editItemType === 'cycle') {
        if (!editCycleParentProjectId) {
          alert('A parent project is required for mock cycles.');
          return;
        }

        await apiClient.patch(`/api/mock-cycles/${editItemId}`, {
          name: editItemName,
          description: editItemDesc,
          testPhase: editCycleTestPhase,
          scheduleMode: editCycleScheduleMode,
          accentColor: editAccentColor || null,
        });
        await apiClient.patch(`/api/projects/${editCycleParentProjectId}`, { mockCycleId: editItemId });
      } else if (editItemType === 'project') {
        const leadUserId = workflowUserIdSet.has(projectLeadUserIdDraft) ? projectLeadUserIdDraft : null;
        const projectManagerUserId = workflowUserIdSet.has(projectManagerUserIdDraft) ? projectManagerUserIdDraft : null;
        await apiClient.patch(`/api/projects/${editItemId}`, {
          name: editItemName,
          accentColor: editAccentColor,
          programId: editProjectParentProgramId,
        });
        await apiClient.put(`/api/projects/${editItemId}/workflow-roles`, {
          leadUserId,
          projectManagerUserId,
        });
      }

      // Refresh all hierarchy data sources used by maintain + tree views.
      await Promise.all([
        queryClient.invalidateQueries({ queryKey: ['programs'] }),
        queryClient.invalidateQueries({ queryKey: ['mockCycles'] }),
        queryClient.invalidateQueries({ queryKey: ['allMockCyclesForMaintain'] }),
        queryClient.invalidateQueries({ queryKey: ['projectsByMockCycle'] }),
        queryClient.invalidateQueries({ queryKey: ['projectsByProgram'] }),
      ]);

      await Promise.all([
        queryClient.refetchQueries({ queryKey: ['mockCycles'], type: 'active' }),
        queryClient.refetchQueries({ queryKey: ['allMockCyclesForMaintain'], type: 'active' }),
        queryClient.refetchQueries({ queryKey: ['projectsByMockCycle'], type: 'active' }),
        queryClient.refetchQueries({ queryKey: ['projectsByProgram'], type: 'active' }),
      ]);

      setEditDialogOpen(false);
    } catch (error) {
      console.error('Failed to update:', error);
      alert('Failed to update. Please try again.');
    } finally {
      setIsEditing(false);
    }
  };

  const handleCloneCycle = (cycleId: string) => {
    const sourceCycle = allMaintainCycles.find((cycle) => cycle.id === cycleId) || null;

    if (!sourceCycle) {
      alert('Unable to locate source mock cycle.');
      return;
    }

    if (allMaintainCycles.length < 2) {
      alert('At least two mock cycles must exist in Maintain to copy between cycles.');
      return;
    }

    // The right-clicked cycle is the SOURCE (Copy From).
    // Pre-select the first other available cycle as the destination.
    const defaultTarget = maintainCycleRows.find((cycle: any) => cycle.id !== cycleId) || null;

    setCloneCycleSourceId(cycleId);
    setCloneCycleTargetId(defaultTarget?.id || null);
    setCloneCycleDialogOpen(true);
  };

  const handleCloneCycleConfirm = async () => {
    if (!cloneCycleSourceId || !cloneCycleTargetId) return;

    const selectedSourceCycle = allMaintainCycles.find((cycle) => cycle.id === cloneCycleSourceId) || null;
    const selectedTargetCycle = allMaintainCycles.find((cycle) => cycle.id === cloneCycleTargetId) || null;
    if (!selectedSourceCycle) {
      alert('Select a valid mock cycle from Maintain to copy.');
      return;
    }
    if (!selectedTargetCycle) {
      alert('Select a valid destination mock cycle from Maintain.');
      return;
    }
    if (selectedSourceCycle.id === selectedTargetCycle.id) {
      alert('Source and destination mock cycles must be different.');
      return;
    }

    try {
      setIsCloningCycle(true);
      const res = await apiClient.post(`/api/mock-cycles/${cloneCycleSourceId}/copy-to`, {
        targetMockCycleId: cloneCycleTargetId,
      });
      const copiedToCycle = res?.data?.data;

      queryClient.invalidateQueries({ queryKey: ['mockCycles'] });
      queryClient.invalidateQueries({ queryKey: ['projectsByMockCycle'] });
      queryClient.invalidateQueries({ queryKey: ['projectsByProgram'] });
      queryClient.invalidateQueries({ queryKey: ['allMockCyclesForMaintain'] });

      setExpandedPrograms(prev => new Set(prev).add(selectedTargetCycle.programId));
      if (copiedToCycle?.id) {
        // Add target cycle to treeOrder so it appears in the hierarchy.
        setTreeOrder(prev => {
          const existing = prev.cycles[selectedTargetCycle.programId] || [];
          if (existing.includes(copiedToCycle.id)) return prev;
          return {
            ...prev,
            cycles: {
              ...prev.cycles,
              [selectedTargetCycle.programId]: [...existing, copiedToCycle.id],
            },
          };
        });
        // Copy ALL local hierarchy state from source to target cycle.
        const sourceKey = cloneCycleSourceId as string;
        const targetKey = copiedToCycle.id as string;

        setPlanningAdditionalGroups(prev => ({
          ...prev,
          [targetKey]: [...(prev[sourceKey] || [])],
        }));
        setPlanningAdditionalProcessAreas(prev => ({
          ...prev,
          [targetKey]: [...(prev[sourceKey] || [])],
        }));
        setTreeOrder(prev => ({
          ...prev,
          processAreas: {
            ...prev.processAreas,
            [targetKey]: [...(prev.processAreas[sourceKey] || [])],
          },
        }));
        setHiddenProcessAreas(prev => ({
          ...prev,
          [targetKey]: [...(prev[sourceKey] || [])],
        }));
        // Copy accent colours so the visual style matches the source.
        setProcessAreaAccentOverrides(prev => ({
          ...prev,
          [targetKey]: { ...(prev[sourceKey] || {}) },
        }));
        setProcessAreaIconOverrides(prev => ({
          ...prev,
          [targetKey]: { ...(prev[sourceKey] || {}) },
        }));
        setExpandedCycles(prev => new Set(prev).add(copiedToCycle.id));
        setSelectedItem({ type: 'cycle', id: copiedToCycle.id, programId: selectedTargetCycle.programId, projectId: copiedToCycle.projectId });
      }
      setTabValue(0);
      setCloneCycleDialogOpen(false);
      setCloneCycleSourceId(null);
      setCloneCycleTargetId(null);
    } catch (error) {
      console.error('Failed to copy mock cycle to destination:', error);
      alert('Failed to copy mock cycle. Please try again.');
    } finally {
      setIsCloningCycle(false);
    }
  };

  // Handle edit catalog object
  const handleEditCatalogObject = (obj: any) => {
    setEditingCatalogObjectId(obj.id);
    setCatalogObjectId(obj.objectId);
    setCatalogObjectDesc(obj.description);
    setCatalogProcessArea(obj.processArea || '');
    setCatalogObjectDialogOpen(true);
  };

  // Handle delete catalog object
  const handleDeleteCatalogObject = (obj: any) => {
    setDeletingCatalogObjectId(obj.id);
    setDeletingCatalogObjectName(obj.objectId);
  };

  const handleCatalogProcessAreaChange = async (objectId: string, processArea: string) => {
    try {
      await apiClient.patch(`/api/global-objects/${objectId}`, {
        processArea,
      });
      setInventoryObjects((prev: any[]) => prev.map((obj: any) => (
        obj.id === objectId
          ? { ...obj, processArea }
          : obj
      )));
    } catch (error) {
      console.error('Failed to update catalog process area:', error);
      alert('Failed to update process area. Please try again.');
    }
  };

  const handleOpenAddToInv = async (obj: any) => {
    setAddToInvObj(obj);
    setAddToInvProjectId(selectedProjectForInventory || inventoryProjectsForSelectedProgram[0]?.id || '');
    setAddToInvSubObjects([]);
    setAddToInvSelectedSubs(new Set());
    setAddToInvOpen(true);
    setAddToInvLoading(true);
    try {
      const ddRes = await apiClient.get(`/api/applications/data-definitions/object/${obj.id}`);
      const defs: any[] = ddRes.data.data || [];
      const seenNames = new Set<string>();
      const allSubs: {name: string; description: string}[] = [];
      await Promise.all(defs.map(async (dd: any) => {
        const soRes = await apiClient.get(`/api/applications/data-definitions/${dd.id}/sub-objects`).catch(() => ({ data: { data: [] } }));
        for (const so of (soRes.data.data || [])) {
          if (!seenNames.has(so.name)) {
            seenNames.add(so.name);
            allSubs.push({ name: so.name, description: so.description || '' });
          }
        }
      }));
      setAddToInvSubObjects(allSubs);
      setAddToInvSelectedSubs(new Set(allSubs.map(s => s.name)));
    } catch (_e) {
      // proceed with no sub-objects
    } finally {
      setAddToInvLoading(false);
    }
  };

  const confirmAddToInv = async () => {
    if (!addToInvObj || !addToInvProjectId) return;
    setIsAddingToInv(true);
    try {
      const ddRes = await apiClient.get(`/api/applications/data-definitions/object/${addToInvObj.id}`);
      const defs: any[] = ddRes.data.data || [];
      const defaultApplicationId = defs[0]?.application_id || null;
      const res = await apiClient.post(`/api/project-objects/project/${addToInvProjectId}`, {
        globalObjectId: addToInvObj.id,
        targetApplicationId: defaultApplicationId,
        sourceApplicationId: defaultApplicationId,
        processArea: addToInvObj.processArea || null,
      });
      const parent = res.data.data;
      const parentItem: any = {
        id: parent.id, projectId: parent.projectId,
        dataObjectId: parent.objectId, objectId: parent.objectId,
        globalObjectId: parent.globalObjectId,
        parentProjectObjectId: '', isSubObject: false,
        targetApplicationId: parent.targetApplicationId || defaultApplicationId || '',
        targetApplicationName: parent.targetApplicationName || defs[0]?.application_name || '',
        sourceApplicationId: parent.sourceApplicationId || defaultApplicationId || '',
        sourceApplicationName: parent.sourceApplicationName || defs[0]?.application_name || '',
        processArea: parent.processArea,
        complexity: null, deploymentDisposition: null, buildType: null,
        objectType: null, cutoverPhase: null, ddmApproach: null,
        riskSecurityType: null, migrationType: null, factorType: null, loadMethod: null,
        startDate: null, endDate: null, subObjectSuffix: '', subObjectDescription: '',
      };
      const newItems: any[] = [parentItem];
      const selectedSubs = addToInvSubObjects.filter(s => addToInvSelectedSubs.has(s.name));
      for (const so of selectedSubs) {
        const subRes = await apiClient.post(`/api/project-objects/project/${addToInvProjectId}`, {
          parentProjectObjectId: parent.id,
          targetApplicationId: defaultApplicationId,
          sourceApplicationId: defaultApplicationId,
          subObjectSuffix: so.name,
          subObjectDescription: so.description || so.name,
        });
        const sub = subRes.data.data;
        const derivedSubObjectId = sub.objectId || `${parent.objectId}-${so.name}`;
        newItems.push({
          id: sub.id, projectId: sub.projectId,
          dataObjectId: derivedSubObjectId, objectId: derivedSubObjectId,
          globalObjectId: sub.globalObjectId,
          parentProjectObjectId: parent.id,
          isSubObject: true,
          targetApplicationId: sub.targetApplicationId || defaultApplicationId || '',
          targetApplicationName: sub.targetApplicationName || defs[0]?.application_name || '',
          sourceApplicationId: sub.sourceApplicationId || defaultApplicationId || '',
          sourceApplicationName: sub.sourceApplicationName || defs[0]?.application_name || '',
          subObjectSuffix: sub.subObjectSuffix || so.name,
          subObjectDescription: sub.subObjectDescription || so.description,
          processArea: sub.processArea,
          complexity: null, deploymentDisposition: null, buildType: null,
          objectType: null, cutoverPhase: null, ddmApproach: null,
          riskSecurityType: null, migrationType: null, factorType: null, loadMethod: null,
          startDate: null, endDate: null,
        });
      }
      setProjectInventoryItems(prev => [...prev, ...newItems]);
      setSelectedProjectForInventory(addToInvProjectId);
      setInventorySubTab(1);
      setAddToInvOpen(false);
      // Navigate to the inventory page so the user sees the added item
      if (sectionMode === 'planning') navigate('/planning/inventory');
    } catch (e: any) {
      alert(e?.response?.data?.message || 'Failed to add to inventory');
    } finally {
      setIsAddingToInv(false);
    }
  };

  // Confirm delete catalog object
  const confirmDeleteCatalogObject = async () => {
    if (!deletingCatalogObjectId) return;
    
    try {
      setIsDeletingCatalogObject(true);
      await apiClient.delete(`/api/global-objects/${deletingCatalogObjectId}`);
      setInventoryObjects(inventoryObjects.filter(obj => obj.id !== deletingCatalogObjectId));
      setDeletingCatalogObjectId(null);
      alert('Object deleted successfully');
    } catch (error) {
      console.error('Failed to delete:', error);
      alert('Failed to delete object. Please try again.');
    } finally {
      setIsDeletingCatalogObject(false);
    }
  };

  // Get filtered and sorted catalog objects
  const getFilteredSortedCatalogObjects = () => {
    let filtered = inventoryObjects.filter(obj =>
      obj.objectId.toLowerCase().includes(catalogSearchTerm.toLowerCase()) ||
      obj.description.toLowerCase().includes(catalogSearchTerm.toLowerCase())
    );

    filtered.sort((a, b) => {
      const aVal = a[catalogSortColumn]?.toLowerCase() || '';
      const bVal = b[catalogSortColumn]?.toLowerCase() || '';
      return catalogSortDirection === 'asc' ? aVal.localeCompare(bVal) : bVal.localeCompare(aVal);
    });

    return filtered;
  };

  // Get filtered and sorted inventory items
  const getFilteredSortedInventoryItems = () => {
    let filtered = projectInventoryItems.filter(item =>
      item.dataObjectId?.toLowerCase().includes(inventorySearchTerm.toLowerCase()) ||
      item.processArea?.toLowerCase().includes(inventorySearchTerm.toLowerCase()) ||
      item.complexity?.toLowerCase().includes(inventorySearchTerm.toLowerCase()) ||
      item.subObjectDescription?.toLowerCase().includes(inventorySearchTerm.toLowerCase())
    );

    const byId = new Map(filtered.map((item: any) => [item.id, item]));
    const getRootItem = (item: any) => {
      if (!item?.parentProjectObjectId) return item;
      return byId.get(item.parentProjectObjectId) || projectInventoryItems.find((entry: any) => entry.id === item.parentProjectObjectId) || item;
    };

    filtered.sort((a, b) => {
      const rootA = getRootItem(a);
      const rootB = getRootItem(b);
      const rootNameA = ((rootA?.dataObjectId || rootA?.objectId || '') as string).toLowerCase();
      const rootNameB = ((rootB?.dataObjectId || rootB?.objectId || '') as string).toLowerCase();
      if (rootNameA !== rootNameB) {
        return rootNameA.localeCompare(rootNameB);
      }

      const aIsSub = !!a.parentProjectObjectId;
      const bIsSub = !!b.parentProjectObjectId;
      if (aIsSub !== bIsSub) return aIsSub ? 1 : -1;

      if (aIsSub && bIsSub) {
        const aSuffix = (a.subObjectSuffix || '').toString().toLowerCase();
        const bSuffix = (b.subObjectSuffix || '').toString().toLowerCase();
        if (aSuffix !== bSuffix) return aSuffix.localeCompare(bSuffix);
      }

      const aVal = (a[inventorySortColumn] || '')?.toString().toLowerCase();
      const bVal = (b[inventorySortColumn] || '')?.toString().toLowerCase();
      return inventorySortDirection === 'asc' ? aVal.localeCompare(bVal) : bVal.localeCompare(aVal);
    });

    return filtered;
  };

  const getParentInventoryObjects = () => {
    return projectInventoryItems
      .filter((item: any) => !item.parentProjectObjectId)
      .sort((a: any, b: any) => (a.objectId || '').localeCompare(b.objectId || ''));
  };

  const getSubObjectsForParent = (parentId: string) => {
    return projectInventoryItems
      .filter((item: any) => item.parentProjectObjectId === parentId)
      .sort((a: any, b: any) => (a.subObjectSuffix || '').localeCompare(b.subObjectSuffix || ''));
  };

  const getObjectAndDescendantIds = (rootObjectId: string) => {
    const ids = new Set<string>();
    const queue: string[] = [rootObjectId];

    while (queue.length > 0) {
      const currentId = queue.shift();
      if (!currentId || ids.has(currentId)) continue;
      ids.add(currentId);

      projectInventoryItems.forEach((item: any) => {
        if (item.parentProjectObjectId === currentId && !ids.has(item.id)) {
          queue.push(item.id);
        }
      });
    }

    return ids;
  };

  // Handle edit inventory item
  const handleEditInventoryItem = (item: any) => {
    setInventoryDialogProcessAreaFilter('');
    const baseCatalogObject = inventoryObjects.find(obj => obj.id === item.globalObjectId) || null;
    const baseObjectId = baseCatalogObject?.objectId || item.parentObjectId || item.dataObjectId || item.objectId || '';

    setEditingInventoryItemId(item.id);
    setProjectInventoryItem({
      dataObjectId: baseObjectId,
      parentProjectObjectId: item.parentProjectObjectId || '',
      subObjectSuffix: item.subObjectSuffix || '',
      subObjectDescription: item.subObjectDescription || '',
      isSubObject: !!item.parentProjectObjectId,
      processArea: item.processArea || '',
      targetApplicationId: item.targetApplicationId || '',
      sourceApplicationId: item.sourceApplicationId || '',
      complexity: item.complexity || '',
      deploymentDisposition: item.deploymentDisposition || '',
      buildType: item.buildType || '',
      objectType: item.objectType || '',
      dra: item.dra || '',
      developer: item.developer || '',
      systemsAnalyst: item.systemsAnalyst || '',
      cutoverPhase: item.cutoverPhase || '',
      ddmApproach: item.ddmApproach || '',
      riskSecurityType: item.riskSecurityType || '',
      migrationType: item.migrationType || '',
      factorType: item.factorType || '',
      loadMethod: item.loadMethod || '',
    });
    setInvDialogAppId('');
    setInvDialogSourceAppId('');
    setInvDialogAppOptions([]);
    setInvDialogSubObjects([]);
    setInvDialogSubLoading(true);

    const objectId = baseObjectId;
    const targetApplicationId = item.targetApplicationId || '';
    const sourceApplicationId = item.sourceApplicationId || '';
    const globalObj = baseCatalogObject || inventoryObjects.find(obj => obj.objectId === objectId);

    if (!objectId || !globalObj) {
      setInvDialogSubLoading(false);
      setProjectInventoryDialogOpen(true);
      return;
    }

    apiClient.get(`/api/applications/data-definitions/object/${globalObj.id}`)
      .then(async (ddRes) => {
        const defs: any[] = ddRes.data.data || [];
        const options = defs.map((d: any) => ({ id: d.id, name: d.application_name, applicationId: d.application_id }));
        setInvDialogAppOptions(options);

        if (targetApplicationId) {
          const matched = options.find((opt: any) => opt.applicationId === targetApplicationId);
          if (matched) {
            setInvDialogAppId(matched.id);
            const soRes = await apiClient.get(`/api/applications/data-definitions/${matched.id}/sub-objects`).catch(() => ({ data: { data: [] } }));
            setInvDialogSubObjects(soRes.data.data || []);
          }
        }

        if (sourceApplicationId) {
          const matchedSource = options.find((opt: any) => opt.applicationId === sourceApplicationId);
          if (matchedSource) {
            setInvDialogSourceAppId(matchedSource.id);
          }
        }

        if (targetApplicationId) {
          const matched = options.find((opt: any) => opt.applicationId === targetApplicationId);
          if (matched) {
            return;
          }
        }

        const seenNames = new Set<string>();
        const allSubs: {name: string; description: string}[] = [];
        await Promise.all(defs.map(async (dd: any) => {
          const soRes = await apiClient.get(`/api/applications/data-definitions/${dd.id}/sub-objects`).catch(() => ({ data: { data: [] } }));
          for (const so of (soRes.data.data || [])) {
            if (!seenNames.has(so.name)) {
              seenNames.add(so.name);
              allSubs.push({ name: so.name, description: so.description || '' });
            }
          }
        }));
        setInvDialogSubObjects(allSubs);
      })
      .catch(() => {
        setInvDialogAppOptions([]);
        setInvDialogSubObjects([]);
      })
      .finally(() => {
        setInvDialogSubLoading(false);
      });

    setProjectInventoryDialogOpen(true);
  };

  const startSubObjectCreateFromParent = (parentItem: any) => {
    setInventoryDialogProcessAreaFilter('');
    setEditingInventoryItemId(null);
    setProjectInventoryItem({
      ...getEmptyProjectInventoryItem(),
      isSubObject: true,
      parentProjectObjectId: parentItem.id,
      dataObjectId: parentItem.objectId || parentItem.dataObjectId || '',
      processArea: parentItem.processArea || '',
      targetApplicationId: parentItem.targetApplicationId || '',
      sourceApplicationId: parentItem.sourceApplicationId || '',
    });
  };

  // Handle delete inventory item
  const handleDeleteInventoryItem = (item: any) => {
    setDeletingInventoryItemId(item.id);
    setDeletingInventoryItemName(item.dataObjectId || item.objectId || 'this item');
  };

  // Confirm delete inventory item
  const confirmDeleteInventoryItem = async () => {
    if (!deletingInventoryItemId) return;

    const idsToRemove = getObjectAndDescendantIds(deletingInventoryItemId);
    try {
      setIsDeletingInventoryItem(true);
      await apiClient.delete(`/api/project-objects/${deletingInventoryItemId}`);
      setProjectInventoryItems(prev => prev.filter(entry => !idsToRemove.has(entry.id)));
      setDeletingInventoryItemId(null);
      setDeletingInventoryItemName('');
    } catch (error) {
      console.error('Failed to delete:', error);
      alert('Failed to delete item. Please try again.');
    } finally {
      setIsDeletingInventoryItem(false);
    }
  };

  const deletingInventoryItem = deletingInventoryItemId
    ? projectInventoryItems.find((item: any) => item.id === deletingInventoryItemId) || null
    : null;
  const deletingInventoryDescendantItems = deletingInventoryItemId
    ? projectInventoryItems.filter((item: any) => getObjectAndDescendantIds(deletingInventoryItemId).has(item.id) && item.id !== deletingInventoryItemId)
    : [];

  const handleProjectInventoryInlineChange = async (itemId: string, field: string, value: string) => {
    try {
      if (field === 'processArea') {
        const item = projectInventoryItems.find((entry: any) => entry.id === itemId);
        if (!item?.globalObjectId) {
          throw new Error('Missing global object id for process area update');
        }

        await apiClient.patch(`/api/global-objects/${item.globalObjectId}`, {
          processArea: value || null,
        });

        setProjectInventoryItems(prev => prev.map(entry => entry.id === itemId ? { ...entry, processArea: value } : entry));
        setInventoryObjects(prev => prev.map(obj => obj.id === item.globalObjectId ? { ...obj, processArea: value } : obj));
        return;
      }

      await apiClient.patch(`/api/project-objects/${itemId}`, {
        [field]: value || null,
      });
      setProjectInventoryItems(prev => prev.map(item => item.id === itemId ? { ...item, [field]: value } : item));
    } catch (error) {
      console.error('Failed to update inventory item field:', error);
      alert('Failed to update inventory item. Please try again.');
    }
  };

  useEffect(() => {
    if (sectionMode !== 'planning') return;
    if (!activeProjectId || !activeCycleId) return;
    const estimationNodeSelected = (
      (selectedItem?.type === 'deliverable' || selectedItem?.type === 'deliverableProcessArea')
      && selectedItem.deliverableId === 'designBuildEstimation'
    );
    if (!estimationNodeSelected) return;

    const topLevelObjects = projectInventoryItems.filter((item: any) => !item.parentProjectObjectId);
    const processAreas = Array.from(new Set(
      topLevelObjects
        .map((item: any) => String(item.processArea || '').trim())
        .filter(Boolean)
    ));
    if (processAreas.length === 0) return;

    const assignedMap = deliverableTaskGroupAssignments[activeProjectId] || {};
    const assignedGroupIds = new Set(
      Object.keys(assignedMap).filter((groupId) => assignedMap[groupId] === 'designBuildEstimation')
    );
    const existingAreaKeys = new Set(
      projectTaskGroups
        .filter((group: any) => assignedGroupIds.has(group.id))
        .map((group: any) => String(group.processArea || '').trim().toLowerCase())
        .filter(Boolean)
    );

    const missingAreas = processAreas.filter((area) => !existingAreaKeys.has(area.toLowerCase()));
    if (missingAreas.length === 0) return;

    let cancelled = false;

    const syncGroups = async () => {
      for (const area of missingAreas) {
        const dedupeKey = `${activeProjectId}:${activeCycleId}:${area.toLowerCase()}`;
        if (estimationAutoGroupInFlightRef.current.has(dedupeKey)) continue;
        estimationAutoGroupInFlightRef.current.add(dedupeKey);

        try {
          const response = await apiClient.post(`/api/tasks/groups/cycle/${activeCycleId}`, {
            name: `Design/Build Estimation - ${area}`,
            processArea: area,
          });
          const createdGroup = response.data?.data;
          if (!createdGroup || cancelled) continue;

          setProjectTaskGroups((prev) => (
            prev.some((group: any) => group.id === createdGroup.id) ? prev : [...prev, createdGroup]
          ));
          setDeliverableTaskGroupAssignments((prev) => ({
            ...prev,
            [activeProjectId]: {
              ...(prev[activeProjectId] || {}),
              [createdGroup.id]: 'designBuildEstimation',
            },
          }));
        } catch (error) {
          console.error('Failed to auto-create design/build estimation task group', error);
        } finally {
          estimationAutoGroupInFlightRef.current.delete(dedupeKey);
        }
      }
    };

    syncGroups();

    return () => {
      cancelled = true;
    };
  }, [
    sectionMode,
    selectedItem?.type,
    selectedItem?.type === 'deliverable' || selectedItem?.type === 'deliverableProcessArea' ? selectedItem.deliverableId : undefined,
    activeProjectId,
    activeCycleId,
    projectInventoryItems,
    projectTaskGroups,
    deliverableTaskGroupAssignments,
  ]);

  useEffect(() => {
    if (sectionMode !== 'planning') return;

    const normalizeCriteriaDraft = (
      source: any,
      defaults: MockCycleCriterionDraft[],
    ): MockCycleCriterionDraft[] => {
      const incoming = Array.isArray(source) ? source : [];
      if (incoming.length > 0 && incoming[0]?.fieldType) {
        const byKey = new Map<string, MockCycleCriterionDraft>();
        incoming.forEach((item: MockCycleCriterionDraft) => { if (item?.key) byKey.set(item.key, item); });
        return defaults.map((def) => byKey.get(def.key) ?? { ...def });
      }
      return defaults.map((d) => ({ ...d }));
    };

    const loadProjectWorkflowRoles = async (projectId: string) => {
      try {
        const response = await apiClient.get(`/api/projects/${projectId}/workflow-roles`);
        const payload = response.data?.data || {};
        setProjectLeadUserIdDraft(payload.leadUserId || '');
        setProjectManagerUserIdDraft(payload.projectManagerUserId || '');
      } catch {
        setProjectLeadUserIdDraft('');
        setProjectManagerUserIdDraft('');
      }
    };

    const loadCycleWorkflowStatus = async (cycleId: string) => {
      try {
        const response = await apiClient.get(`/api/mock-cycles/${cycleId}/workflow-status`);
        setCycleWorkflowEvaluation(response.data?.data || null);
      } catch {
        setCycleWorkflowEvaluation(null);
      }
    };

    if (selectedItem?.type === 'program') {
      const program = programs.find((p: Program) => p.id === selectedItem.id) as Program | undefined;
      setPlanningStrategyDraft(program?.description || '');
      setCycleEntryCriteriaDraft(MOCK_CYCLE_ENTRY_CRITERIA_DEFAULTS);
      setCycleExitCriteriaDraft(MOCK_CYCLE_EXIT_CRITERIA_DEFAULTS);
      setCycleWorkflowEvaluation(null);
      return;
    }
    if (selectedItem?.type === 'cycle') {
      const cycle = mockCycles[selectedItem.programId]?.find((c: MockCycle) => c.id === selectedItem.id) as MockCycle | undefined;
      setCycleEntryCriteriaDraft(normalizeCriteriaDraft(cycle?.entryCriteriaItems, MOCK_CYCLE_ENTRY_CRITERIA_DEFAULTS));
      setCycleExitCriteriaDraft(normalizeCriteriaDraft(cycle?.exitCriteriaItems, MOCK_CYCLE_EXIT_CRITERIA_DEFAULTS));
      setPlanningStrategyDraft('');
      if (cycle?.projectId) {
        loadProjectWorkflowRoles(cycle.projectId).catch(() => {});
      }
      loadCycleWorkflowStatus(selectedItem.id).catch(() => {});
      return;
    }
    if (selectedItem?.type === 'project') {
      loadProjectWorkflowRoles(selectedItem.id).catch(() => {});
      setCycleWorkflowEvaluation(null);
      return;
    }
    if (selectedItem?.type === 'deliverable') {
      if (selectedItem.deliverableId.startsWith(MOCK_CRITERIA_CYCLE_NODE_PREFIX)) {
        const cycleId = selectedItem.deliverableId.slice(MOCK_CRITERIA_CYCLE_NODE_PREFIX.length);
        const cycle = allMaintainCycles.find((item) => item.id === cycleId);
        setCycleEntryCriteriaDraft(normalizeCriteriaDraft(cycle?.entryCriteriaItems, MOCK_CYCLE_ENTRY_CRITERIA_DEFAULTS));
        setCycleExitCriteriaDraft(normalizeCriteriaDraft(cycle?.exitCriteriaItems, MOCK_CYCLE_EXIT_CRITERIA_DEFAULTS));
        if (cycleId) {
          loadCycleWorkflowStatus(cycleId).catch(() => {});
        } else {
          setCycleWorkflowEvaluation(null);
        }
      }
      loadProjectWorkflowRoles(selectedItem.projectId).catch(() => {});
      if (!selectedItem.deliverableId.startsWith(MOCK_CRITERIA_CYCLE_NODE_PREFIX)) {
        setCycleWorkflowEvaluation(null);
      }
      return;
    }
    if (selectedItem?.type === 'deliverableProcessArea') {
      loadProjectWorkflowRoles(selectedItem.projectId).catch(() => {});
      setCycleWorkflowEvaluation(null);
      return;
    }
    setPlanningStrategyDraft('');
    setCycleEntryCriteriaDraft(MOCK_CYCLE_ENTRY_CRITERIA_DEFAULTS);
    setCycleExitCriteriaDraft(MOCK_CYCLE_EXIT_CRITERIA_DEFAULTS);
    setCycleWorkflowEvaluation(null);
  }, [sectionMode, selectedItem, programs, mockCycles]);

  if (isLoading) {
    return (
      <Layout>
        <Box sx={{ display: 'flex', justifyContent: 'center', py: 4 }}>
          <CircularProgress />
        </Box>
      </Layout>
    );
  }

  // Get selected item details
  const getSelectedItemDetails = () => {
    if (!selectedItem) return null;
    
    if (selectedItem.type === 'program') {
      return programs.find(p => p.id === selectedItem.id);
    } else if (selectedItem.type === 'cycle') {
      return mockCycles[selectedItem.programId]?.find(c => c.id === selectedItem.id);
    } else if (selectedItem.type === 'project') {
      for (const cycleId in projectsByMockCycle) {
        const project = projectsByMockCycle[cycleId]?.find(p => p.id === selectedItem.id);
        if (project) return project;
      }
      for (const programId in projectsByProgram) {
        const project = projectsByProgram[programId]?.find((p: Project) => p.id === selectedItem.id);
        if (project) return project;
      }
    } else if (selectedItem.type === 'deliverable') {
      for (const cycleId in projectsByMockCycle) {
        const project = projectsByMockCycle[cycleId]?.find(p => p.id === selectedItem.projectId);
        if (project) return project;
      }
      for (const programId in projectsByProgram) {
        const project = projectsByProgram[programId]?.find((p: Project) => p.id === selectedItem.projectId);
        if (project) return project;
      }
    } else if (selectedItem.type === 'deliverableProcessArea') {
      for (const cycleId in projectsByMockCycle) {
        const project = projectsByMockCycle[cycleId]?.find(p => p.id === selectedItem.projectId);
        if (project) return project;
      }
      for (const programId in projectsByProgram) {
        const project = projectsByProgram[programId]?.find((p: Project) => p.id === selectedItem.projectId);
        if (project) return project;
      }
    } else if (selectedItem.type === 'processArea') {
      for (const cycleId in projectsByMockCycle) {
        const project = projectsByMockCycle[cycleId]?.find(p => p.id === selectedItem.projectId);
        if (project) return project;
      }
    }
    return null;
  };

  const selectedDetails = getSelectedItemDetails();

