  const getTaskStatusColor = (status: string) => {
    switch (status) {
      case 'complete': return '#4CAF50';
      case 'in_progress': return '#29B6F6';
      case 'blocked': return '#EF5350';
      default: return 'rgba(255,255,255,0.2)';
    }
  };

  const isWeekend = (d: Date) => d.getDay() === 0 || d.getDay() === 6;

  const formatDateOnly = (d: Date) => {
    const y = d.getFullYear();
    const m = String(d.getMonth() + 1).padStart(2, '0');
    const day = String(d.getDate()).padStart(2, '0');
    return `${y}-${m}-${day}`;
  };

  const adjustStartForMode = (startDate: string, mode: CalendarMode) => {
    const d = new Date(startDate.substring(0, 10) + 'T00:00:00');
    if (mode === 'working_days') {
      while (isWeekend(d)) d.setDate(d.getDate() + 1);
    }
    return d;
  };

  const addOneDay = (d: Date) => {
    const next = new Date(d);
    next.setDate(next.getDate() + 1);
    return next;
  };

  const getTaskCalendarMode = (task: any): CalendarMode => {
    if (task?.scheduleModeOverride === 'working_days') return 'working_days';
    if (task?.scheduleModeOverride === 'all_days') return 'all_days';
    return activeCycleScheduleMode;
  };

  const calcEndDate = (startDate: string, duration: number, task?: any): string => {
    if (!startDate || !duration) return '';
    const mode = getTaskCalendarMode(task);
    const d = adjustStartForMode(startDate, mode);
    // end = start + max(0, ceil(duration) - 1) working days.
    // ceil(0.5)-1=0 (same day), ceil(1.0)-1=0 (same day), ceil(1.6)-1=1 (+1 day), ceil(2.0)-1=1.
    // This is consistent with the cascade formula: endDate = chainStart + (ceil(cumFrac)-1) days.
    const daysToAdd = Math.max(0, Math.ceil(duration) - 1);
    if (mode === 'all_days') {
      d.setDate(d.getDate() + daysToAdd);
      return formatDateOnly(d);
    }
    let remaining = daysToAdd;
    while (remaining > 0) {
      d.setDate(d.getDate() + 1);
      if (!isWeekend(d)) remaining--;
    }
    return formatDateOnly(d);
  };

  /**
   * Compute the end date for a task considering its position within the sequence of sibling
   * tasks on the same object.
   * arrows, the cumulative fraction of all preceding siblings determines whether the end date
   * spills into the next calendar day.
   *
   * If no object context is available (task group task, or no siblings), falls back to
   * calcEndDate(start, duration).
   */
  const calcEndDateWithContext = (taskId: string, startDate: string, duration: number, task: any, tasksSnapshot: any[]): string => {
    if (!startDate || !duration) return '';
    const objectId = task?.projectObjectId;
    if (!objectId) return calcEndDate(startDate, duration, task);

    // Collect sibling tasks for the same object, sorted by start date then default order.
    const siblings = tasksSnapshot
      .filter(t => t.projectObjectId === objectId && t.startDate)
      .sort((a, b) => {
        const aDate = a.startDate ? new Date(a.startDate).getTime() : Infinity;
        const bDate = b.startDate ? new Date(b.startDate).getTime() : Infinity;
        if (aDate !== bDate) return aDate - bDate;
        // Tiebreak by template order so "Transformation" sorts before "PreLoad Validation"
        const aIdx = defaultTaskOrder.indexOf(a.name);
        const bIdx = defaultTaskOrder.indexOf(b.name);
        const aOrd = aIdx === -1 ? 9999 : aIdx;
        const bOrd = bIdx === -1 ? 9999 : bIdx;
        if (aOrd !== bOrd) return aOrd - bOrd;
        if (a.createdAt && b.createdAt) return new Date(a.createdAt).getTime() - new Date(b.createdAt).getTime();
        return (a.name || '').localeCompare(b.name || '');
      });

    const idx = siblings.findIndex(t => t.id === taskId);
    if (idx <= 0) return calcEndDate(startDate, duration, task); // first or not found — no chain context

    // Sum durations of all siblings that start on or before this task's start.
    // They form the "chain" up to this point.
    const chainStart = siblings[0].startDate;
    let cumFrac = 0;
    for (let i = 0; i < idx; i++) {
      cumFrac += Number(siblings[i].duration) || 0;
    }
    cumFrac += duration; // include this task's duration for the end-date formula

    return calcEndDate(chainStart, cumFrac, task);
  };

  /**
   * Apply sibling-context end-date correction to an entire task list in one pass.
   * Returns a new array with corrected endDate values and fires background API patches
   * for any tasks whose end date changed.
   */
  const applyAutoSchedule = (tasks: any[]): any[] => {
    const byObject: Record<string, any[]> = {};
    for (const t of tasks) {
      if (t.projectObjectId && t.startDate && t.duration) {
        (byObject[t.projectObjectId] = byObject[t.projectObjectId] || []).push(t);
      }
    }
    const correctedMap: Record<string, string> = {};
    for (const siblings of Object.values(byObject)) {
      if (siblings.length < 2) continue;
      const sorted = [...siblings].sort((a, b) => {
        const aD = a.startDate ? new Date(a.startDate).getTime() : Infinity;
        const bD = b.startDate ? new Date(b.startDate).getTime() : Infinity;
        if (aD !== bD) return aD - bD;
        // Tiebreak by default task template order so e.g. "Transformation"
        // sorts before "PreLoad Validation" (P < T alphabetically but wrong order).
        const aIdx = defaultTaskOrder.indexOf(a.name);
        const bIdx = defaultTaskOrder.indexOf(b.name);
        const aOrd = aIdx === -1 ? 9999 : aIdx;
        const bOrd = bIdx === -1 ? 9999 : bIdx;
        if (aOrd !== bOrd) return aOrd - bOrd;
        // Final fallback: creation time if available, else name
        if (a.createdAt && b.createdAt) return new Date(a.createdAt).getTime() - new Date(b.createdAt).getTime();
        return (a.name || '').localeCompare(b.name || '');
      });
      const chainStart = sorted[0].startDate;
      let cumFrac = 0;
      for (const t of sorted) {
        cumFrac += Number(t.duration) || 0;
        const expectedEnd = calcEndDate(chainStart, cumFrac, t);
        if (expectedEnd && expectedEnd !== t.endDate) {
          correctedMap[t.id] = expectedEnd;
        }
      }
    }
    if (Object.keys(correctedMap).length === 0) return tasks;
    // Persist corrections to DB in background (fire-and-forget).
    Object.entries(correctedMap).forEach(([id, endDate]) =>
      apiClient.patch(`/api/tasks/${id}`, { endDate }).catch(() => {})
    );
    return tasks.map(t => correctedMap[t.id] ? { ...t, endDate: correctedMap[t.id] } : t);
  };

  const updateTaskInline = async (taskId: string, field: string, value: string) => {
    try {
      const numericFields = ['progressPercentage', 'duration'];
      const parsedValue = numericFields.includes(field)
        ? (field === 'duration' ? (parseFloat(value) || null) : (parseInt(value) || 0))
        : value;
      const payload = { [field]: parsedValue };
      await apiClient.patch(`/api/tasks/${taskId}`, payload);
      // Use functional updater to avoid stale closure when multiple fields update simultaneously
      setProjectTasks(prev => {
        const updatedTasks = prev.map(t => t.id === taskId ? { ...t, [field]: parsedValue } : t);
        // Recalculate project % complete inline using updated snapshot
        if (activeProjectId) {
          const allPct = updatedTasks.filter(t => t.projectObjectId || t.taskGroupId);
          const avg = allPct.length > 0
            ? Math.round(allPct.reduce((sum, t) => {
                const pct = t.id === taskId && field === 'status' && value === 'complete' ? 100
                  : t.id === taskId && field === 'progressPercentage' ? (parseInt(value) || 0)
                  : (t.progressPercentage ?? 0);
                return sum + pct;
              }, 0) / allPct.length)
            : 0;
          apiClient.patch(`/api/projects/${activeProjectId}`, { progressPercentage: avg })
            .then(() => {
              queryClient.invalidateQueries({ queryKey: ['projectsByMockCycle'] });
              queryClient.invalidateQueries({ queryKey: ['projectsByProgram'] });
            })
            .catch(() => {});
        }
        return updatedTasks;
      });
      // When endDate changes, cascade to all downstream dependent tasks
      if (field === 'endDate' && parsedValue) {
        const snapshot = projectTasksRef.current.map(t => t.id === taskId ? { ...t, endDate: String(parsedValue) } : t);
        cascadeAllDates(snapshot, taskDepsRef.current);
      }
    } catch (e) { console.error('Failed to update task', e); }
  };

  const loadTaskDeps = async (taskId: string) => {
    try {
      const res = await apiClient.get(`/api/tasks/${taskId}/dependencies?t=${Date.now()}`);
      const newDeps = res.data.data || [];
      setTaskDeps(prev => ({ ...prev, [taskId]: newDeps }));
      return newDeps as any[];
    } catch (e) { /* ignore */ }
    return [] as any[];
  };

